CHOICE_SECTION_TITLE_RE = re.compile(
    r"(?:选择题|单选|多选|单项选择|多项选择|选择填空|选择合适的关联词语填空|关联词语填空|选择最佳选项|选出最佳选项|选择正确答案|选择正确的答案|选择正确选项|最佳选项|选择.{0,8}一项)"
)
def _is_choice_root_title(title_text: str) -> bool:
    title = normalize_line(title_text or "")
    if not title:
        return False
    # “非选择题”不是选择题根，避免误应用选择题规则。
    if re.search(r"(?:非\s*选择题|非选择题|非选择)", title):
        return False
    if CHOICE_SECTION_TITLE_RE.search(title):
        return True
    if re.search(r"(?:情景选择|单项选择题)", title):
        return True
    if re.search(r"(?:^|[\u3001\.\uFF0E])\s*选择(?:[\u3002。．\.]|$)", title):
        return True
    # 英语卷常见“阅读理解/完形填空”标题本身未显式写“选择题”，
    # 但其子题是 A-D 选择；在标题含英文线索时按选择题根处理，
    # 避免把题干中的下划线再次渲染成 blankText。
    if re.search(r"(?:阅读理解|完形填空)", title) and re.search(r"[A-Za-zＡ-Ｚａ-ｚ]", title):
        return True
    return False


def _extract_non_numbered_question_section_label(text: str) -> str:
    normalized = normalize_line(text or "")
    if not normalized:
        return ""
    for label in NON_NUMBERED_QUESTION_SECTION_LABELS:
        if not normalized.startswith(label):
            continue
        if len(normalized) == len(label):
            return label
        next_char = normalized[len(label)]
        if next_char in {" ", "\u3000", "：", ":", "，", ",", "。", "．"}:
            return label
    return ""


