    inserted_later_sections = False
    later_numbers = {"四", "五", "六", "七", "八", "九", "十"}
    for node in roots:
        node_numbering = str(node.get("numbering") or "")
        if node_numbering in later_numbers:
            if not inserted_later_sections:
                rebuilt_roots.extend([root_four, root_five, root_six, root_seven, root_eight, root_nine, root_ten])
