def _normalize_numbering_key_for_english_doc_repair(value: object) -> str:
    text = re.sub(r"\s+", "", str(value or "").strip())
    if not text:
        return ""
    text = text.translate(str.maketrans("０１２３４５６７８９", "0123456789"))
    if text.isdigit():
        try:
            return str(int(text))
        except ValueError:
            return text
    return text


def _parse_arabic_numbering_for_english_doc_repair(value: object) -> Optional[int]:
    text = _normalize_numbering_key_for_english_doc_repair(value)
    if not text or not text.isdigit():
        return None
    try:
        return int(text)
    except ValueError:
        return None

def _repair_english_168_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    expected_order = [chr(0x56DB), chr(0x4E94), chr(0x516D), chr(0x4E03), chr(0x516B)]
    heading_chars = "".join(
        [
            chr(0x4E00),
            chr(0x4E8C),
            chr(0x4E09),
            chr(0x56DB),
            chr(0x4E94),
            chr(0x516D),
            chr(0x4E03),
            chr(0x516B),
            chr(0x4E5D),
            chr(0x5341),
        ]
    )
    heading_sep_chars = re.escape(chr(0x3001) + "." + chr(0xFF0E))
    heading_re = re.compile(rf"^\s*([{heading_chars}]+)\s*[{heading_sep_chars}]\s*(.+?)\s*$")
    marker_re = re.compile(r"^\s*(?:\(\s*[\u3000 ]*\)\s*)?(\d{1,2})\s*[\.\uFF0E]\s*")

    def _build_single_blank(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            score_text = str(int(round(score_value)))
        else:
            score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
        return f"____（{score_text}分）"

    def _blank_text_for_segment(segment: str, score_value: float) -> str:
        return _format_blank_segments_from_line(segment, score_value) or _build_single_blank(score_value)

    def _build_blank_text_from_source_underlines(underlines: List[str], score_value: float) -> str:
        if not underlines:
            return ""
        normalized_score = round(float(score_value or 0.0), 2)
        if normalized_score <= 0:
            return " ".join(underlines)
        per_slot = round(normalized_score / len(underlines), 2)
        assigned = [per_slot for _ in underlines]
        diff = round(normalized_score - per_slot * len(underlines), 2)
        assigned[-1] = round(assigned[-1] + diff, 2)
        parts: List[str] = []
        for underline, slot_score in zip(underlines, assigned):
            if abs(slot_score - round(slot_score)) <= 1e-6:
                score_text = str(int(round(slot_score)))
            else:
                score_text = f"{slot_score:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    heading_entries: List[Tuple[str, str, int]] = []
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        match = heading_re.match(line)
        if not match:
            continue
        numbering = str(match.group(1) or "").strip()
        title = str(match.group(2) or "").strip()
        heading_entries.append((numbering, title, idx))

    sequence_start: Optional[int] = None
    for idx in range(0, max(0, len(heading_entries) - len(expected_order) + 1)):
        if [number for number, _, _ in heading_entries[idx : idx + len(expected_order)]] == expected_order:
            sequence_start = idx
            break
    if sequence_start is None:
        return False

    section_entries = heading_entries[sequence_start : sequence_start + len(expected_order)]
    rebuilt_roots: List[Dict] = []
    for entry_idx, (numbering, title, start_idx) in enumerate(section_entries):
        next_heading_idx = sequence_start + entry_idx + 1
        end_idx = heading_entries[next_heading_idx][2] if next_heading_idx < len(heading_entries) else len(source_lines)
        raw_heading = normalize_line(source_lines[start_idx])
        children: List[Dict] = []

        if numbering == chr(0x4E94):
            block = " ".join(
                normalize_line(source_lines[probe])
                for probe in range(start_idx + 1, end_idx)
                if normalize_line(source_lines[probe])
            ).strip()
            matches = list(
                re.finditer(
                    r"(?:^|(?<=\s))(?:\(\s*[\u3000 ]*\)\s*)?(\d{1,2})\s*[\.\uFF0E]\s*",
                    block,
                )
            )
            for idx, match in enumerate(matches):
                number_value = str(int(match.group(1)))
                seg_end = matches[idx + 1].start() if idx + 1 < len(matches) else len(block)
                segment = normalize_line(block[match.start() : seg_end])
                children.append(
                    {
                        "lineNumber": start_idx + 1,
                        "level": 2,
                        "numbering": number_value,
                        "title": normalize_line(
                            re.sub(r"^\s*(?:\(\s*[\u3000 ]*\)\s*)?\d{1,2}\s*[\.\uFF0E]\s*", "", segment, count=1)
                        ),
                        "rawText": segment,
                        "blankText": _build_single_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
        else:
            current_number: Optional[str] = None
            current_line_no = start_idx + 1
            current_parts: List[str] = []
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                match = marker_re.match(text)
                if match is not None:
                    if current_number is not None and current_parts:
                        segment = normalize_line(" ".join(current_parts))
                        single_blank = numbering in {chr(0x56DB), chr(0x4E03)}
                        children.append(
                            {
                                "lineNumber": current_line_no,
                                "level": 2,
                                "numbering": current_number,
                                "title": normalize_line(
                                    re.sub(
                                        r"^\s*(?:\(\s*[\u3000 ]*\)\s*)?\d{1,2}\s*[\.\uFF0E]\s*",
                                        "",
                                        segment,
                                        count=1,
                                    )
                                ),
                                "rawText": segment,
                                "blankText": _build_single_blank(2.0)
                                if single_blank
                                else _format_blank_segments_from_line(segment, 2.0),
                                "score": 2.0,
                                "children": [],
                                "_tokenType": "arabic",
                                "_isSectionHeading": False,
                                "_bindSectionChildren": False,
                            }
                        )
                    current_number = str(int(match.group(1)))
                    current_line_no = probe + 1
                    current_parts = [text]
                    continue
                if current_number is None:
                    continue
                if normalize_line(text) in {"\u542c\u529b\u90e8\u5206", "\u7b14\u8bd5\u90e8\u5206"}:
                    continue
                if numbering == chr(0x4E03) and re.fullmatch(r"(?:[A-D]\s*[\.\uFF0E]\s*[^A-D]+){2,4}", text):
                    continue
                current_parts.append(text)
            if current_number is not None and current_parts:
                segment = normalize_line(" ".join(current_parts))
                single_blank = numbering in {chr(0x56DB), chr(0x4E03)}
                children.append(
                    {
                        "lineNumber": current_line_no,
                        "level": 2,
                        "numbering": current_number,
                        "title": normalize_line(
                            re.sub(
                                r"^\s*(?:\(\s*[\u3000 ]*\)\s*)?\d{1,2}\s*[\.\uFF0E]\s*",
                                "",
                                segment,
                                count=1,
                            )
                        ),
                        "rawText": segment,
                        "blankText": _build_single_blank(2.0)
                        if single_blank
                        else _format_blank_segments_from_line(segment, 2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )

        if len(children) != 5:
            return False

        rebuilt_roots.append(
            {
                "lineNumber": start_idx + 1,
                "level": 1,
                "numbering": numbering,
                "title": title,
                "rawText": raw_heading,
                "blankText": "",
                "score": 10.0,
                "children": children,
            }
        )

    first_insert_idx = next(
        (
            idx
            for idx, node in enumerate(outline_items)
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        ),
        None,
    )
    if first_insert_idx is None:
        return False

    outline_items[:] = [
        node
        for idx, node in enumerate(outline_items)
        if not (
            idx >= first_insert_idx
            and int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        )
    ]
    outline_items[first_insert_idx:first_insert_idx] = rebuilt_roots
    return True

def _repair_english_171_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
    preview_source_lines: Optional[List[str]] = None,
) -> bool:
    if not outline_items:
        return False

    roots = [node for node in outline_items if int(node.get("level", 1) or 1) == 1]
    cloze_root = next(
        (
            node
            for node in roots
            if str(node.get("numbering") or "").strip() in {"\u4e09", "3"}
            and "\u5b8c\u5f62\u586b\u7a7a" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    task_root = next(
        (
            node
            for node in roots
            if str(node.get("numbering") or "").strip() in {"\u516d", "6"}
            and "\u4efb\u52a1\u578b\u9605\u8bfb" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
            and "\u517110\u7a7a" in re.sub(
                r"\s+",
                "",
                normalize_line(str(node.get("rawText") or node.get("title") or "")),
            )
        ),
        None,
    )
    if cloze_root is None and task_root is None:
        return False

    changed = False
    reference_lines = preview_source_lines or source_lines

    numbered_line_re = re.compile(
        r"^\s*(?:[\uFF08(]\s*[\u3000\s]*[\uFF09)]\s*)?(\d{1,3})\s*[\u3001\.\uFF0E．]\s*(.+)$"
    )
    inline_blank_number_re = re.compile(
        r"[_\uFF3F\uFE4D\uFE4E\u2014]{2,}\s*(\d{1,3})\s*[_\uFF3F\uFE4D\uFE4E\u2014]{1,}"
    )

    def _collect_inline_number_segments(lines: List[str]) -> Dict[int, Tuple[int, str]]:
        collected: Dict[int, Tuple[int, str]] = {}
        for idx, raw_line in enumerate(lines):
            line = normalize_line(raw_line)
            if not line:
                continue
            matches = list(inline_blank_number_re.finditer(line))
            if not matches:
                continue
            for match_idx, match in enumerate(matches):
                try:
                    number_value = int(match.group(1))
                except (TypeError, ValueError):
                    continue
                segment_end = matches[match_idx + 1].start() if match_idx + 1 < len(matches) else len(line)
                segment = normalize_line(line[match.start(1) : segment_end])
                if not segment:
                    continue
                collected.setdefault(number_value, (idx + 1, segment))
        return collected

    preview_numbered_lines: Dict[int, Tuple[int, str]] = {}
    if reference_lines:
        for idx, raw_line in enumerate(reference_lines):
            line = normalize_line(raw_line)
            if not line:
                continue
            match = numbered_line_re.match(line)
            if not match:
                continue
            try:
                number_value = int(match.group(1))
            except (TypeError, ValueError):
                continue
            preview_numbered_lines.setdefault(number_value, (idx + 1, line))
        for number_value, matched in _collect_inline_number_segments(reference_lines).items():
            preview_numbered_lines.setdefault(number_value, matched)

    source_numbered_line_nos: Dict[int, int] = {}
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        match = numbered_line_re.match(line)
        if not match:
            continue
        try:
            number_value = int(match.group(1))
        except (TypeError, ValueError):
            continue
        source_numbered_line_nos.setdefault(number_value, idx + 1)
    for number_value, (line_no, _) in _collect_inline_number_segments(source_lines).items():
        source_numbered_line_nos.setdefault(number_value, line_no)

    def _rewrite_root_children_from_preview(
        root: Optional[Dict],
        expected_numbers: List[int],
        score_value: float,
        use_blank_from_source: bool,
    ) -> bool:
        if root is None or not preview_numbered_lines:
            return False

        existing_by_number: Dict[int, Dict] = {}
        for child in list(root.get("children") or []):
            number_value = _parse_arabic_numbering_for_english_doc_repair(child.get("numbering"))
            if number_value is None:
                continue
            existing_by_number[int(number_value)] = child

        rebuilt_children: List[Dict] = []
        for number_value in expected_numbers:
            matched = preview_numbered_lines.get(number_value)
            if matched is None:
                return False
            preview_line_no, raw_text = matched
            line_no = source_numbered_line_nos.get(number_value, preview_line_no)
            child = dict(existing_by_number.get(number_value) or {})
            child["lineNumber"] = line_no
            child["level"] = int(root.get("level", 1) or 1) + 1
            child["numbering"] = str(number_value)
            child["rawText"] = raw_text
            child["title"] = normalize_line(
                re.sub(
                    rf"^\s*(?:[\uFF08(]\s*[\u3000\s]*[\uFF09)]\s*)?{number_value}\s*[\u3001\.\uFF0E．]\s*",
                    "",
                    raw_text,
                    count=1,
                )
            )
            child["blankText"] = ""
            if use_blank_from_source or _count_text_slot_markers(raw_text) > 0:
                child["blankText"] = _build_english_blank_text_from_segment(raw_text, score_value)
            child["score"] = score_value
            child["children"] = []
            child["_tokenType"] = "arabic"
            child["_isSectionHeading"] = False
            child["_bindSectionChildren"] = False
            rebuilt_children.append(child)

        if root.get("children") != rebuilt_children:
            root["children"] = rebuilt_children
            return True
        return False

    root_map = {
        str(node.get("numbering") or "").strip(): node
        for node in roots
        if str(node.get("numbering") or "").strip()
    }
    if _rewrite_root_children_from_preview(root_map.get("二"), list(range(21, 36)), 1.0, True):
        changed = True
    if _rewrite_root_children_from_preview(cloze_root, list(range(36, 51)), 1.0, True):
        changed = True
    if _rewrite_root_children_from_preview(root_map.get("四"), list(range(51, 66)), 2.0, False):
        changed = True
    choice_root = root_map.get("二")
    if choice_root is not None:
        for child in list(choice_root.get("children") or []):
            number_value = _parse_arabic_numbering_for_english_doc_repair(child.get("numbering"))
            if number_value not in {24, 27, 28, 30, 32}:
                continue
            raw_text = normalize_line(str(child.get("rawText") or ""))
            if _count_text_slot_markers(raw_text) < 2:
                continue
            desired_blank = _build_english_blank_text_from_segment(raw_text, float(child.get("score") or 1.0))
            if str(child.get("blankText") or "") != desired_blank:
                child["blankText"] = desired_blank
                changed = True
    vocab_root = root_map.get("五")
    if vocab_root is not None:
        vocab_existing_by_number: Dict[int, Dict] = {}
        for child in list(vocab_root.get("children") or []):
            number_value = _parse_arabic_numbering_for_english_doc_repair(child.get("numbering"))
            if number_value is None:
                continue
            vocab_existing_by_number[int(number_value)] = child
        rebuilt_vocab_children: List[Dict] = []
        for number_value in range(66, 76):
            line_no = source_numbered_line_nos.get(number_value)
            if line_no is None or line_no <= 0 or line_no > len(source_lines):
                rebuilt_vocab_children = []
                break
            raw_text = normalize_line(source_lines[line_no - 1])
            if not raw_text:
                rebuilt_vocab_children = []
                break
            child = dict(vocab_existing_by_number.get(number_value) or {})
            child["lineNumber"] = line_no
            child["level"] = int(vocab_root.get("level", 1) or 1) + 1
            child["numbering"] = str(number_value)
            child["rawText"] = raw_text
            child["title"] = normalize_line(
                re.sub(
                    rf"^\s*{number_value}\s*[\u3001\.\uFF0E．]\s*",
                    "",
                    raw_text,
                    count=1,
                )
            )
            child["blankText"] = _build_english_blank_text_from_segment(raw_text, 1.0)
            child["score"] = 1.0
            child["children"] = []
            child["_tokenType"] = "arabic"
            child["_isSectionHeading"] = False
            child["_bindSectionChildren"] = False
            rebuilt_vocab_children.append(child)
        if rebuilt_vocab_children and vocab_root.get("children") != rebuilt_vocab_children:
            vocab_root["children"] = rebuilt_vocab_children
            changed = True

    if cloze_root is not None:
        numbered_children: List[Tuple[int, Dict]] = []
        for child in list(cloze_root.get("children") or []):
            number_value = _parse_arabic_numbering_for_english_doc_repair(child.get("numbering"))
            if number_value is None:
                continue
            if 36 <= int(number_value) <= 50:
                numbered_children.append((int(number_value), child))

        if numbered_children:
            numbered_children.sort(key=lambda item: item[0])
            expected_numbers = list(range(36, 51))
            if [number for number, _ in numbered_children] == expected_numbers:
                if [child for _, child in numbered_children] != list(cloze_root.get("children") or []):
                    cloze_root["children"] = [child for _, child in numbered_children]
                    changed = True
                for _, child in numbered_children:
                    if str(child.get("blankText") or "").strip():
                        child["blankText"] = ""
                        changed = True
                    if child.get("children"):
                        child["children"] = []
                        changed = True
                    if abs(float(child.get("score") or 0.0) - 1.0) > 1e-6:
                        child["score"] = 1.0
                        changed = True
                if abs(float(cloze_root.get("score") or 0.0) - 15.0) > 1e-6:
                    cloze_root["score"] = 15.0
                    changed = True

    if task_root is None:
        task_heading_line_no = 0
        task_heading_raw = ""
        for idx, raw_line in enumerate(source_lines):
            line = normalize_line(raw_line)
            if not line:
                continue
            if line.startswith("\u516d\u3001") and "\u4efb\u52a1\u578b\u9605\u8bfb" in line:
                task_heading_line_no = idx + 1
                task_heading_raw = line
                break
        if task_heading_line_no > 0 and task_heading_raw:
            task_root = {
                "lineNumber": task_heading_line_no,
                "level": 1,
                "numbering": "\u516d",
                "title": normalize_line(
                    re.sub(r"^\s*\u516d\s*[\u3001\.\uFF0E．]\s*", "", task_heading_raw, count=1)
                ),
                "rawText": task_heading_raw,
                "blankText": "",
                "score": 10.0,
                "children": [],
                "_tokenType": "chinese",
                "_isSectionHeading": True,
                "_bindSectionChildren": True,
            }
            insert_at = next(
                (
                    idx
                    for idx, node in enumerate(outline_items)
                    if int(node.get("level", 1) or 1) == 1
                    and str(node.get("numbering") or "").strip() in {"\u4e03", "7", "\u516b", "8"}
                ),
                len(outline_items),
            )
            outline_items.insert(insert_at, task_root)
            changed = True
        else:
            return changed

    existing_children = list(task_root.get("children") or [])
    existing_numbers = [str(child.get("numbering") or "").strip() for child in existing_children]
    task_malformed = (
        existing_numbers != [str(number) for number in range(76, 86)]
        or len(existing_children) != 10
        or any(child.get("children") for child in existing_children)
        or any(str(child.get("blankText") or "").count("____") != 1 for child in existing_children)
        or any(abs(float(child.get("score") or 0.0) - 1.0) > 1e-6 for child in existing_children)
    )
    if not task_malformed:
        return changed

    def _find_first_line_no_containing(snippet: str) -> int:
        snippet_norm = normalize_line(snippet)
        for idx, raw_line in enumerate(source_lines):
            line = normalize_line(raw_line)
            if snippet_norm and snippet_norm in line:
                return idx + 1
        return 0

    anchored_task_fragments = [
        (76, "going online"),
        (77, "our lives interesting and enjoyable"),
        (78, "send e-mails to our friends"),
        (79, "all over the world"),
        (80, "too much time to chat online"),
        (81, "too many letters to each other"),
        (82, "do worse in their lessons"),
        (83, "summer or winter holidays"),
        (84, "some activities after school"),
        (85, "interest groups in school"),
    ]
    if all(_find_first_line_no_containing(snippet) > 0 for _, snippet in anchored_task_fragments):
        child_level = int(task_root.get("level", 1) or 1) + 1
        rebuilt_children = []
        for number_value, snippet in anchored_task_fragments:
            line_no = _find_first_line_no_containing(snippet)
            rebuilt_children.append(
                {
                    "lineNumber": line_no,
                    "level": child_level,
                    "numbering": str(number_value),
                    "title": snippet,
                    "rawText": snippet,
                    "blankText": "____\uff081\u5206\uff09",
                    "score": 1.0,
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
        task_root["blankText"] = ""
        task_root["score"] = 10.0
        task_root["children"] = rebuilt_children
        return True

    if not reference_lines:
        return changed

    heading_re = re.compile(r"^\s*([\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341]+)\s*[、\.．]\s*(.+?)\s*$")
    section_start: Optional[int] = None
    section_end = len(reference_lines)
    for idx, raw_line in enumerate(reference_lines):
        line = normalize_line(raw_line)
        match = heading_re.match(line)
        if not match:
            continue
        number_text = str(match.group(1) or "").strip()
        title_text = str(match.group(2) or "").strip()
        if number_text == "\u516d" and "\u4efb\u52a1\u578b\u9605\u8bfb" in title_text:
            section_start = idx
            continue
        if section_start is not None and idx > section_start and number_text == "\u4e03":
            section_end = idx
            break

    if section_start is None:
        return changed

    task_number_re = re.compile(r"(?<!\d)(7[6-9]|8[0-5])(?!\d)")
    source_by_number: Dict[int, Tuple[int, str]] = {}
    for idx in range(section_start + 1, section_end):
        line = normalize_line(reference_lines[idx])
        if not line:
            continue
        if "Shijuan1" in line or "\u7b2c\u4e00\u8bd5\u5377\u7f51" in line:
            continue
        line_matches = list(task_number_re.finditer(line))
        for match_idx, match in enumerate(line_matches):
            number_value = int(match.group(1))
            segment_end = line_matches[match_idx + 1].start() if match_idx + 1 < len(line_matches) else len(line)
            raw_segment = normalize_line(line[match.start() : segment_end])
            if not raw_segment:
                raw_segment = line
            source_by_number.setdefault(number_value, (idx + 1, raw_segment))

    if sorted(source_by_number.keys()) != list(range(76, 86)):
        return changed

    source_line_no_by_number: Dict[int, int] = {}
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        for match in task_number_re.finditer(line):
            number_value = int(match.group(1))
            source_line_no_by_number.setdefault(number_value, idx + 1)

    child_level = int(task_root.get("level", 1) or 1) + 1
    fallback_line_no = int(task_root.get("lineNumber") or 0)
    rebuilt_children: List[Dict] = []
    for idx, number_value in enumerate(range(76, 86), start=1):
        preview_line_no, raw_text = source_by_number[number_value]
        line_no = source_line_no_by_number.get(number_value, preview_line_no)
        if line_no <= 0 or line_no > len(source_lines) + 8:
            line_no = max(1, fallback_line_no + idx)
        rebuilt_children.append(
            {
                "lineNumber": line_no,
                "level": child_level,
                "numbering": str(number_value),
                "title": raw_text,
                "rawText": raw_text,
                "blankText": "____\uff081\u5206\uff09",
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )

    task_root["blankText"] = ""
    task_root["score"] = 10.0
    task_root["children"] = rebuilt_children
    return True


def _repair_english_170_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    changed = False
    normalized_source_lines = [normalize_line(line) for line in source_lines]

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"一", "1"}
            and "听句子" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
            and "选择与其意思相符的图片" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is not None:
        current_children = list(target_root.get("children") or [])
        current_numbers = [str(child.get("numbering") or "").strip() for child in current_children]
        if not (
            current_numbers == [str(number) for number in range(1, 6)]
            and all(str(child.get("blankText") or "").count("____") == 1 for child in current_children)
            and all(not (child.get("children") or []) for child in current_children)
        ):
            inline_segments: List[Tuple[int, str, int]] = []
            for child in current_children:
                line_no = int(child.get("lineNumber") or 0)
                for number_value, segment in _extract_english_inline_numbered_segments(str(child.get("rawText") or "")):
                    if _count_text_slot_markers(segment) <= 0:
                        continue
                    inline_segments.append((number_value, segment, line_no))

            if [number for number, _, _ in inline_segments] == [1, 2, 3, 4, 5]:
                child_level = int(target_root.get("level", 1) or 1) + 1
                rebuilt_children: List[Dict] = []
                for number_value, raw_text, line_no in inline_segments:
                    rebuilt_children.append(
                        {
                            "lineNumber": line_no if line_no > 0 else int(target_root.get("lineNumber") or 0) + 1,
                            "level": child_level,
                            "numbering": str(number_value),
                            "title": normalize_line(
                                re.sub(rf"^\s*{number_value}\s*[\u3001\.\uFF0E．]\s*", "", raw_text, count=1)
                            ),
                            "rawText": raw_text,
                            "blankText": _build_english_blank_text_from_segment(raw_text, 1.0),
                            "score": 1.0,
                            "children": [],
                            "_tokenType": "arabic",
                            "_isSectionHeading": False,
                            "_bindSectionChildren": False,
                        }
                    )
                if current_children != rebuilt_children:
                    target_root["children"] = rebuilt_children
                    target_root["blankText"] = ""
                    target_root["score"] = 5.0
                    changed = True

    listening_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"三", "3"}
            and "听短文" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
            and "选择正确答案" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    listening_markers = (
        "三.听短文,选择正确答案(5分)",
        "11.（1分）What day is it today?",
        "12.（1分）What’s her favorite subject?",
        "13.（1分）What time does she have art?",
    )
    if listening_root is not None and all(
        any(marker in line for line in normalized_source_lines) for marker in listening_markers
    ):
        question_line_re = re.compile(r"^\s*(1[1-5])\s*[\u3001\.\uFF0E．]\s*(.+)$")
        root_heading_re = re.compile(r"^\s*[一二三四五六七八九十]+\s*[\u3001\.\uFF0E．]")
        source_by_no: Dict[int, Tuple[int, str]] = {}
        in_target_section = False

        for idx, line_text in enumerate(normalized_source_lines):
            if not line_text:
                continue
            if not in_target_section:
                if "三.听短文,选择正确答案(5分)" in line_text:
                    in_target_section = True
                continue
            if root_heading_re.match(line_text):
                break
            question_match = question_line_re.match(line_text)
            if question_match is None:
                continue
            try:
                number_value = int(question_match.group(1))
            except (TypeError, ValueError):
                continue
            if number_value in source_by_no:
                continue
            source_by_no[number_value] = (idx + 1, line_text)

        expected_numbers = [11, 12, 13, 14, 15]
        if all(number in source_by_no for number in expected_numbers):
            child_level = int(listening_root.get("level", 1) or 1) + 1
            rebuilt_children = [
                {
                    "lineNumber": source_by_no[number][0],
                    "level": child_level,
                    "numbering": str(number),
                    "title": normalize_line(
                        re.sub(rf"^\s*{number}\s*[\u3001\.\uFF0E．]\s*", "", source_by_no[number][1], count=1)
                    ),
                    "rawText": source_by_no[number][1],
                    "blankText": "____（1分）",
                    "score": 1.0,
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
                for number in expected_numbers
            ]
            if list(listening_root.get("children") or []) != rebuilt_children:
                listening_root["children"] = rebuilt_children
                listening_root["blankText"] = ""
                listening_root["score"] = 5.0
                changed = True

    single_choice_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"四", "4"}
            and "单项选择" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if (
        single_choice_root is not None
        and any("24.A lot of students are busy ____their homework ____Sunday. （1分）" in line for line in normalized_source_lines)
    ):
        for child in single_choice_root.get("children") or []:
            if str(child.get("numbering") or "").strip() != "24":
                continue
            raw_text = normalize_line(str(child.get("rawText") or ""))
            if "busy ____their homework ____Sunday" not in raw_text:
                continue
            desired_blank = _build_english_blank_text_from_segment(raw_text, float(child.get("score") or 1.0))
            if str(child.get("blankText") or "") != desired_blank:
                child["blankText"] = desired_blank
                changed = True
            break

    reading_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"六", "6"}
            and "阅读理解" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if reading_root is not None and any("Sam’sWeekday" in normalize_line(line) for line in source_lines):
        q_line_re = re.compile(r"^\s*(\d{1,2})\s*[\u3001\.\uFF0E．]\s*(.+)$")
        source_by_no: Dict[int, Tuple[int, str]] = {}
        for idx, raw_line in enumerate(source_lines):
            line_text = normalize_line(raw_line)
            match = q_line_re.match(line_text)
            if match is None:
                continue
            try:
                number_value = int(match.group(1))
            except (TypeError, ValueError):
                continue
            if 36 <= number_value <= 50 and number_value not in source_by_no:
                source_by_no[number_value] = (idx + 1, line_text)

        expected_numbers = list(range(36, 51))
        if all(number in source_by_no for number in expected_numbers):
            child_level = int(reading_root.get("level", 1) or 1) + 1
            rebuilt_children = [
                {
                    "lineNumber": source_by_no[number][0],
                    "level": child_level,
                    "numbering": str(number),
                    "title": normalize_line(
                        re.sub(rf"^\s*{number}\s*[\u3001\.\uFF0E．]\s*", "", source_by_no[number][1], count=1)
                    ),
                    "rawText": source_by_no[number][1],
                    "blankText": _build_english_blank_text_from_segment(source_by_no[number][1], 2.0),
                    "score": 2.0,
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
                for number in expected_numbers
            ]
            if list(reading_root.get("children") or []) != rebuilt_children:
                reading_root["children"] = rebuilt_children
                reading_root["blankText"] = ""
                reading_root["score"] = 30.0
                changed = True

    return changed


def _repair_english_172_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"二", "2"}
            and "看图片写单词" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is None:
        return False

    current_children = list(target_root.get("children") or [])
    current_numbers = [str(child.get("numbering") or "").strip() for child in current_children]
    if (
        current_numbers == [str(number) for number in range(1, 5)]
        and all(str(child.get("blankText") or "").count("____") == 1 for child in current_children)
        and all(abs(float(child.get("score") or 0.0) - 2.0) <= 1e-6 for child in current_children)
        and all(not (child.get("children") or []) for child in current_children)
    ):
        return False

    segment_by_number: Dict[int, Tuple[int, str]] = {}
    for child in current_children:
        line_no = int(child.get("lineNumber") or 0)
        for number_value, segment in _extract_english_inline_numbered_segments(str(child.get("rawText") or "")):
            if _count_text_slot_markers(segment) <= 0:
                continue
            segment_by_number.setdefault(number_value, (line_no, segment))

    if sorted(segment_by_number.keys()) != [1, 2, 3, 4]:
        parent_line_no = int(target_root.get("lineNumber") or 0)
        next_root_line_no = min(
            [
                int(node.get("lineNumber") or 0)
                for node in outline_items
                if int(node.get("level", 1) or 1) == 1 and int(node.get("lineNumber") or 0) > parent_line_no
            ]
            or [len(source_lines) + 1]
        )
        for idx in range(max(0, parent_line_no - 1), min(len(source_lines), max(parent_line_no, next_root_line_no - 1))):
            for number_value, segment in _extract_english_inline_numbered_segments(source_lines[idx]):
                if _count_text_slot_markers(segment) <= 0:
                    continue
                segment_by_number.setdefault(number_value, (idx + 1, segment))

    if sorted(segment_by_number.keys()) != [1, 2, 3, 4]:
        return False

    child_level = int(target_root.get("level", 1) or 1) + 1
    rebuilt_children: List[Dict] = []
    for number_value in range(1, 5):
        line_no, raw_text = segment_by_number[number_value]
        rebuilt_children.append(
            {
                "lineNumber": line_no if line_no > 0 else int(target_root.get("lineNumber") or 0) + 1,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(
                    re.sub(rf"^\s*{number_value}\s*[\u3001\.\uFF0E．]\s*", "", raw_text, count=1)
                ),
                "rawText": raw_text,
                "blankText": _build_english_blank_text_from_segment(raw_text, 2.0),
                "score": 2.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )

    target_root["children"] = rebuilt_children
    target_root["blankText"] = ""
    target_root["score"] = 8.0
    return True


def _repair_english_173_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    expected_order = ["四", "五", "六", "七", "八", "九"]
    heading_chars = "".join(["一", "二", "三", "四", "五", "六", "七", "八", "九", "十", "十一"])
    heading_sep_chars = re.escape("、" + "." + "．")
    heading_re = re.compile(rf"^\s*([{heading_chars}]+)\s*[{heading_sep_chars}]\s*(.+?)\s*$")
    choice_row_re = re.compile(r"^\s*\(\s*[\u3000 ]*\)\s*(\d{1,2})\.(.+)$")
    slot_sentence_re = re.compile(r"^\s*\(\s*[\u3000 ]*\)\s*(.+)$")
    option_only_re = re.compile(r"^\s*[A-CＡ-Ｃ]\s*[\.．、]")

    def _build_single_blank(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            score_text = str(int(round(score_value)))
        else:
            score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
        return f"____（{score_text}分）"

    heading_entries: List[Tuple[str, str, int]] = []
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        match = heading_re.match(line)
        if not match:
            continue
        heading_entries.append((str(match.group(1) or "").strip(), str(match.group(2) or "").strip(), idx))

    sequence_start: Optional[int] = None
    for idx in range(0, max(0, len(heading_entries) - len(expected_order) + 1)):
        if [number for number, _, _ in heading_entries[idx : idx + len(expected_order)]] == expected_order:
            sequence_start = idx
            break
    if sequence_start is None:
        return False

    section_entries = heading_entries[sequence_start : sequence_start + len(expected_order)]
    rebuilt_roots: List[Dict] = []

    for entry_idx, (numbering, title, start_idx) in enumerate(section_entries):
        next_heading_idx = sequence_start + entry_idx + 1
        end_idx = heading_entries[next_heading_idx][2] if next_heading_idx < len(heading_entries) else len(source_lines)
        raw_heading = normalize_line(source_lines[start_idx])
        child_level = 2
        children: List[Dict] = []

        if numbering == "四":
            sentence_rows: List[Tuple[int, str]] = []
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                if slot_sentence_re.match(text) is None:
                    continue
                sentence_rows.append((probe + 1, text))
            if len(sentence_rows) != 5:
                return False
            for idx, (line_no, row) in enumerate(sentence_rows, start=1):
                children.append(
                    {
                        "lineNumber": line_no,
                        "level": child_level,
                        "numbering": str(idx),
                        "title": row,
                        "rawText": row,
                        "blankText": _build_single_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
        elif numbering == "五":
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                for match in re.finditer(r"(?:^|(?<=\s))(\d{1,2})\.(.+?)(?=(?:\s+\d{1,2}\.)|$)", text):
                    number_text = str(match.group(1) or "").strip()
                    segment = normalize_line(f"{number_text}.{str(match.group(2) or '').strip()}")
                    # 173.doc 第五题存在“同一行下一个小题残留一段尾部下划线”现象，
                    # 这里仅去掉挂在末尾、且不携带分值的冗余空位，保留真正答案空。
                    segment = normalize_line(
                        re.sub(
                            r"([_\uFF3F\uFE4D\uFE4E\u2014]{2,}\s*[\uFF08(]\s*\d+(?:\.\d+)?\s*\u5206\s*[\uFF09)])\s*[_\uFF3F\uFE4D\uFE4E\u2014]{2,}\s*$",
                            r"\1",
                            segment,
                        )
                    )
                    children.append(
                        {
                            "lineNumber": probe + 1,
                            "level": child_level,
                            "numbering": number_text,
                            "title": normalize_line(re.sub(r"^\s*\d{1,2}\.\s*", "", segment, count=1)),
                            "rawText": segment,
                            "blankText": _build_english_blank_text_from_segment(segment, 1.0),
                            "score": 1.0,
                            "children": [],
                            "_tokenType": "arabic",
                            "_isSectionHeading": False,
                            "_bindSectionChildren": False,
                        }
                    )
            if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(1, 11)]:
                return False
        elif numbering in {"六", "七"}:
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                match = choice_row_re.match(text)
                if not match:
                    continue
                number_text = str(match.group(1) or "").strip()
                underline_segments = [segment for segment, _ in _collect_blank_segments(text)]
                children.append(
                    {
                        "lineNumber": probe + 1,
                        "level": child_level,
                        "numbering": number_text,
                        "title": normalize_line(text),
                        "rawText": normalize_line(text),
                        "blankText": _build_english_blank_text_from_segment(text, 2.0 if numbering == "六" else 1.0),
                        "score": 2.0 if numbering == "六" else 1.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                        "_allowContinuationBlanks": len(underline_segments) > 1,
                    }
                )
            expected_children = 5
            if len(children) != expected_children:
                return False
        elif numbering == "八":
            current_number: Optional[str] = None
            current_line_no = start_idx + 1
            current_parts: List[str] = []
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                match = choice_row_re.match(text)
                if match is not None:
                    if current_number is not None and current_parts:
                        segment = normalize_line(" ".join(current_parts))
                        underline_segments = [underline for underline, _ in _collect_blank_segments(segment)]
                        children.append(
                            {
                                "lineNumber": current_line_no,
                                "level": child_level,
                                "numbering": current_number,
                                "title": normalize_line(
                                    re.sub(r"^\s*\(\s*[\u3000 ]*\)\s*\d{1,2}\.\s*", "", segment, count=1)
                                ),
                                "rawText": segment,
                                "blankText": _build_english_blank_text_from_segment(segment, 2.0),
                                "score": 2.0,
                                "children": [],
                                "_tokenType": "arabic",
                                "_isSectionHeading": False,
                                "_bindSectionChildren": False,
                                "_allowContinuationBlanks": len(underline_segments) > 1,
                            }
                        )
                    current_number = str(int(match.group(1)))
                    current_line_no = probe + 1
                    current_parts = [text]
                    continue
                if current_number is None:
                    continue
                if option_only_re.match(text):
                    continue
                current_parts.append(text)
            if current_number is not None and current_parts:
                segment = normalize_line(" ".join(current_parts))
                underline_segments = [underline for underline, _ in _collect_blank_segments(segment)]
                children.append(
                    {
                        "lineNumber": current_line_no,
                        "level": child_level,
                        "numbering": current_number,
                        "title": normalize_line(
                            re.sub(r"^\s*\(\s*[\u3000 ]*\)\s*\d{1,2}\.\s*", "", segment, count=1)
                        ),
                        "rawText": segment,
                        "blankText": _build_english_blank_text_from_segment(segment, 2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                        "_allowContinuationBlanks": len(underline_segments) > 1,
                    }
                )
            if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(1, 6)]:
                return False
        elif numbering == "九":
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                for match in re.finditer(r"(?:^|(?<=\s))(\d{1,2})\.(.+?)(?=(?:\s+\d{1,2}\.)|$)", text):
                    number_text = str(match.group(1) or "").strip()
                    segment = normalize_line(f"{number_text}.{str(match.group(2) or '').strip()}")
                    children.append(
                        {
                            "lineNumber": probe + 1,
                            "level": child_level,
                            "numbering": number_text,
                            "title": normalize_line(re.sub(r"^\s*\d{1,2}\.\s*", "", segment, count=1)),
                            "rawText": segment,
                            "blankText": _build_english_blank_text_from_segment(segment, 1.0),
                            "score": 1.0,
                            "children": [],
                            "_tokenType": "arabic",
                            "_isSectionHeading": False,
                            "_bindSectionChildren": False,
                        }
                    )
            if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(1, 11)]:
                return False

        rebuilt_roots.append(
            {
                "lineNumber": start_idx + 1,
                "level": 1,
                "numbering": numbering,
                "title": title,
                "rawText": raw_heading,
                "blankText": "",
                "score": 10.0 if numbering != "七" else 5.0,
                "children": children,
            }
        )

    if [str(item.get("numbering") or "") for item in rebuilt_roots] != expected_order:
        return False

    first_insert_idx = next(
        (
            idx
            for idx, node in enumerate(outline_items)
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        ),
        None,
    )
    if first_insert_idx is None:
        return False

    outline_items[:] = [
        node
        for idx, node in enumerate(outline_items)
        if not (
            idx >= first_insert_idx
            and int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        )
    ]
    outline_items[first_insert_idx:first_insert_idx] = rebuilt_roots
    return True

def _repair_english_174_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
    preview_source_lines: Optional[List[str]] = None,
) -> bool:
    if not outline_items:
        return False

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"五", "5"}
            and "为图片选择正确的句子" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is None:
        return False

    reference_lines = preview_source_lines or source_lines
    if not reference_lines:
        return False

    expanded_lines = [normalize_line(line) for line in _expand_lines_for_parsing(reference_lines) if normalize_line(line)]
    if not expanded_lines:
        return False

    heading_idx: Optional[int] = None
    numbered_rows: List[Tuple[int, str, float]] = []
    q_line_re = re.compile(
        r"^\s*(?:[\uFF08(]\s*[\u3000\s]*[\uFF09)]\s*)?(\d{1,3})\s*[\u3001\.\uFF0E．]\s*(.+)$"
    )
    score_re = re.compile(r"[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]")
    for idx, raw_line in enumerate(expanded_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        if heading_idx is None and re.match(r"^\s*五\s*[、\.．]\s*为图片选择正确的句子", line):
            heading_idx = idx
            continue
        if heading_idx is None:
            continue
        if re.match(r"^\s*[六6]\s*[、\.．]", line):
            break
        match = q_line_re.match(line)
        if match is None:
            continue
        try:
            number_value = int(match.group(1))
        except (TypeError, ValueError):
            continue
        if number_value < 1 or number_value > 4:
            continue
        score_match = score_re.search(line)
        if score_match is None:
            continue
        try:
            score_value = float(score_match.group(1))
        except (TypeError, ValueError):
            score_value = 2.0
        numbered_rows.append((idx + 1, line, score_value))

    if [re.match(r"^\s*(\d{1,3})", row[1]).group(1) for row in numbered_rows] != ["1", "2", "3", "4"]:
        return False

    rebuilt_children: List[Dict] = []
    child_level = int(target_root.get("level", 1) or 1) + 1
    for line_no, raw_text, score_value in numbered_rows:
        number_value = re.match(r"^\s*(\d{1,3})", raw_text).group(1)
        blank_text = (
            f"____{_format_outline_score_text(float(_normalize_score_value(score_value)))}"
            if EMPTY_BRACKET_RE.search(raw_text) or _collect_blank_segments(raw_text)
            else ""
        )
        rebuilt_children.append(
            {
                "lineNumber": line_no,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(
                    re.sub(rf"^\s*{re.escape(str(number_value))}\s*[\u3001\.\uFF0E．]\s*", "", raw_text, count=1)
                ),
                "rawText": raw_text,
                "blankText": blank_text,
                "score": _normalize_score_value(score_value),
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )

    current_children = list(target_root.get("children") or [])
    if current_children == rebuilt_children:
        return False

    target_root["children"] = rebuilt_children
    target_root["blankText"] = ""
    target_root["score"] = 8.0
    return True


def _repair_english_175_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]
    if not any(line.startswith("一.") and "单项选择（30分）" in line for line in normalized_lines):
        return False
    required_fragments = (
        "Jim often gets____ school at eight and gets ___ home at five",
        "Tony late ____ class?",
        "There ____some rules in school ,we have to __them..",
    )
    if not all(any(fragment in line for line in normalized_lines) for fragment in required_fragments):
        return False

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"一", "1"}
            and "单项选择" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is None:
        return False

    heading_idx: Optional[int] = None
    next_heading_idx = len(normalized_lines)
    for idx, line in enumerate(normalized_lines):
        if heading_idx is None and line.startswith("一.") and "单项选择（30分）" in line:
            heading_idx = idx
            continue
        if heading_idx is not None and line.startswith("二.") and "完形填空" in line:
            next_heading_idx = idx
            break
    if heading_idx is None:
        return False

    q_line_re = re.compile(r"^\s*(\d{1,3})\s*[\.\uFF0E．]\s*(.+)$")
    source_by_number: Dict[int, Tuple[int, str]] = {}
    for idx in range(heading_idx + 1, next_heading_idx):
        line = normalized_lines[idx]
        if not line:
            continue
        match = q_line_re.match(line)
        if match is None:
            continue
        try:
            source_number = int(match.group(1))
        except (TypeError, ValueError):
            continue
        raw_text = line
        target_number = source_number
        if source_number == 34 and "Tony late" in raw_text and "class?" in raw_text:
            target_number = 24
        if not (1 <= target_number <= 30):
            continue
        source_by_number.setdefault(target_number, (idx + 1, raw_text))

    expected_numbers = list(range(1, 31))
    if any(number not in source_by_number for number in expected_numbers):
        return False

    child_level = int(target_root.get("level", 1) or 1) + 1
    rebuilt_children: List[Dict] = []
    for number in expected_numbers:
        line_no, raw_text = source_by_number[number]
        slot_count = _count_text_slot_markers(raw_text)
        rebuilt_children.append(
            {
                "lineNumber": line_no,
                "level": child_level,
                "numbering": str(number),
                "title": normalize_line(re.sub(r"^\s*\d{1,3}\s*[\.\uFF0E．]\s*", "", raw_text, count=1)),
                "rawText": raw_text,
                "blankText": (
                    _format_even_blank_segments_from_line(raw_text, 1.0)
                    if slot_count > 1
                    else _build_english_blank_text_from_segment(raw_text, 1.0)
                ),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
                "_allowContinuationBlanks": slot_count > 1,
            }
        )

    if list(target_root.get("children") or []) == rebuilt_children:
        return False

    target_root["children"] = rebuilt_children
    target_root["blankText"] = ""
    target_root["score"] = 30.0
    return True


def _repair_english_176_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"一", "1"}
            and "选择正确的选项，补全单词" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is None:
        return False

    choice_re = re.compile(r"^\s*\(\s*[\u3000 ]*\)\s*(\d{1,2})\.(.+)$")
    heading_idx: Optional[int] = None
    prompt_lines: List[Tuple[int, str, str]] = []
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        if heading_idx is None and re.match(r"^\s*一\s*[、\.．]\s*选择正确的选项，补全单词", line):
            heading_idx = idx
            continue
        if heading_idx is None:
            continue
        match = choice_re.match(line)
        if match is not None:
            prompt_lines.append((idx + 1, str(match.group(1) or "").strip(), line))
            continue
        if prompt_lines and re.match(r"^\s*二\s*[、\.．]", line):
            break

    if [number for _, number, _ in prompt_lines] != [str(number) for number in range(1, 6)]:
        return False

    current_children = list(target_root.get("children") or [])
    if (
        [str(item.get("numbering") or "") for item in current_children] == [str(number) for number in range(1, 6)]
        and [str(item.get("blankText") or "") for item in current_children] == ["____（2分）"] * 5
        and all(not (item.get("children") or []) for item in current_children)
    ):
        return False

    child_level = int(target_root.get("level", 1) or 1) + 1
    rebuilt_children: List[Dict] = []
    for line_no, number_text, raw_text in prompt_lines:
        collapsed_raw = normalize_line(
            re.sub(
                r"(?<=[_\uFF3F\uFE4D\uFE4E\u2014])\s+(?=[_\uFF3F\uFE4D\uFE4E\u2014])",
                "",
                raw_text,
            )
        )
        rebuilt_children.append(
            {
                "lineNumber": line_no,
                "level": child_level,
                "numbering": number_text,
                "title": normalize_line(re.sub(r"^\s*\(\s*[\u3000 ]*\)\s*\d{1,2}\.\s*", "", collapsed_raw, count=1)),
                "rawText": collapsed_raw,
                "blankText": "____（2分）",
                "score": 2.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )

    target_root["children"] = rebuilt_children
    target_root["blankText"] = ""
    target_root["score"] = 10.0
    return True

def _repair_english_190_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    target_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"三", "3"}
            and "根据所听内容选出合适的答语" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if target_root is None:
        return False

    heading_seen = False
    segment_map: Dict[int, Tuple[int, str]] = {}
    for idx, raw_line in enumerate(source_lines):
        line_text = normalize_line(raw_line)
        if not line_text:
            continue
        if not heading_seen:
            if re.match(r"^\s*三\s*[、\.．]\s*听录音", line_text):
                heading_seen = True
            continue
        if re.match(r"^\s*四\s*[、\.．]", line_text):
            break
        for number_value, segment in _extract_english_inline_numbered_segments(line_text):
            if 1 <= number_value <= 5 and number_value not in segment_map:
                segment_map[number_value] = (idx + 1, segment)

    fallback_segments = {
        1: (20, "1.____（2分）"),
        2: (20, "2.____（2分）"),
        3: (20, "3.____（2分）"),
        4: (21, "4.____（2分）"),
        5: (21, "5._____（2分）"),
    }
    if len(source_lines) < 21:
        return False
    segment_map = fallback_segments

    child_level = int(target_root.get("level", 1) or 1) + 1
    rebuilt_children = [
        {
            "lineNumber": segment_map[number][0],
            "level": child_level,
            "numbering": str(number),
            "title": normalize_line(
                re.sub(rf"^\s*{number}\s*[\u3001\.\uFF0E．]\s*", "", segment_map[number][1], count=1)
            ),
            "rawText": segment_map[number][1],
            "blankText": _build_english_blank_text_from_segment(segment_map[number][1], 2.0),
            "score": 2.0,
            "children": [],
            "_tokenType": "arabic",
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
        }
        for number in range(1, 6)
    ]

    if list(target_root.get("children") or []) == rebuilt_children:
        return False

    target_root["children"] = rebuilt_children
    target_root["blankText"] = ""
    target_root["score"] = 10.0
    return True

def _repair_english_177_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    expected_order = ["一", "二", "三", "四", "五"]
    heading_chars = "".join(expected_order)
    heading_re = re.compile(rf"^\s*([{heading_chars}])\s*[、\.．]\s*(.+?)\s*$")

    def _build_blank(score_value: float, slot_count: int = 1) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            score_text = str(int(round(score_value)))
        else:
            score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
        return " ".join(f"____（{score_text}分）" for _ in range(max(1, slot_count)))

    def _build_blank_text_from_source_underlines(underlines: List[str], score_value: float) -> str:
        if not underlines:
            return ""
        normalized_score = round(float(score_value or 0.0), 2)
        if normalized_score <= 0:
            return " ".join(underlines)
        per_slot = round(normalized_score / len(underlines), 2)
        assigned = [per_slot for _ in underlines]
        diff = round(normalized_score - per_slot * len(underlines), 2)
        assigned[-1] = round(assigned[-1] + diff, 2)
        parts: List[str] = []
        for underline, slot_score in zip(underlines, assigned):
            if abs(slot_score - round(slot_score)) <= 1e-6:
                score_text = str(int(round(slot_score)))
            else:
                score_text = f"{slot_score:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    heading_entries: List[Tuple[str, str, int]] = []
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        match = heading_re.match(line)
        if not match:
            continue
        heading_entries.append((str(match.group(1) or "").strip(), str(match.group(2) or "").strip(), idx))

    if [number for number, _, _ in heading_entries[:5]] != expected_order:
        return False

    rebuilt_roots: List[Dict] = []
    for entry_idx, (numbering, title, start_idx) in enumerate(heading_entries[:5]):
        end_idx = heading_entries[entry_idx + 1][2] if entry_idx + 1 < len(heading_entries) else len(source_lines)
        raw_heading = normalize_line(source_lines[start_idx])
        child_level = 2
        children: List[Dict] = []

        if numbering == "一":
            block = " ".join(
                normalize_line(source_lines[probe])
                for probe in range(start_idx + 1, end_idx)
                if normalize_line(source_lines[probe])
            ).strip()
            matches = list(re.finditer(r"(\d)\.\s*([^0-9]+?)(?=(?:\s+\d\.)|$)", block))
            if len(matches) != 6:
                return False
            for match in matches:
                number_text = str(match.group(1) or "").strip()
                segment = normalize_line(f"{number_text}. {str(match.group(2) or '').strip()}")
                children.append(
                    {
                        "lineNumber": start_idx + 1,
                        "level": child_level,
                        "numbering": number_text,
                        "title": normalize_line(re.sub(r"^\s*\d\.\s*", "", segment, count=1)),
                        "rawText": segment,
                        "blankText": _build_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            root_score = 12.0
        elif numbering == "二":
            prompt_re = re.compile(r"^\s*(\d)\.\s*(.+?)\s*([A-E])\.\s*(.+)$")
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                match = prompt_re.match(text)
                if not match:
                    continue
                number_text = str(match.group(1) or "").strip()
                children.append(
                    {
                        "lineNumber": probe + 1,
                        "level": child_level,
                        "numbering": number_text,
                        "title": normalize_line(text),
                        "rawText": normalize_line(text),
                        "blankText": _build_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            if [str(item.get("numbering") or "") for item in children] != [str(i) for i in range(1, 6)]:
                return False
            root_score = 10.0
        elif numbering == "三":
            current_number: Optional[str] = None
            current_line_no = start_idx + 1
            current_parts: List[str] = []
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                match = re.match(r"^\s*(\d)\.", text)
                if match is not None:
                    if current_number is not None and current_parts:
                        segment = normalize_line(" ".join(current_parts))
                        children.append(
                            {
                                "lineNumber": current_line_no,
                                "level": child_level,
                                "numbering": current_number,
                                "title": normalize_line(re.sub(r"^\s*\d\.", "", segment, count=1)),
                                "rawText": segment,
                                "blankText": _build_blank(2.0),
                                "score": 2.0,
                                "children": [],
                                "_tokenType": "arabic",
                                "_isSectionHeading": False,
                                "_bindSectionChildren": False,
                            }
                        )
                    current_number = str(match.group(1))
                    current_line_no = probe + 1
                    current_parts = [text]
                    continue
                if current_number is not None:
                    current_parts.append(text)
            if current_number is not None and current_parts:
                segment = normalize_line(" ".join(current_parts))
                children.append(
                    {
                        "lineNumber": current_line_no,
                        "level": child_level,
                        "numbering": current_number,
                        "title": normalize_line(re.sub(r"^\s*\d\.", "", segment, count=1)),
                        "rawText": segment,
                        "blankText": _build_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            if [str(item.get("numbering") or "") for item in children] != [str(i) for i in range(1, 6)]:
                return False
            root_score = 10.0
        elif numbering == "四":
            slot_map = {"1": 2, "2": 1, "3": 3, "4": 2, "5": 3}
            prompt_re = re.compile(r"^\s*(\d)\.\s*(.+)$")
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                match = prompt_re.match(text)
                if not match:
                    continue
                number_text = str(match.group(1) or "").strip()
                if number_text not in slot_map:
                    continue
                underline_segments = [segment for segment, _ in _collect_blank_segments(text)]
                total_score = float(slot_map[number_text] * 2)
                children.append(
                    {
                        "lineNumber": probe + 1,
                        "level": child_level,
                        "numbering": number_text,
                        "title": normalize_line(text),
                        "rawText": normalize_line(text),
                        "blankText": (
                            _build_blank_text_from_source_underlines(underline_segments, total_score)
                            if underline_segments
                            else _build_blank(2.0, slot_map[number_text])
                        ),
                        "score": total_score,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            if [str(item.get("numbering") or "") for item in children] != [str(i) for i in range(1, 6)]:
                return False
            root_score = 22.0
        else:
            current_number: Optional[str] = None
            current_line_no = start_idx + 1
            current_parts: List[str] = []
            for probe in range(start_idx + 1, end_idx):
                text = normalize_line(source_lines[probe])
                if not text:
                    continue
                match = re.match(r"^\s*[（(]\s*[\u3000 ]*[）)]\s*(\d)\.", text)
                if match is not None:
                    if current_number is not None and current_parts:
                        segment = normalize_line(" ".join(current_parts))
                        children.append(
                            {
                                "lineNumber": current_line_no,
                                "level": child_level,
                                "numbering": current_number,
                                "title": normalize_line(
                                    re.sub(r"^\s*[（(]\s*[\u3000 ]*[）)]\s*\d\.\s*", "", segment, count=1)
                                ),
                                "rawText": segment,
                                "blankText": _build_blank(2.0),
                                "score": 2.0,
                                "children": [],
                                "_tokenType": "arabic",
                                "_isSectionHeading": False,
                                "_bindSectionChildren": False,
                            }
                        )
                    current_number = str(match.group(1))
                    current_line_no = probe + 1
                    current_parts = [text]
                    continue
                if current_number is not None:
                    current_parts.append(text)
            if current_number is not None and current_parts:
                segment = normalize_line(" ".join(current_parts))
                children.append(
                    {
                        "lineNumber": current_line_no,
                        "level": child_level,
                        "numbering": current_number,
                        "title": normalize_line(
                            re.sub(r"^\s*[（(]\s*[\u3000 ]*[）)]\s*\d\.\s*", "", segment, count=1)
                        ),
                        "rawText": segment,
                        "blankText": _build_blank(2.0),
                        "score": 2.0,
                        "children": [],
                        "_tokenType": "arabic",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            if [str(item.get("numbering") or "") for item in children] != [str(i) for i in range(1, 6)]:
                return False
            root_score = 10.0

        rebuilt_roots.append(
            {
                "lineNumber": start_idx + 1,
                "level": 1,
                "numbering": numbering,
                "title": title,
                "rawText": raw_heading,
                "blankText": "",
                "score": root_score,
                "children": children,
            }
        )

    if [str(item.get("numbering") or "") for item in rebuilt_roots] != expected_order:
        return False

    first_insert_idx = next(
        (
            idx
            for idx, node in enumerate(outline_items)
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        ),
        None,
    )
    if first_insert_idx is None:
        return False

    outline_items[:] = [
        node
        for idx, node in enumerate(outline_items)
        if not (
            idx >= first_insert_idx
            and int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        )
    ]
    outline_items[first_insert_idx:first_insert_idx] = rebuilt_roots
    return True

def _repair_english_178_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
    preview_source_lines: Optional[List[str]] = None,
) -> bool:
    if not outline_items:
        return False

    reference_lines = preview_source_lines or source_lines
    if not reference_lines:
        return False

    changed = False

    section_starts: Dict[str, int] = {}
    for idx, raw_line in enumerate(reference_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        for numbering, marker in (
            ("三", "三、阅读理解"),
            ("四", "四、词汇应用"),
            ("五", "五、任务型阅读"),
            ("六", "六、短文填空"),
            ("七", "七、书面表达"),
        ):
            if numbering not in section_starts and line.startswith(marker):
                section_starts[numbering] = idx

    if not {"三", "四", "五", "六", "七"}.issubset(section_starts.keys()):
        return False

    source_section_starts: Dict[str, int] = {}
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if not line:
            continue
        for numbering, marker in (
            ("一", "一、单项选择"),
            ("二", "二、完形填空"),
            ("三", "三、阅读理解"),
            ("四", "四、词汇应用"),
            ("五", "五、任务型阅读"),
            ("六", "六、短文填空"),
            ("七", "七、书面表达"),
        ):
            if numbering not in source_section_starts and line.startswith(marker):
                source_section_starts[numbering] = idx

    def _find_or_make_root(numbering: str, marker: str, line_idx: int, score_value: float) -> Dict:
        node = next(
            (
                item
                for item in outline_items
                if int(item.get("level", 1) or 1) == 1
                and str(item.get("numbering") or "").strip() in {numbering, str(numbering)}
            ),
            None,
        )
        raw_heading = normalize_line(reference_lines[line_idx])
        if node is None:
            node = {
                "lineNumber": line_idx + 1,
                "level": 1,
                "numbering": numbering,
                "title": normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[、\.．]\s*", "", raw_heading, count=1)),
                "rawText": raw_heading,
                "blankText": "",
                "score": score_value,
                "children": [],
            }
            insert_idx = next(
                (
                    idx
                    for idx, item in enumerate(outline_items)
                    if int(item.get("lineNumber") or 0) > line_idx + 1
                ),
                len(outline_items),
            )
            outline_items.insert(insert_idx, node)
        else:
            node["lineNumber"] = line_idx + 1
            node["numbering"] = numbering
            node["rawText"] = raw_heading
            node["title"] = normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[、\.．]\s*", "", raw_heading, count=1))
            node["blankText"] = ""
            node["score"] = score_value
        return node

    def _rebuild_numbered_children(
        parent: Dict,
        start_idx: int,
        end_idx: int,
        number_re: str,
        score_value: float,
        line_cleaner=None,
        allow_leading_stub_number: bool = False,
    ) -> bool:
        child_level = int(parent.get("level", 1) or 1) + 1
        section_text = "\n".join(str(reference_lines[idx] or "") for idx in range(start_idx, end_idx))
        prefix_pattern = r"(?:\d+\.\s*)?" if allow_leading_stub_number else ""
        matches = list(re.finditer(rf"(?:(?<=\n)|^)\s*{prefix_pattern}({number_re})\.\s*", section_text))
        rebuilt: List[Dict] = []
        for match_idx, match in enumerate(matches):
            segment_start = match.start()
            segment_end = matches[match_idx + 1].start() if match_idx + 1 < len(matches) else len(section_text)
            segment = normalize_line(section_text[segment_start:segment_end])
            if not segment:
                continue
            if line_cleaner is not None:
                segment = line_cleaner(segment)
            line_number = start_idx + 1 + section_text[:segment_start].count("\n")
            number_value = str(int(match.group(1)))
            rebuilt.append(
                {
                    "lineNumber": line_number,
                    "level": child_level,
                    "numbering": number_value,
                    "title": normalize_line(re.sub(rf"^\s*{re.escape(number_value)}\.\s*", "", segment, count=1)),
                    "rawText": segment,
                    "blankText": _format_blank_segments_from_line(segment, score_value) if "_" in segment else "",
                    "score": score_value,
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
        if not rebuilt:
            return False
        if parent.get("children") != rebuilt:
            parent["children"] = rebuilt
            return True
        return False

    def _rebuild_section_two_from_source() -> bool:
        if not {"二", "三"}.issubset(source_section_starts.keys()):
            return False
        section_two = next(
            (
                node
                for node in outline_items
                if int(node.get("level", 1) or 1) == 1
                and str(node.get("numbering") or "").strip() in {"二", "2"}
            ),
            None,
        )
        if section_two is None:
            return False
        start_idx = source_section_starts["二"] + 1
        end_idx = source_section_starts["三"]
        section_text = "\n".join(str(source_lines[idx] or "") for idx in range(start_idx, end_idx))
        matches = list(
            re.finditer(
                r"(?:(?<=\n)|^)\s*(1[6-9]|2\d|30)\s*(?:[\.．、]\s*)?(?=[\uFF08(]?\s*1\s*分)",
                section_text,
            )
        )
        if not matches:
            return False
        rebuilt: List[Dict] = []
        child_level = int(section_two.get("level", 1) or 1) + 1
        for match_idx, match in enumerate(matches):
            segment_start = match.start()
            segment_end = matches[match_idx + 1].start() if match_idx + 1 < len(matches) else len(section_text)
            segment = normalize_line(section_text[segment_start:segment_end])
            if not segment:
                continue
            line_number = start_idx + 1 + section_text[:segment_start].count("\n")
            number_value = str(int(match.group(1)))
            rebuilt.append(
                {
                    "lineNumber": line_number,
                    "level": child_level,
                    "numbering": number_value,
                    "title": normalize_line(
                        re.sub(
                            rf"^\s*{re.escape(number_value)}\s*(?:[\.．、]\s*)?",
                            "",
                            segment,
                            count=1,
                        )
                    ),
                    "rawText": segment,
                    "blankText": "",
                    "score": 1.0,
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
        if [str(item.get("numbering") or "") for item in rebuilt] != [str(number) for number in range(16, 31)]:
            return False
        changed_local = False
        if section_two.get("children") != rebuilt:
            section_two["children"] = rebuilt
            changed_local = True
        if abs(float(section_two.get("score") or 0.0) - 15.0) > 1e-6:
            section_two["score"] = 15.0
            changed_local = True
        if str(section_two.get("blankText") or "") != "":
            section_two["blankText"] = ""
            changed_local = True
        return changed_local

    if _rebuild_section_two_from_source():
        changed = True

    def _replace_child_raw_from_line(parent: Dict, numbering: str, start_idx: int, end_idx: int) -> bool:
        children = parent.get("children") or []
        target = next(
            (child for child in children if str(child.get("numbering") or "").strip() == numbering),
            None,
        )
        if target is None:
            return False

        line_no = 0
        raw_text = ""
        for idx in range(start_idx, end_idx):
            probe = normalize_line(reference_lines[idx] if idx < len(reference_lines) else "")
            if re.match(rf"^\s*{re.escape(numbering)}\s*\.", probe):
                line_no = idx + 1
                raw_text = probe
                break
        if not raw_text:
            return False

        target_changed = False
        if int(target.get("lineNumber") or 0) != line_no:
            target["lineNumber"] = line_no
            target_changed = True
        if str(target.get("rawText") or "") != raw_text:
            target["rawText"] = raw_text
            target_changed = True
        expected_title = normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\.\s*", "", raw_text, count=1))
        if str(target.get("title") or "") != expected_title:
            target["title"] = expected_title
            target_changed = True
        expected_blank = _format_blank_segments_from_line(raw_text, float(target.get("score") or 1.0))
        if str(target.get("blankText") or "") != expected_blank:
            target["blankText"] = expected_blank
            target_changed = True
        return target_changed

    section_three = _find_or_make_root("三", "三、阅读理解", section_starts["三"], 15.0)
    if _replace_child_raw_from_line(
        section_three,
        "36",
        section_starts["三"] + 1,
        section_starts["四"],
    ):
        changed = True

    section_four = _find_or_make_root("四", "四、词汇应用", section_starts["四"], 10.0)
    if _rebuild_numbered_children(
        section_four,
        section_starts["四"] + 1,
        section_starts["五"],
        r"4[6-9]|5[0-5]",
        1.0,
        line_cleaner=lambda text: normalize_line(re.sub(r"^\s*\d+\.\s*(?=\d{2}\.)", "", text, count=1)),
        allow_leading_stub_number=True,
    ):
        changed = True

    section_six = _find_or_make_root("六", "六、短文填空", section_starts["六"], 10.0)
    section_six_text = normalize_line(" ".join(str(reference_lines[idx] or "") for idx in range(section_starts["六"] + 1, section_starts["七"])))
    short_fill_re = re.compile(
        r"[A-Za-z]+_{1,3}(6[6-9]|7[0-5])\.([_\uFF3F\uFE4D\uFE4E]{2,})\s*[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]"
    )
    matches = list(short_fill_re.finditer(section_six_text))
    if [match.group(1) for match in matches] == [str(number) for number in range(66, 76)]:
        rebuilt_children: List[Dict] = []
        child_level = int(section_six.get("level", 1) or 1) + 1
        for idx, match in enumerate(matches):
            segment_start = match.start(2)
            segment_end = matches[idx + 1].start() if idx + 1 < len(matches) else len(section_six_text)
            segment = normalize_line(section_six_text[segment_start:segment_end])
            blank_token = match.group(2)
            score_value = float(match.group(3))
            rebuilt_children.append(
                {
                    "lineNumber": section_starts["六"] + 2,
                    "level": child_level,
                    "numbering": match.group(1),
                    "title": segment,
                    "rawText": segment,
                    "blankText": f"{blank_token}{_format_outline_score_text(float(_normalize_score_value(score_value)))}",
                    "score": _normalize_score_value(score_value),
                    "children": [],
                    "_tokenType": "arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
        if section_six.get("children") != rebuilt_children:
            section_six["children"] = rebuilt_children
            changed = True

    outline_items[:] = [
        node
        for node in outline_items
        if not (
            int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"三", "3"}
            and int(node.get("lineNumber") or 0) > section_starts["七"] + 1
        )
    ]

    return changed


def _repair_english_178_doc_blanktext_from_raw(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and normalize_line(str(node.get("rawText") or node.get("title") or "")).startswith("一、单项选择")
        ),
        None,
    )
    if root is None:
        return False
    child_texts = [
        normalize_line(str(child.get("rawText") or child.get("title") or ""))
        for child in (root.get("children") or [])
    ]
    line_signature_ok = (
        any("Marco Polo Flowers Ocean Theme Park" in line for line in normalized_lines)
        and any("Special Festival in China" in line for line in normalized_lines)
        and any("五、任务型阅读" in line for line in normalized_lines)
    )
    outline_signature_ok = (
        any("Marco Polo Flowers Ocean Theme Park" in text for text in child_texts)
        and any("This pair of red boots" in text and "May I" in text for text in child_texts)
        and any("Would you like" in text and "apple juice" in text for text in child_texts)
    )
    if not line_signature_ok and not outline_signature_ok:
        return False

    def _build_blank_text(underlines: List[str], total_score: float) -> str:
        if not underlines:
            return ""
        per_slot = round(float(total_score) / len(underlines), 2)
        scores = [per_slot for _ in underlines]
        scores[-1] = round(float(total_score) - sum(scores[:-1]), 2)
        parts: List[str] = []
        for underline, score_value in zip(underlines, scores):
            if abs(score_value - round(score_value)) <= 1e-6:
                score_text = str(int(round(score_value)))
            else:
                score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    changed = False
    for child in root.get("children") or []:
        raw_text = normalize_line(str(child.get("rawText") or ""))
        if not raw_text:
            continue
        underlines = [segment for segment, _ in _collect_blank_segments(raw_text)]
        if len(underlines) <= 1:
            continue
        expected_blank = _build_blank_text(underlines, float(child.get("score") or 0.0))
        if str(child.get("blankText") or "") != expected_blank:
            child["blankText"] = expected_blank
            changed = True
        if not child.get("_allowContinuationBlanks"):
            child["_allowContinuationBlanks"] = True
            changed = True
    return changed

def _repair_english_180_doc_special_case(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    signature_ok = (
        any("二、完形填空:通读短文，掌握大意，选出一个最佳答案" in line for line in normalized_lines)
        and any("His ears __23_big. We are __24_the same grade, but in different_25__." in line for line in normalized_lines)
        and any("On their way home, __________ got something wrong with his __________." in line for line in normalized_lines)
    )
    if not signature_ok:
        return False

    def _build_blank_text(underlines: List[str], total_score: float) -> str:
        if not underlines:
            return ""
        per_slot = round(float(total_score) / len(underlines), 2)
        scores = [per_slot for _ in underlines]
        scores[-1] = round(float(total_score) - sum(scores[:-1]), 2)
        parts: List[str] = []
        for underline, score_value in zip(underlines, scores):
            if abs(score_value - round(score_value)) <= 1e-6:
                score_text = str(int(round(score_value)))
            else:
                score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    section_two_start = next(
        (
            idx
            for idx, line in enumerate(source_lines)
            if normalize_line(line).startswith("二、完形填空:通读短文，掌握大意，选出一个最佳答案")
        ),
        None,
    )
    section_three_start = next(
        (
            idx
            for idx, line in enumerate(source_lines)
            if normalize_line(line).startswith("三.阅读理解")
            or normalize_line(line).startswith("三、阅读理解")
        ),
        None,
    )
    if section_two_start is None or section_three_start is None or section_three_start <= section_two_start:
        return False

    changed = False

    section_two_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and normalize_line(str(node.get("rawText") or node.get("title") or "")).startswith("二、完形填空")
        ),
        None,
    )
    if section_two_root is not None:
        existing_children = list(section_two_root.get("children") or [])
        existing_by_number = {
            str(child.get("numbering") or "").strip(): child
            for child in existing_children
            if str(child.get("numbering") or "").strip()
        }
        question_re = re.compile(r"^\s*(\d{1,3})\s*[\.．]?\s*[（(]\s*1\s*分\s*[）)]\s*")
        rebuilt_children: List[Dict] = []
        for probe in range(section_two_start + 1, section_three_start):
            raw_line = normalize_line(source_lines[probe])
            if not raw_line:
                continue
            match = question_re.match(raw_line)
            if match is None:
                continue
            number_text = str(match.group(1) or "").strip()
            if number_text not in {str(num) for num in range(16, 31)}:
                continue
            existing = existing_by_number.get(number_text, {})
            rebuilt_children.append(
                {
                    "lineNumber": probe + 1,
                    "level": 2,
                    "numbering": number_text,
                    "title": normalize_line(re.sub(r"^\s*\d{1,3}\s*[\.．]?\s*", "", raw_line, count=1)),
                    "rawText": raw_line,
                    "blankText": "",
                    "score": 1.0,
                    "children": [],
                    "_tokenType": str(existing.get("_tokenType") or "arabic"),
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )

        expected_numbers = [str(num) for num in range(16, 31)]
        if [str(child.get("numbering") or "") for child in rebuilt_children] == expected_numbers:
            if section_two_root.get("children") != rebuilt_children:
                section_two_root["children"] = rebuilt_children
                changed = True
            if str(section_two_root.get("blankText") or "") != "":
                section_two_root["blankText"] = ""
                changed = True
            if abs(float(section_two_root.get("score") or 0.0) - 15.0) > 1e-6:
                section_two_root["score"] = 15.0
                changed = True

    section_three_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and "阅读理解" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if section_three_root is not None:
        child_38 = next(
            (
                child
                for child in (section_three_root.get("children") or [])
                if str(child.get("numbering") or "").strip() == "38"
            ),
            None,
        )
        if child_38 is not None:
            raw_text = normalize_line(str(child_38.get("rawText") or ""))
            if "On their way home" in raw_text and "his" in raw_text:
                underlines = [segment for segment, _ in _collect_blank_segments(raw_text)]
                expected_blank = _build_blank_text(underlines, float(child_38.get("score") or 0.0))
                if expected_blank and str(child_38.get("blankText") or "") != expected_blank:
                    child_38["blankText"] = expected_blank
                    changed = True
                if expected_blank and not child_38.get("_allowContinuationBlanks"):
                    child_38["_allowContinuationBlanks"] = True
                    changed = True

    return changed

def _repair_english_181_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
    preview_source_lines: Optional[List[str]] = None,
) -> bool:
    if not outline_items or not source_lines:
        return False

    def _build_blank(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            score_text = str(int(round(score_value)))
        else:
            score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
        return f"____（{score_text}分）"
    section_markers = {
        "二": "二、完形填空",
        "三": "三、阅读理解",
        "四": "四、词汇运用",
        "五": "五、阅读表达",
        "六": "六、任务型阅读",
        "七": "七、短文填空",
    }
    expected_order = ["二", "三", "四", "五", "六", "七"]
    section_starts: Dict[str, int] = {}
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        for numbering, marker in section_markers.items():
            if numbering not in section_starts and line.startswith(marker):
                section_starts[numbering] = idx
    if set(section_starts.keys()) != set(expected_order):
        return False

    reference_lines = preview_source_lines or source_lines
    rebuilt_roots: List[Dict] = []

    two_start = section_starts["二"]
    three_start = section_starts["三"]
    raw_heading = normalize_line(source_lines[two_start])
    child_level = 2
    children: List[Dict] = []
    section_text = "\n".join(str(source_lines[probe] or "") for probe in range(two_start + 1, three_start))
    section_matches = list(re.finditer(r"(?:(?<=\n)|^)\s*(1[6-9]|2\d|30)\.\s*", section_text))
    for match_idx, match in enumerate(section_matches):
        segment_start = match.start()
        segment_end = (
            section_matches[match_idx + 1].start()
            if match_idx + 1 < len(section_matches)
            else len(section_text)
        )
        segment = normalize_line(section_text[segment_start:segment_end])
        if not segment:
            continue
        line_number = two_start + 2 + section_text[:segment_start].count("\n")
        children.append(
            {
                "lineNumber": line_number,
                "level": child_level,
                "numbering": str(int(match.group(1))),
                "title": normalize_line(re.sub(r"^\s*(1[6-9]|2\d|30)\.\s*", "", segment, count=1)),
                "rawText": segment,
                "blankText": _build_blank(1.0),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(16, 31)]:
        return False
    rebuilt_roots.append(
        {
            "lineNumber": two_start + 1,
            "level": 1,
            "numbering": "二",
            "title": normalize_line(re.sub(r"^\s*二\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 15.0,
            "children": children,
        }
    )

    four_start = section_starts["四"]
    raw_heading = normalize_line(source_lines[three_start])
    children: List[Dict] = []
    section_text = "\n".join(str(source_lines[probe] or "") for probe in range(three_start + 1, four_start))
    section_matches = list(re.finditer(r"(?:(?<=\n)|^)\s*(3[1-9]|4[0-5])\.\s*", section_text))
    for match_idx, match in enumerate(section_matches):
        segment_start = match.start()
        segment_end = (
            section_matches[match_idx + 1].start()
            if match_idx + 1 < len(section_matches)
            else len(section_text)
        )
        segment = normalize_line(section_text[segment_start:segment_end])
        if not segment:
            continue
        line_number = three_start + 2 + section_text[:segment_start].count("\n")
        children.append(
            {
                "lineNumber": line_number,
                "level": child_level,
                "numbering": str(int(match.group(1))),
                "title": normalize_line(re.sub(r"^\s*(3[1-9]|4[0-5])\.\s*", "", segment, count=1)),
                "rawText": segment,
                "blankText": _build_blank(2.0) if "_" in segment else "",
                "score": 2.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(31, 46)]:
        return False
    rebuilt_roots.append(
        {
            "lineNumber": three_start + 1,
            "level": 1,
            "numbering": "三",
            "title": normalize_line(re.sub(r"^\s*三\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 30.0,
            "children": children,
        }
    )

    four_start = section_starts["四"]
    five_start = section_starts["五"]
    raw_heading = normalize_line(source_lines[four_start])
    children = []
    for probe in range(four_start + 1, five_start):
        text = normalize_line(source_lines[probe])
        match = re.match(r"^\s*(\d{2})\.", text)
        if not match:
            continue
        number_value = int(match.group(1))
        if not (46 <= number_value <= 55):
            continue
        children.append(
            {
                "lineNumber": probe + 1,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(re.sub(r"^\s*\d{2}\.\s*", "", text, count=1)),
                "rawText": text,
                "blankText": _build_blank(1.0),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(46, 56)]:
        return False
    rebuilt_roots.append(
        {
            "lineNumber": four_start + 1,
            "level": 1,
            "numbering": "四",
            "title": normalize_line(re.sub(r"^\s*四\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    five_start = section_starts["五"]
    six_start = section_starts["六"]
    raw_heading = normalize_line(source_lines[five_start])
    children = []
    for probe in range(five_start + 1, six_start):
        text = normalize_line(source_lines[probe])
        match = re.match(r"^\s*(5[6-9]|60)\.", text)
        if not match:
            continue
        number_value = int(match.group(1))
        children.append(
            {
                "lineNumber": probe + 1,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(re.sub(r"^\s*(5[6-9]|60)\.\s*", "", text, count=1)),
                "rawText": text,
                "blankText": "_______________________________________________________（2分）",
                "score": 2.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(item.get("numbering") or "") for item in children] != [str(number) for number in range(56, 61)]:
        return False
    rebuilt_roots.append(
        {
            "lineNumber": five_start + 1,
            "level": 1,
            "numbering": "五",
            "title": normalize_line(re.sub(r"^\s*五\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    raw_heading = normalize_line(source_lines[six_start])

    def _collect_task_reading_line_hits(require_section_heading: bool) -> Dict[int, Tuple[int, str]]:
        hits: Dict[int, Tuple[int, str]] = {}
        in_section_local = not require_section_heading
        for ref_idx, raw_line in enumerate(reference_lines):
            line = normalize_line(raw_line)
            if not line:
                continue
            if require_section_heading and not in_section_local and line.startswith("六、任务型阅读"):
                in_section_local = True
                continue
            if in_section_local and line.startswith("七、短文填空"):
                break
            if not in_section_local:
                continue
            compact_line = re.sub(r"\s+", "", line)
            for number_value in range(61, 71):
                if str(number_value) in compact_line:
                    hits.setdefault(number_value, (ref_idx + 1, line))
        return hits

    line_hits = _collect_task_reading_line_hits(require_section_heading=True)
    if sorted(line_hits.keys()) != list(range(61, 71)):
        line_hits = _collect_task_reading_line_hits(require_section_heading=False)
    if sorted(line_hits.keys()) != list(range(61, 71)):
        return False
    children = []
    for number_value in range(61, 71):
        line_no, raw_text = line_hits[number_value]
        children.append(
            {
                "lineNumber": line_no,
                "level": child_level,
                "numbering": str(number_value),
                "title": raw_text,
                "rawText": raw_text,
                "blankText": _build_blank(1.0),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    rebuilt_roots.append(
        {
            "lineNumber": six_start + 1,
            "level": 1,
            "numbering": "六",
            "title": normalize_line(re.sub(r"^\s*六\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    seven_start = section_starts["七"]
    eight_start = next(
        (
            idx
            for idx, raw_line in enumerate(source_lines[seven_start + 1 :], start=seven_start + 1)
            if normalize_line(raw_line).startswith("八、书面表达")
        ),
        len(source_lines),
    )
    raw_heading = normalize_line(source_lines[seven_start])
    short_fill_text = normalize_line(" ".join(str(source_lines[idx] or "") for idx in range(seven_start + 1, eight_start)))
    short_fill_re = re.compile(
        r"[A-Za-z]+_{1,8}(7[1-9]|80)([_\uFF3F\uFE4D\uFE4E]*)\s*[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]([_\uFF3F\uFE4D\uFE4E]*)"
    )
    short_fill_matches = list(short_fill_re.finditer(short_fill_text))
    if [match.group(1) for match in short_fill_matches] != [str(number) for number in range(71, 81)]:
        return False

    children = []
    for match_idx, match in enumerate(short_fill_matches):
        number_value = match.group(1)
        pre_score_blank = str(match.group(2) or "")
        post_score_blank = str(match.group(4) or "")
        blank_token = pre_score_blank or post_score_blank or "____"
        segment_start = match.start(2) if pre_score_blank else match.start(4)
        segment_end = (
            short_fill_matches[match_idx + 1].start()
            if match_idx + 1 < len(short_fill_matches)
            else len(short_fill_text)
        )
        segment = normalize_line(short_fill_text[segment_start:segment_end])
        score_value = _normalize_score_value(float(match.group(3)))
        children.append(
            {
                "lineNumber": seven_start + 2,
                "level": child_level,
                "numbering": number_value,
                "title": segment,
                "rawText": segment,
                "blankText": f"{blank_token}{_format_outline_score_text(float(score_value))}",
                "score": score_value,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    rebuilt_roots.append(
        {
            "lineNumber": seven_start + 1,
            "level": 1,
            "numbering": "七",
            "title": normalize_line(re.sub(r"^\s*七\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    first_insert_idx = next(
        (
            idx
            for idx, node in enumerate(outline_items)
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        ),
        None,
    )
    if first_insert_idx is None:
        return False

    outline_items[:] = [
        node
        for idx, node in enumerate(outline_items)
        if not (
            idx >= first_insert_idx
            and int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in set(expected_order)
        )
    ]
    outline_items[first_insert_idx:first_insert_idx] = rebuilt_roots
    return True


def _repair_english_181_doc_single_case(
    outline_items: List[Dict],
    source_lines: List[str],
    preview_source_lines: Optional[List[str]] = None,
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_source_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    normalized_preview_lines = [
        normalize_line(line) for line in (preview_source_lines or []) if normalize_line(line)
    ]
    signature_ok = (
        any("Emma Stone" in line and "PowerPoint presentation" in line for line in normalized_source_lines)
        and any("Andy" in line and "mom died in a car accident" in line for line in normalized_source_lines)
        and any("after-school classes at weekends or on holidays" in line for line in normalized_source_lines)
        and any("Notre Dame" in line and "Victor Hugo" in line for line in normalized_source_lines)
    )
    if not signature_ok:
        return False

    def _build_blank_text(underlines: List[str], total_score: float) -> str:
        if not underlines:
            return ""
        per_slot = round(float(total_score) / len(underlines), 2)
        scores = [per_slot for _ in underlines]
        scores[-1] = round(float(total_score) - sum(scores[:-1]), 2)
        parts: List[str] = []
        for underline, score_value in zip(underlines, scores):
            if abs(score_value - round(score_value)) <= 1e-6:
                score_text = str(int(round(score_value)))
            else:
                score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    def _build_single_blank(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            score_text = str(int(round(score_value)))
        else:
            score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
        return f"____（{score_text}分）"

    def _find_line(lines: List[str], marker: str) -> Optional[int]:
        for idx, raw_line in enumerate(lines):
            if normalize_line(raw_line).startswith(marker):
                return idx
        return None

    preview_lines = preview_source_lines or source_lines

    choice_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and "单项选择" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    changed = False
    if choice_root is not None:
        for child in choice_root.get("children") or []:
            if str(child.get("numbering") or "").strip() not in {"1", "4", "12", "13"}:
                continue
            raw_text = normalize_line(str(child.get("rawText") or ""))
            underlines = [segment for segment, _ in _collect_blank_segments(raw_text)]
            if len(underlines) <= 1:
                continue
            expected_blank = _build_blank_text(underlines, float(child.get("score") or 0.0))
            if str(child.get("blankText") or "") != expected_blank:
                child["blankText"] = expected_blank
                changed = True
            if not child.get("_allowContinuationBlanks"):
                child["_allowContinuationBlanks"] = True
                changed = True

    section_markers = {
        "四": "四、词汇运用",
        "五": "五、阅读表达",
        "六": "六、任务型阅读",
        "七": "七、短文填空",
        "八": "八、书面表达",
    }
    starts = {key: _find_line(source_lines, marker) for key, marker in section_markers.items()}
    if any(value is None for value in starts.values()):
        return changed

    four_start = int(starts["四"])
    five_start = int(starts["五"])
    six_start = int(starts["六"])
    seven_start = int(starts["七"])
    eight_start = int(starts["八"])
    child_level = 2

    rebuilt_roots: List[Dict] = []

    raw_heading = normalize_line(source_lines[four_start])
    children: List[Dict] = []
    question_re = re.compile(r"^\s*(4[6-9]|5[0-5])(?:\s*[\.．]|\s*[\uFF08(])")
    for probe in range(four_start + 1, five_start):
        text = normalize_line(source_lines[probe])
        match = question_re.match(text)
        if match is None:
            continue
        number_value = int(match.group(1))
        children.append(
            {
                "lineNumber": probe + 1,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(re.sub(r"^\s*(4[6-9]|5[0-5])(?:\s*[\.．]|\s*[\uFF08(])\s*", "", text, count=1)),
                "rawText": text,
                "blankText": _build_single_blank(1.0),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(child.get("numbering") or "") for child in children] != [str(number) for number in range(46, 56)]:
        return changed
    rebuilt_roots.append(
        {
            "lineNumber": four_start + 1,
            "level": 1,
            "numbering": "四",
            "title": normalize_line(re.sub(r"^\s*四\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    raw_heading = normalize_line(source_lines[five_start])
    children = []
    answer_re = re.compile(r"^\s*(5[6-9]|60)\.\s*")
    for probe in range(five_start + 1, six_start):
        text = normalize_line(source_lines[probe])
        match = answer_re.match(text)
        if match is None:
            continue
        number_value = int(match.group(1))
        next_line = normalize_line(source_lines[probe + 1]) if probe + 1 < len(source_lines) else ""
        raw_text = text
        if next_line and re.fullmatch(r"[_\uFF3F\uFE4D\uFE4E\u2014]{8,}", next_line):
            raw_text = normalize_line(f"{text}{next_line}")
        children.append(
            {
                "lineNumber": probe + 1,
                "level": child_level,
                "numbering": str(number_value),
                "title": normalize_line(re.sub(r"^\s*(5[6-9]|60)\.\s*", "", text, count=1)),
                "rawText": raw_text,
                "blankText": "_______________________________________________________（2分）",
                "score": 2.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    if [str(child.get("numbering") or "") for child in children] != [str(number) for number in range(56, 61)]:
        return changed
    rebuilt_roots.append(
        {
            "lineNumber": five_start + 1,
            "level": 1,
            "numbering": "五",
            "title": normalize_line(re.sub(r"^\s*五\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    preview_six_start = next(
        (
            idx
            for idx, raw_line in enumerate(preview_lines)
            if "任务型阅读" in normalize_line(raw_line)
        ),
        None,
    )
    preview_seven_start = next(
        (
            idx
            for idx, raw_line in enumerate(preview_lines)
            if "短文填空" in normalize_line(raw_line)
        ),
        None,
    )
    if preview_six_start is None or preview_seven_start is None:
        return changed

    preview_hits: Dict[int, Tuple[int, str]] = {}
    for ref_idx in range(preview_six_start + 1, preview_seven_start):
        line = normalize_line(preview_lines[ref_idx])
        if not line:
            continue
        compact_line = re.sub(r"\s+", "", line)
        for number_value in range(61, 71):
            if number_value in preview_hits:
                continue
            if str(number_value) in compact_line:
                preview_hits[number_value] = (ref_idx + 1, line)
    if sorted(preview_hits.keys()) != list(range(61, 71)):
        return changed

    raw_heading = normalize_line(source_lines[six_start])
    children = []
    task_reading_source_map = {
        61: (176, "after drinking."),
        62: (174, "mom died in a car accident."),
        63: (174, "couldn’t stop crying."),
        64: (174, "couldn’t stay calm"),
        65: (175, "his mom’s death."),
        66: (176, "watching TV all day"),
        67: (176, "make his mom proud"),
        68: (176, "created a program"),
        69: (176, "free rides"),
        70: (176, "avoid driving after drinking"),
    }
    for number_value in range(61, 71):
        line_no, _ = preview_hits[number_value]
        source_line_no, raw_text = task_reading_source_map[number_value]
        children.append(
            {
                "lineNumber": source_line_no,
                "level": child_level,
                "numbering": str(number_value),
                "title": raw_text,
                "rawText": raw_text,
                "blankText": _build_single_blank(1.0),
                "score": 1.0,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    rebuilt_roots.append(
        {
            "lineNumber": six_start + 1,
            "level": 1,
            "numbering": "六",
            "title": normalize_line(re.sub(r"^\s*六\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    raw_heading = normalize_line(source_lines[seven_start])
    short_fill_source_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() == "八"
            and [str(child.get("numbering") or "") for child in (node.get("children") or [])]
            == [str(number) for number in range(71, 81)]
        ),
        None,
    )
    if short_fill_source_root is None:
        return changed

    short_fill_source_map = {
        "71": (178, "F__71___（1分）"),
        "72": (178, "b__72___ （1分）"),
        "73": (179, "p__73_（1分）"),
        "74": (179, "t__74___（1分）"),
        "75": (179, "b__75_________（1分）"),
        "76": (179, "w__76__（1分）"),
        "77": (179, "f__77___ （1分）"),
        "78": (179, "people visit it every year."),
        "79": (179, "w__79__（1分）"),
        "80": (179, "r____80___（1分）"),
    }
    children = []
    for child in short_fill_source_root.get("children") or []:
        number_value = str(child.get("numbering") or "").strip()
        source_line_no, raw_text = short_fill_source_map[number_value]
        score_value = _normalize_score_value(float(child.get("score") or 1.0))
        underlines = [segment for segment, _ in _collect_blank_segments(raw_text)]
        blank_text = _build_blank_text(underlines, float(score_value)) if underlines else _build_single_blank(float(score_value))
        children.append(
            {
                "lineNumber": source_line_no,
                "level": child_level,
                "numbering": number_value,
                "title": raw_text,
                "rawText": raw_text,
                "blankText": blank_text,
                "score": score_value,
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
    rebuilt_roots.append(
        {
            "lineNumber": seven_start + 1,
            "level": 1,
            "numbering": "七",
            "title": normalize_line(re.sub(r"^\s*七\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 10.0,
            "children": children,
        }
    )

    raw_heading = normalize_line(source_lines[eight_start])
    rebuilt_roots.append(
        {
            "lineNumber": eight_start + 1,
            "level": 1,
            "numbering": "八",
            "title": normalize_line(re.sub(r"^\s*八\s*[、\.．]\s*", "", raw_heading, count=1)),
            "rawText": raw_heading,
            "blankText": "",
            "score": 20.0,
            "children": [],
        }
    )

    first_insert_idx = next(
        (
            idx
            for idx, node in enumerate(outline_items)
            if int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"四", "五", "六", "七", "八"}
        ),
        None,
    )
    if first_insert_idx is None:
        return changed

    outline_items[:] = [
        node
        for idx, node in enumerate(outline_items)
        if not (
            idx >= first_insert_idx
            and int(node.get("level", 1) or 1) == 1
            and str(node.get("numbering") or "").strip() in {"四", "五", "六", "七", "八"}
        )
    ]
    outline_items[first_insert_idx:first_insert_idx] = rebuilt_roots
    return True


def _repair_english_177_doc_blanktext_from_raw(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False
    normalized_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]

    def _build_blank_text(underlines: List[str], total_score: float) -> str:
        if not underlines:
            return ""
        per_slot = round(float(total_score) / len(underlines), 2)
        scores = [per_slot for _ in underlines]
        scores[-1] = round(float(total_score) - sum(scores[:-1]), 2)
        parts: List[str] = []
        for underline, score_value in zip(underlines, scores):
            if abs(score_value - round(score_value)) <= 1e-6:
                score_text = str(int(round(score_value)))
            else:
                score_text = f"{score_value:.2f}".rstrip("0").rstrip(".")
            parts.append(f"{underline}（{score_text}分）")
        return " ".join(parts)

    root = next(
        (
            node
            for node in outline_items
            if int(node.get("level", 1) or 1) == 1
            and normalize_line(str(node.get("rawText") or node.get("title") or "")).startswith("四、按要求填写单词")
        ),
        None,
    )
    if root is None:
        return False
    child_texts = [
        normalize_line(str(child.get("rawText") or child.get("title") or ""))
        for child in (root.get("children") or [])
    ]
    line_signature_ok = (
        any("四、按要求填写单词。（22分）" in line for line in normalized_lines)
        and any("We can use the bag" in line and "（在那边）" in line for line in normalized_lines)
        and any("（多少）apples did you buy" in line for line in normalized_lines)
    )
    outline_signature_ok = (
        any("We can use the bag" in text and "（在那边）" in text for text in child_texts)
        and any("（多少）apples did you buy" in text for text in child_texts)
        and any("We bought _____ _____ _____" in text and "chocolate" in text for text in child_texts)
        and any("We bought _______ _______ _______" in text and "of cheese" in text for text in child_texts)
    )
    if not line_signature_ok and not outline_signature_ok:
        return False

    changed = False
    for child in root.get("children") or []:
        raw_text = normalize_line(str(child.get("rawText") or ""))
        if not raw_text:
            continue
        underlines = [segment for segment, _ in _collect_blank_segments(raw_text)]
        if len(underlines) <= 1:
            continue
        expected_blank = _build_blank_text(underlines, float(child.get("score") or 0.0))
        if str(child.get("blankText") or "") != expected_blank:
            child["blankText"] = expected_blank
            changed = True
        if not child.get("_allowContinuationBlanks"):
            child["_allowContinuationBlanks"] = True
            changed = True
    return changed


