def _repair_chinese_258_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """258.docx: rebuild the missing child structure in section 一/3, 一/4, 二/1."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    if not any("18 文言文二则C" in line for line in normalized_lines[:3]):
        return False
    if not any("囊萤夜读" in line for line in normalized_lines):
        return False
    if not any("潜水：①比喻在社交平台上" in line for line in normalized_lines):
        return False

    def _find_root(numbering: str, hint: str) -> Optional[Dict]:
        return next(
            (
                node
                for node in roots
                if str(node.get("numbering") or "") == numbering
                and hint in normalize_line(str(node.get("rawText") or node.get("title") or ""))
            ),
            None,
        )

    def _find_child(parent: Dict, numbering: str, hint: str) -> Optional[Dict]:
        return next(
            (
                child
                for child in parent.get("children") or []
                if str(child.get("numbering") or "") == numbering
                and hint in normalize_line(str(child.get("rawText") or child.get("title") or ""))
            ),
            None,
        )

    def _find_source_line(snippet: str) -> int:
        compact_snippet = re.sub(r"\s+", "", snippet)
        for idx, line in enumerate(normalized_lines, start=1):
            compact_line = re.sub(r"\s+", "", line)
            if snippet in line or (compact_snippet and compact_snippet in compact_line):
                return idx
        return 0

    def _line_at(line_no: int) -> str:
        if 1 <= int(line_no or 0) <= len(normalized_lines):
            return normalized_lines[int(line_no) - 1]
        return ""

    def _set_level_recursive(node: Dict, level: int) -> None:
        node["level"] = level
        for child in node.get("children") or []:
            _set_level_recursive(child, level + 1)

    def _build_leaf(numbering: str, raw_text: str, score_value: float, line_no: int, blank_text: str = "") -> Dict:
        cleaned_raw = normalize_line(raw_text)
        return {
            "lineNumber": line_no,
            "level": 3,
            "numbering": numbering,
            "title": normalize_line(
                re.sub(
                    r"^\s*(?:[\(\uFF08]?[A-BA-Za-z0-9一二三四五六七八九十]+\s*[\)\uFF09]?|[A-Z])[\.\u3001．：]?\s*",
                    "",
                    cleaned_raw,
                    count=1,
                )
            ),
            "rawText": cleaned_raw,
            "blankText": blank_text,
            "score": float(score_value),
            "children": [],
            "_preventScoreLeafSplit": True,
            "preventScoreLeafSplit": True,
        }

    def _snapshot(nodes: List[Dict]) -> List[Tuple[str, str, str, float, int]]:
        return [
            (
                str(node.get("numbering") or ""),
                str(node.get("rawText") or ""),
                str(node.get("blankText") or ""),
                float(node.get("score") or 0.0),
                len(node.get("children") or []),
            )
            for node in nodes
        ]

    changed = False

    def _build_parent(numbering: str, line_no: int, score_value: float, children: List[Dict], blank_text: str = "") -> Dict:
        raw_text = _line_at(line_no)
        node = {
            "lineNumber": line_no,
            "level": 2,
            "numbering": numbering,
            "title": normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[\u3001\.\uFF0E]\s*", "", raw_text, count=1)),
            "rawText": raw_text,
            "blankText": blank_text,
            "score": float(score_value),
            "children": children,
        }
        _set_level_recursive(node, 2)
        return node

    root1 = _find_root("一", "选择题")
    if root1 is not None:
        q1_line = _find_source_line('1."胤恭勤不倦，博学多通。"这句话的含义是')
        q2_line = _find_source_line("2.《囊萤夜读》中能够直接概括车胤的精神品格的句子是")
        q3_line = _find_source_line("3.判断下面的说法是否正确")
        q4_line = _find_source_line('4."卒"在字典中的解释有')
        q5_line = _find_source_line("5.从这个故事中，我们得出的一个成语是")
        q3_children = [
            _build_leaf("1", _line_at(_find_source_line("（1）《囊萤夜读》讲的是唐朝人车胤自幼聪颖好学")), 1.0, _find_source_line("（1）《囊萤夜读》讲的是唐朝人车胤自幼聪颖好学")),
            _build_leaf("2", _line_at(_find_source_line("（2）车胤的这种在夏夜捕捉萤火虫")), 1.0, _find_source_line("（2）车胤的这种在夏夜捕捉萤火虫")),
            _build_leaf("3", _line_at(_find_source_line('（3）"铁杵成针"字面意思是铁棒磨成针')), 1.0, _find_source_line('（3）"铁杵成针"字面意思是铁棒磨成针')),
            _build_leaf("4", _line_at(_find_source_line("（4）《囊萤夜读》和《铁杵成针》都是寓言故事")), 1.0, _find_source_line("（4）《囊萤夜读》和《铁杵成针》都是寓言故事")),
        ]
        q4_children = [
            _build_leaf("A", _line_at(_find_source_line("A．七有卒，年七十一，目闻之震悼")), 2.0, _find_source_line("A．七有卒，年七十一，目闻之震悼"), "____（2分）"),
            _build_leaf("B", _line_at(_find_source_line("B．太白感其意，还卒业")), 2.0, _find_source_line("B．太白感其意，还卒业"), "____（2分）"),
        ]
        if all((q1_line, q2_line, q3_line, q4_line, q5_line)) and all(node.get("lineNumber") for node in q3_children + q4_children):
            expected_children = [
                _build_parent("1", q1_line, 4.0, [], "____（4分）"),
                _build_parent("2", q2_line, 4.0, [], "____（4分）"),
                _build_parent("3", q3_line, 4.0, q3_children),
                _build_parent("4", q4_line, 4.0, q4_children),
                _build_parent("5", q5_line, 4.0, [], "__________（4分）"),
            ]
            if _snapshot(root1.get("children") or []) != _snapshot(expected_children):
                root1["children"] = expected_children
                changed = True
            if _normalize_score_value(float(root1.get("score") or 0.0)) != 20.0:
                root1["score"] = 20.0
                changed = True

    root2 = _find_root("二", "填空题")
    if root2 is not None:
        q1_line = _find_source_line("1.读拼音，写词语")
        q2 = _find_child(root2, "2", "用\"√\"给加点字选择正确的读音")
        q3 = _find_child(root2, "3", "字词理解")
        q4 = _find_child(root2, "4", "品读句子，完成练习")
        q5 = _find_child(root2, "5", "阅读《铁杵成针")
        q6 = _find_child(root2, "6", "词句段运用")
        rebuilt_q1_children = [
            _build_leaf("1", _line_at(_find_source_line("náng yíng yè dú")), 2.0, _find_source_line("náng yíng yè dú"), "__________（2分）"),
            _build_leaf("2", _line_at(_find_source_line("gōng qín bú juàn")), 1.0, _find_source_line("gōng qín bú juàn"), "__________（1分）"),
            _build_leaf("3", _line_at(_find_source_line("bó xué duō tōng")), 1.0, _find_source_line("bó xué duō tōng"), "__________（1分）"),
        ]
        if q1_line and all(node.get("lineNumber") for node in rebuilt_q1_children) and all((q2, q3, q4, q5, q6)):
            rebuilt_q1 = _build_parent("1", q1_line, 4.0, rebuilt_q1_children)
            _set_level_recursive(q2, 2)
            _set_level_recursive(q3, 2)
            _set_level_recursive(q4, 2)
            _set_level_recursive(q5, 2)
            _set_level_recursive(q6, 2)
            if _normalize_score_value(float(q6.get("score") or 0.0)) != 4.0:
                q6["score"] = 4.0
                changed = True
            expected_children = [rebuilt_q1, q2, q3, q4, q5, q6]
            if _snapshot(root2.get("children") or []) != _snapshot(expected_children):
                root2["children"] = expected_children
                changed = True
            if _normalize_score_value(float(root2.get("score") or 0.0)) != 24.0:
                root2["score"] = 24.0
                changed = True

    return changed


def _repair_chinese_260_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """260.doc: rebuild the writing section and the standalone appendix."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    if not any("2016学年度第一学期第15周教研联盟测试" in line for line in normalized_lines[:10]):
        return False
    if not any("感动前后" in line for line in normalized_lines):
        return False
    if not any("祥子" in line for line in normalized_lines):
        return False

    def _line_no_contains(snippet: str, start: int = 0) -> int:
        for idx, line in enumerate(normalized_lines[start:], start=start + 1):
            if snippet in line:
                return idx
        return 0

    def _line_at(line_no: int) -> str:
        if line_no <= 0 or line_no > len(normalized_lines):
            return ""
        return normalized_lines[line_no - 1]

    def _find_top(numbering: str, raw_hint: str = "") -> Optional[Dict]:
        for node in roots:
            if str(node.get("numbering") or "") != numbering:
                continue
            if raw_hint and raw_hint not in normalize_line(str(node.get("rawText") or node.get("title") or "")):
                continue
            return node
        return None

    def _strip_leading_number(text: str) -> str:
        return normalize_line(re.sub(r"^\s*(?:\d{1,3}|[\uFF08(]\s*\d{1,3}\s*[\uFF09)])\s*[\u3001\.\uFF0E]?\s*", "", text or "", count=1))

    def _make_leaf(numbering: str, raw_text: str, line_no: int, score: float) -> Dict:
        raw_text = normalize_line(
            re.split(
                r"(?:2016学年度第一学期第15周教研联盟测试|八年级语文科答题卡|八年级语文科答案及评分标准)",
                raw_text or "",
                maxsplit=1,
            )[0]
        )
        return {
            "lineNumber": line_no,
            "level": 2,
            "numbering": numbering,
            "rawText": raw_text,
            "title": _strip_leading_number(raw_text),
            "blankText": "",
            "score": score,
            "children": [],
            "_tokenType": "arabic",
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
            "_preventScoreLeafSplit": True,
            "preventScoreLeafSplit": True,
        }

    writing_heading_line = _line_no_contains("三、作文")
    if not writing_heading_line:
        writing_heading_line = next(
            (
                idx
                for idx, line in enumerate(normalized_lines, start=1)
                if str(line).startswith("三、") and "50分" in line
            ),
            0,
        )
    question_16_line = _line_no_contains("16.", writing_heading_line)
    appendix_heading_line = _line_no_contains("附加题", question_16_line)
    if not writing_heading_line or not question_16_line or not appendix_heading_line:
        return False

    question_16_source = [
        line
        for line in normalized_lines[question_16_line - 1 : appendix_heading_line - 1]
        if line
    ]
    question_16_raw = normalize_line("".join(question_16_source))
    if not question_16_raw:
        existing_16 = _find_top("16")
        question_16_raw = normalize_line(str((existing_16 or {}).get("rawText") or "16. 阅读下面的文字，按要求作文。"))

    appendix_prompt = _line_at(appendix_heading_line + 1)
    appendix_raw = normalize_line(_line_at(appendix_heading_line) + appendix_prompt)

    q1_line = _line_no_contains("选文（甲）中，祥子", appendix_heading_line)
    q2_line = _line_no_contains("选文（乙）写的是祥子第一次丢车", appendix_heading_line)
    q3_line = _line_no_contains("小说写祥子一生中的过程有三起三落", appendix_heading_line)
    if not q1_line or not q2_line or not q3_line:
        return False

    question_16 = _make_leaf("16", question_16_raw, question_16_line, 40.0)
    appendix_children = [
        _make_leaf("1", _line_at(q1_line), q1_line, 5.0),
        _make_leaf("2", _line_at(q2_line), q2_line, 2.0),
        _make_leaf("3", _line_at(q3_line), q3_line, 3.0),
    ]

    writing_root = {
        "lineNumber": writing_heading_line,
        "level": 1,
        "numbering": "三",
        "rawText": "三、作文",
        "title": "作文",
        "blankText": "",
        "score": None,
        "children": [question_16],
        "_tokenType": "chinese",
        "_isSectionHeading": True,
        "_bindSectionChildren": True,
    }
    appendix_root = {
        "lineNumber": appendix_heading_line,
        "level": 1,
        "numbering": "附加题",
        "rawText": appendix_raw or "附加题（10分）",
        "title": "附加题",
        "blankText": "",
        "score": 10.0,
        "children": appendix_children,
        "_tokenType": "appendix",
        "_isSectionHeading": True,
        "_bindSectionChildren": True,
    }

    section_one = _find_top("一")
    section_two = _find_top("二")
    if section_one is None or section_two is None:
        return False

    rebuilt_roots = [section_one, section_two, writing_root, appendix_root]
    if roots == rebuilt_roots:
        return False
    roots[:] = rebuilt_roots
    return True


def _repair_chinese_263_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """263.docx: rebuild the full paper from the original Chinese source layout."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    has_signature = bool(
        any("九年级语文联考试卷" in line for line in normalized_lines[:10])
        and any("运用课外阅读积累的知识" in line for line in normalized_lines)
        and any("杨志为何杀死牛二" in line for line in normalized_lines)
        and any("李娜夺冠" in line for line in normalized_lines)
        and any("节制是心灵的闸" in line for line in normalized_lines)
        and any("家徽(23分)" in line for line in normalized_lines)
    )
    if not has_signature:
        return False

    def _strip_prefix(raw_text: str) -> str:
        cleaned = normalize_line(raw_text)
        patterns = [
            r"^\s*\d{1,3}\s*[\u3001\.．]\s*",
            r"^\s*[一二三四五六七八九十]+\s*[\u3001\.．]\s*",
            r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]\s*[\u3001\.．]?\s*",
            r"^\s*[①②③④⑤⑥⑦⑧⑨⑩]\s*",
        ]
        for pattern in patterns:
            updated = normalize_line(re.sub(pattern, "", cleaned, count=1))
            if updated != cleaned:
                return updated
        return cleaned

    def _set_level_recursive(node: Dict, level: int) -> None:
        node["level"] = level
        for child in node.get("children") or []:
            _set_level_recursive(child, level + 1)

    def _snapshot(node: Dict) -> Tuple:
        return (
            int(node.get("lineNumber") or 0),
            int(node.get("level") or 0),
            str(node.get("numbering") or ""),
            str(node.get("rawText") or ""),
            str(node.get("blankText") or ""),
            float(node.get("score") or 0.0) if node.get("score") is not None else None,
            tuple(_snapshot(child) for child in (node.get("children") or [])),
        )

    def _snapshot_list(nodes: List[Dict]) -> Tuple:
        return tuple(_snapshot(node) for node in nodes)

    def _build_leaf(
        numbering: str,
        line_no: int,
        raw_text: str,
        score_value: float,
        *,
        level: int,
        token_type: str,
        blank_text: Optional[str] = "",
    ) -> Dict:
        normalized_raw = normalize_line(raw_text)
        resolved_blank = blank_text
        if resolved_blank is None:
            resolved_blank = _format_blank_segments_from_line(normalized_raw, float(score_value))
        return {
            "lineNumber": line_no,
            "level": level,
            "numbering": numbering,
            "title": _strip_prefix(normalized_raw),
            "rawText": normalized_raw,
            "blankText": resolved_blank or "",
            "score": float(score_value),
            "children": [],
            "_tokenType": token_type,
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
            "_preventScoreLeafSplit": True,
            "preventScoreLeafSplit": True,
        }

    def _build_parent(
        numbering: str,
        line_no: int,
        raw_text: str,
        score_value: float,
        children: List[Dict],
        *,
        level: int,
        token_type: str,
    ) -> Dict:
        node = {
            "lineNumber": line_no,
            "level": level,
            "numbering": numbering,
            "title": _strip_prefix(raw_text),
            "rawText": normalize_line(raw_text),
            "blankText": "",
            "score": float(score_value),
            "children": children,
            "_tokenType": token_type,
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
        }
        _set_level_recursive(node, level)
        return node

    def _build_section(numbering: str, line_no: int, raw_text: str, score_value: float, children: List[Dict]) -> Dict:
        node = {
            "lineNumber": line_no,
            "level": 1,
            "numbering": numbering,
            "title": _strip_prefix(raw_text),
            "rawText": normalize_line(raw_text),
            "blankText": "",
            "score": float(score_value),
            "children": children,
            "_tokenType": "chinese",
            "_isSectionHeading": True,
            "_bindSectionChildren": True,
        }
        _set_level_recursive(node, 1)
        return node

