def _repair_chinese_264_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """264.docx: rebuild the full paper where sections drift after sentence practice."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    has_source_signature = bool(
        any("2023年小学五年级语文下册期末质量检测题" in line for line in normalized_lines[:10])
        and any("又是荠菜花开时" in line for line in normalized_lines)
        and any("下面的题目奖励给知识渊博" in line for line in normalized_lines)
        and any("颜真卿《颜勤礼碑》" in line for line in normalized_lines)
    )
    root_texts = [normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots]
    has_outline_signature = bool(
        any("抄写古诗《村晚》" in text for text in root_texts)
        and any("课本直通车" in text for text in root_texts)
        and any("阅读理解" in text for text in root_texts)
        and any("快乐习作" in text for text in root_texts)
    )
    has_postprocess_drift = bool(
        [str(node.get("numbering") or "") for node in roots].count("六") > 1
        or any(
            str(root.get("numbering") or "") == "五"
            and any("六、实践园地" in normalize_line(str(child.get("rawText") or child.get("title") or "")) for child in root.get("children") or [])
            for root in roots
        )
        or any("十、下面的题目奖励" in text and text.startswith("2.") for text in root_texts)
    )
    if not has_source_signature and not (has_outline_signature and has_postprocess_drift):
        return False

    def _compact(text: str) -> str:
        return re.sub(r"\s+", "", str(text or ""))

    def _find_line(snippet: str, start: int = 0) -> int:
        compact_snippet = _compact(snippet)
        slice_start = max(int(start or 0) - 1, 0)
        for idx, line in enumerate(normalized_lines[slice_start:], start=slice_start + 1):
            if snippet in line or (compact_snippet and compact_snippet in _compact(line)):
                return idx
        return 0

    def _source_line(line_no: int) -> str:
        if 1 <= int(line_no or 0) <= len(normalized_lines):
            return normalized_lines[int(line_no) - 1]
        return ""

    def _source_text(snippet: str, start: int = 0) -> str:
        line_no = _find_line(snippet, start)
        return _source_line(line_no) if line_no > 0 else ""

    def _join_source_lines(start_line: int, end_line: int) -> str:
        start = max(int(start_line or 0), 1)
        end = min(int(end_line or 0), len(normalized_lines))
        if end < start:
            return ""
        return normalize_line(" ".join(_source_line(line_no) for line_no in range(start, end + 1) if _source_line(line_no)))

    def _source_line(line_no: int, fallback: str = "") -> str:
        if 1 <= int(line_no or 0) <= len(normalized_lines):
            return normalize_line(normalized_lines[int(line_no) - 1])
        return normalize_line(fallback)

    def _find_line_text(snippet: str, fallback: str, start: int = 0) -> Tuple[int, str]:
        line_no = _find_line(snippet, start=start)
        return line_no, _source_line(line_no, fallback)

    def _extract_inline_q6_segment(
        number_text: str,
        fallback: str,
        source_line: str,
        *,
        stop_snippet: str = "",
    ) -> str:
        source = normalize_line(source_line or "")
        if not source:
            return normalize_line(fallback)
        match = re.search(rf"[\uFF08(]\s*{re.escape(number_text)}\s*[\uFF09)]", source)
        if not match:
            return normalize_line(fallback)
        segment = source[match.start() :]
        if stop_snippet:
            stop_idx = segment.find(stop_snippet)
            if stop_idx >= 0:
                segment = segment[: stop_idx + len(stop_snippet)]
                return normalize_line(segment)
        return normalize_line(fallback)

    def _line(line_no: int) -> str:
        if 1 <= int(line_no or 0) <= len(normalized_lines):
            return normalized_lines[int(line_no) - 1]
        return ""

    def _join_lines(line_numbers: List[int]) -> str:
        return normalize_line("".join(_line(line_no) for line_no in line_numbers if _line(line_no)))

    def _extract_segment(
        start_snippet: str,
        *,
        end_snippet: str = "",
        fallback: str = "",
        line_no: int = 0,
    ) -> str:
        source = _line(line_no) if line_no else ""
        if not source and start_snippet:
            source = _line(_find_line(start_snippet))
        source = normalize_line(source)
        if not source:
            return normalize_line(fallback)
        start_idx = source.find(start_snippet) if start_snippet else 0
        if start_idx < 0:
            return normalize_line(fallback)
        segment = source[start_idx:]
        if end_snippet:
            end_idx = segment.find(end_snippet)
            if end_idx >= 0:
                segment = segment[:end_idx]
        return normalize_line(segment) or normalize_line(fallback)

    def _strip_prefix(raw_text: str, numbering: str, *, token_type: str = "arabic") -> str:
        cleaned = normalize_line(raw_text)
        if not numbering:
            return cleaned
        if token_type == "chinese":
            return normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[\u3001\.．、]\s*", "", cleaned, count=1))
        if token_type == "chinese_paren":
            return normalize_line(re.sub(r"^\s*[\uFF08(]\s*[一二三四五六七八九十]+\s*[\uFF09)]\s*", "", cleaned, count=1))
        if token_type == "circled":
            return normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*", "", cleaned, count=1))
        return normalize_line(
            re.sub(rf"^\s*{re.escape(numbering)}\s*[\u3001\.\uFF0E、]?\s*", "", cleaned, count=1)
        )

    def _set_level_recursive(node: Dict, level: int) -> None:
        node["level"] = level
        for child in node.get("children") or []:
            _set_level_recursive(child, level + 1)

    def _make_blank_text(raw_text: str, score: float, *, blank_mode: str) -> str:
        if blank_mode == "none":
            return ""
        if blank_mode == "choice":
            return f"____（{int(score) if float(score).is_integer() else score}分）"
        return _format_blank_segments_from_line(raw_text, score)

    def _make_node(
        numbering: str,
        raw_text: str,
        score: float,
        *,
        line_no: int = 0,
        level: int = 1,
        token_type: str = "arabic",
        children: Optional[List[Dict]] = None,
        blank_mode: str = "auto",
        section: bool = False,
        prevent_split: bool = False,
    ) -> Dict:
        cleaned = normalize_line(raw_text)
        node = {
            "lineNumber": line_no or _find_line(cleaned[:30]),
            "level": level,
            "numbering": numbering,
            "title": _strip_prefix(cleaned, numbering, token_type=token_type),
            "rawText": cleaned,
            "blankText": "" if children else _make_blank_text(cleaned, score, blank_mode=blank_mode),
            "score": float(score),
            "children": children or [],
            "_tokenType": token_type,
            "_isSectionHeading": bool(section),
            "_bindSectionChildren": bool(section),
        }
        for child in node["children"]:
            _set_level_recursive(child, level + 1)
        if prevent_split:
            node["_preventScoreLeafSplit"] = True
            node["preventScoreLeafSplit"] = True
        return node

    def _root(numbering: str, raw_text: str, score: float, children: Optional[List[Dict]] = None, *, line_no: int = 0, prevent_split: bool = False) -> Dict:
        return _make_node(
            numbering,
            raw_text,
            score,
            line_no=line_no,
            level=1,
            token_type="chinese",
            children=children,
            blank_mode="none",
            section=True,
            prevent_split=prevent_split,
        )

    def _leaf(numbering: str, raw_text: str, score: float, *, line_no: int = 0, level: int = 2, blank_mode: str = "auto", prevent_split: bool = False, token_type: str = "arabic") -> Dict:
        return _make_node(
            numbering,
            raw_text,
            score,
            line_no=line_no,
            level=level,
            token_type=token_type,
            blank_mode=blank_mode,
            prevent_split=prevent_split,
        )

