            _make_node("15", q15 or "15、文题为“魅力莫言”，你认为莫言的魅力源自哪里？（4分）", 4.0, level=2, line_no=q13_line, blank_text=""),
            _make_node("16", q16 or "16、读完本文，你赞成重修莫言故居吗？为什么？（4分）", 4.0, level=2, line_no=q13_line, blank_text=""),
