def _repair_chinese_278_1_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """278-1.doc: repair Chinese reading/writing sections polluted by article and requirement text."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    line_signature = bool(
        any("扬州树人学校2018" in line and "2019" in line for line in normalized_lines[:20])
        and any("一、积累运用" in line for line in normalized_lines)
        and any("二、阅读理解" in line for line in normalized_lines)
        and any("一碗热饺子" in line for line in normalized_lines)
        and any("粮食的味道" in line for line in normalized_lines)
        and any("亲近了，才知道" in line for line in normalized_lines)
    )
    root_signature = bool(
        any(str(node.get("numbering") or "") == "一" and "积累运用" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(str(node.get("numbering") or "") == "二" and "阅读理解" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(str(node.get("numbering") or "") == "三" and "写作" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(
            any(
                marker in normalize_line(str(child.get("rawText") or child.get("title") or ""))
                for marker in ("一碗热饺子", "粮食的味道", "亲近了，才知道")
            )
            for node in roots
            for child in (node.get("children") or [])
        )
    )
    if not (line_signature or root_signature):
        return False

    def _compact(text: str) -> str:
        return re.sub(r"\s+", "", str(text or ""))

    def _find_line(snippet: str, start: int = 0) -> int:
        compact_snippet = _compact(snippet)
        slice_start = max(int(start or 0) - 1, 0)
        for idx, line in enumerate(normalized_lines[slice_start:], start=slice_start + 1):
            if snippet in line or (compact_snippet and compact_snippet in _compact(line)):
                return idx
        return 0

    def _strip_prefix(raw_text: str, numbering: str) -> str:
        return normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[\.\uFF0E．、]\s*", "", raw_text, count=1))

    def _score_text(score: float) -> str:
        normalized = _normalize_score_value(float(score or 0.0))
        if abs(normalized - round(normalized)) <= 1e-6:
            return str(int(round(normalized)))
        return f"{normalized:.2f}".rstrip("0").rstrip(".")

    def _find_root(numbering: str, hint: str = "") -> Optional[Dict]:
        for node in roots:
            if str(node.get("numbering") or "") != numbering:
                continue
            if hint and hint not in normalize_line(str(node.get("rawText") or node.get("title") or "")):
                continue
            return node
        return None

    def _make_leaf(
        numbering: str,
        raw_text: str,
        score: float,
        *,
        line_no: int = 0,
        level: int = 2,
        blank_text: str = "",
        children: Optional[List[Dict]] = None,
        token_type: str = "arabic",
    ) -> Dict:
        raw_text = normalize_line(raw_text)
        node = {
            "lineNumber": line_no,
            "level": level,
            "numbering": numbering,
            "title": _strip_prefix(raw_text, numbering) if numbering else raw_text,
            "rawText": raw_text,
            "blankText": "" if children else blank_text,
            "score": float(score),
            "children": children or [],
            "_tokenType": token_type,
            "_isSectionHeading": False,
            "_bindSectionChildren": bool(children),
            "_preventScoreLeafSplit": not bool(children),
            "preventScoreLeafSplit": not bool(children),
        }
        for child in node["children"]:
            child["level"] = level + 1
        return node

    def _blank_child(raw_text: str, score: float, line_no: int = 0, *, level: int = 3) -> Dict:
        raw_text = normalize_line(raw_text)
        return {
            "lineNumber": line_no,
            "level": level,
            "numbering": "",
            "title": raw_text,
            "rawText": raw_text,
            "blankText": f"____（{_score_text(score)}分）",
            "score": float(score),
            "children": [],
            "_tokenType": "blank_generated",
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
            "_preventScoreLeafSplit": True,
            "preventScoreLeafSplit": True,
        }

    def _set_node(node: Dict, updates: Dict) -> bool:
        changed = False
        for key, value in updates.items():
            if node.get(key) != value:
                node[key] = value
                changed = True
        return changed

