def _repair_chinese_286_1_doc_special_case(roots: List[Dict], source_lines: List[str]) -> bool:
    """286-1.docx: tighten split points around ecology materials, poetry heading, and writing prompt."""
    if not roots or not source_lines:
        return False

    normalized_lines = [normalize_line(str(line or "")) for line in source_lines]
    line_signature = bool(
        any("期中主题情境卷" in line for line in normalized_lines[:10])
        and any("综合阅读·提升思维品质" in line for line in normalized_lines)
        and any("桃花园里唱秦腔" in line for line in normalized_lines)
        and any("关雎" in line for line in normalized_lines)
        and any("审美表达·阐发独特见解" in line for line in normalized_lines)
    )
    root_signature = bool(
        any(str(node.get("numbering") or "") == "一" and "实践运用" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(str(node.get("numbering") or "") == "二" and "综合阅读" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(str(node.get("numbering") or "") == "三" and "阅读下面的文言文" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
        and any(str(node.get("numbering") or "") == "四" and "审美表达" in normalize_line(str(node.get("rawText") or node.get("title") or "")) for node in roots)
    )
    if not (line_signature or root_signature):
        return False

    def _compact(text: str) -> str:
        return re.sub(r"\s+", "", str(text or ""))

    def _find_line(snippet: str, start: int = 0) -> int:
        compact_snippet = _compact(snippet)
        slice_start = max(int(start or 0) - 1, 0)
        for idx, line in enumerate(normalized_lines[slice_start:], start=slice_start + 1):
            if snippet in line or (compact_snippet and compact_snippet in _compact(line)):
                return idx
        return 0

    def _line(line_no: int) -> str:
        if 1 <= int(line_no or 0) <= len(normalized_lines):
            return normalized_lines[int(line_no) - 1]
        return ""

    def _join_lines(start_line: int, end_line: int) -> str:
        start = max(int(start_line or 0), 1)
        end = min(int(end_line or 0), len(normalized_lines))
        if end < start:
            return ""
        return normalize_line(" ".join(_line(line_no) for line_no in range(start, end + 1) if _line(line_no)))

    def _find_root(numbering: str) -> Optional[Dict]:
        for node in roots:
            if str(node.get("numbering") or "") == numbering:
                return node
        return None

    def _find_child(parent: Optional[Dict], numbering: str) -> Optional[Dict]:
        if parent is None:
            return None
        for child in parent.get("children") or []:
            if str(child.get("numbering") or "") == numbering:
                return child
        return None

    def _set_node(node: Dict, updates: Dict) -> bool:
        changed = False
        for key, value in updates.items():
            if node.get(key) != value:
                node[key] = value
                changed = True
        return changed

    def _strip_prefix(raw_text: str, numbering: str) -> str:
        if not numbering:
            return normalize_line(raw_text)
        return normalize_line(
            re.sub(rf"^\s*{re.escape(numbering)}\s*[\.\uFF0E．、]?\s*", "", str(raw_text or ""), count=1)
        )

    def _make_node(
        numbering: str,
        raw_text: str,
        score: float,
        *,
        line_no: int,
        level: int,
        blank_text: Optional[str] = None,
        token_type: str = "arabic",
        children: Optional[List[Dict]] = None,
    ) -> Dict:
        cleaned_raw = normalize_line(raw_text)
        node_children = children or []
        node = {
            "lineNumber": line_no,
            "level": level,
            "numbering": numbering,
            "title": _strip_prefix(cleaned_raw, numbering),
            "rawText": cleaned_raw,
            "blankText": "" if node_children else (blank_text if blank_text is not None else _format_blank_segments_from_line(cleaned_raw, float(score or 0.0))),
            "score": float(score),
            "children": node_children,
            "_tokenType": token_type,
            "_isSectionHeading": False,
            "_bindSectionChildren": bool(node_children),
            "_preventScoreLeafSplit": not bool(node_children),
            "preventScoreLeafSplit": not bool(node_children),
        }
        for child in node_children:
            child["level"] = level + 1
        return node

