            _make_node("21", _source_line(_find_line("表达作者了怎样的思想感情", start=80), "21．“仍怜故乡水，万里送行舟。”表达作者了怎样的思想感情?（2分）"), 2.0, line_no=_find_line("表达作者了怎样的思想感情", start=80), blank_text="____（2分）"),
