        if q8_8 is not None:
            q8_8_line_no = _find_line("在《春望》一诗中") or int(q8_8.get("lineNumber") or 0)
            q8_8_raw = "（8）在《春望》一诗中，表现诗人因愁苦而日益衰老的句子是：______________，________________。"
