def _repair_orphan_nonchoice_roots_under_chinese_section(roots: List[Dict]) -> None:
    if len(roots) < 2:
        return

    root_like_tokens = {"chinese", "chinese_loose", "roman", "appendix", "paper_volume"}
    arabic_tokens = {"arabic", "arabic_loose", "arabic_bare", "decimal"}

    def _node_line(node: Dict) -> int:
        try:
            return int(node.get("lineNumber") or 0)
        except (TypeError, ValueError):
            return 0

    def _is_nonchoice_chinese_root(node: Dict) -> bool:
        if int(node.get("level") or 1) != 1:
            return False
        token_type = str(node.get("_tokenType") or "")
        if token_type not in root_like_tokens:
            return False
        text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
        if not text:
            return False
        return bool(re.search(r"(?:非选择题|解答题|主观题|综合题|必考题)", text))

    def _iter_direct_arabic_children(node: Dict) -> List[Dict]:
        result: List[Dict] = []
        for child in node.get("children", []) or []:
            if str(child.get("_tokenType") or "") not in arabic_tokens:
                continue
            if _parse_ascii_int(child.get("numbering")) is None:
                continue
            result.append(child)
        return result

    def _is_paren_arabic_like_node(node: Dict) -> bool:
        if str(node.get("_tokenType") or "") == "paren_arabic":
            return True
        text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
        if not text:
            return False
        return bool(re.match(r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]", text))

    def _find_next_root_boundary_line(start_line: int) -> int:
        boundary = 0
        for node in roots:
            if int(node.get("level") or 1) != 1:
                continue
            token_type = str(node.get("_tokenType") or "")
            if token_type not in root_like_tokens:
                continue
            line_no = _node_line(node)
            if line_no <= start_line:
                continue
            if boundary <= 0 or line_no < boundary:
                boundary = line_no
        return boundary

    removed_ids: Set[int] = set()
    for section in roots:
        if id(section) in removed_ids:
            continue
        if not _is_nonchoice_chinese_root(section):
            continue

        section_line = _node_line(section)
        boundary_line = _find_next_root_boundary_line(section_line)

        # 1) 回挂漂移到根级的（1）（2）到最近的阿拉伯父题（如 10.）。
        changed = True
        while changed:
            changed = False
            arabic_children = _iter_direct_arabic_children(section)
            if not arabic_children:
                break

            orphan_paren_candidates: List[Dict] = []
            for node in roots:
                if node is section or id(node) in removed_ids:
                    continue
                if int(node.get("level") or 1) != 1:
                    continue
                if str(node.get("_tokenType") or "") != "paren_arabic":
                    continue
                marker_num = _parse_ascii_int(node.get("numbering"))
                if marker_num is None or marker_num < 1 or marker_num > 8:
                    continue
                line_no = _node_line(node)
                if line_no <= section_line:
                    continue
                if boundary_line > 0 and line_no >= boundary_line:
                    continue
                orphan_paren_candidates.append(node)

            orphan_paren_candidates.sort(key=_node_line)
            for orphan in orphan_paren_candidates:
                orphan_line = _node_line(orphan)
                parent = None
                parent_line = -1
                for child in arabic_children:
                    child_line = _node_line(child)
                    if child_line <= 0 or child_line >= orphan_line:
                        continue
                    if child_line > parent_line:
                        parent = child
                        parent_line = child_line
                if parent is None:
                    continue

                parent_children = list(parent.get("children") or [])
                if parent_children and any(
                    str(item.get("_tokenType") or "") not in {"paren_arabic", "circled"}
                    for item in parent_children
                ):
                    continue

                level_delta = int(parent.get("level") or 1) + 1 - int(orphan.get("level") or 1)
                if level_delta > 0:
                    _increase_outline_levels(orphan, level_delta)
                elif level_delta < 0:
                    _decrease_outline_levels(orphan, -level_delta)
                parent_children.append(orphan)
                parent_children.sort(key=_node_line)
                parent["children"] = parent_children
                removed_ids.add(id(orphan))
                changed = True

        # 2) 回挂被隔断的连续阿拉伯根节点（如 11/12/13）到该中文大题下。
        arabic_children = _iter_direct_arabic_children(section)
        if not arabic_children:
            continue
        current_max = max(
            (_parse_ascii_int(child.get("numbering")) or 0)
            for child in arabic_children
        )
        expected = current_max + 1
        while True:
            candidate = None
            candidate_line = 0
            for node in roots:
                if node is section or id(node) in removed_ids:
                    continue
                if int(node.get("level") or 1) != 1:
                    continue
                if str(node.get("_tokenType") or "") not in arabic_tokens:
                    continue
                node_num = _parse_ascii_int(node.get("numbering"))
                if node_num != expected:
                    continue
                line_no = _node_line(node)
                if line_no <= section_line:
                    continue
                if boundary_line > 0 and line_no >= boundary_line:
                    continue
                if candidate is None or (line_no > 0 and line_no < candidate_line):
                    candidate = node
                    candidate_line = line_no
            if candidate is None:
                break

            level_delta = int(section.get("level") or 1) + 1 - int(candidate.get("level") or 1)
            if level_delta > 0:
                _increase_outline_levels(candidate, level_delta)
            elif level_delta < 0:
                _decrease_outline_levels(candidate, -level_delta)
            section_children = list(section.get("children") or [])
            section_children.append(candidate)
            section_children.sort(key=_node_line)
            section["children"] = section_children
            removed_ids.add(id(candidate))
            expected += 1

        # 3) 修复中文非选择题内部错挂：
        #    - 直接挂在该大题下的（1）（2）应回挂到最近阿拉伯父题（如 10.）；
        #    - 若（1）里误挂了 11/12/13 这类后续平级阿拉伯题，则上提回该中文大题直系。
        section_children = list(section.get("children") or [])
        if section_children:
            section_children.sort(key=_node_line)
            rebuilt_children: List[Dict] = []
            last_arabic_parent: Optional[Dict] = None
            internal_changed = False

            for child in section_children:
                child_num = _parse_ascii_int(child.get("numbering"))
                if str(child.get("_tokenType") or "") in arabic_tokens and child_num is not None:
                    last_arabic_parent = child
                    rebuilt_children.append(child)
                    continue

                if last_arabic_parent is None or not _is_paren_arabic_like_node(child):
                    rebuilt_children.append(child)
                    continue

                # 先把（1）内部误挂的 11/12/13 上提到中文大题直系。
                parent_num = _parse_ascii_int(last_arabic_parent.get("numbering")) or 0
                overflow_mains: List[Dict] = []
                remain_grandchildren: List[Dict] = []
                for grand in list(child.get("children") or []):
                    grand_num = _parse_ascii_int(grand.get("numbering"))
                    if (
                        grand_num is not None
                        and str(grand.get("_tokenType") or "") in arabic_tokens
                        and grand_num > parent_num
                    ):
                        overflow_mains.append(grand)
                        continue
                    remain_grandchildren.append(grand)
                if overflow_mains:
                    child["children"] = remain_grandchildren
                    target_level = int(section.get("level") or 1) + 1
                    for overflow in sorted(overflow_mains, key=_node_line):
                        level_delta = target_level - int(overflow.get("level") or target_level)
                        if level_delta > 0:
                            _increase_outline_levels(overflow, level_delta)
                        elif level_delta < 0:
                            _decrease_outline_levels(overflow, -level_delta)
                        rebuilt_children.append(overflow)
                    internal_changed = True

                # 再把（1）（2）回挂到最近阿拉伯父题（如 10.）下。
                parent_children = list(last_arabic_parent.get("children") or [])
                target_level = int(last_arabic_parent.get("level") or 1) + 1
                level_delta = target_level - int(child.get("level") or target_level)
                if level_delta > 0:
                    _increase_outline_levels(child, level_delta)
                elif level_delta < 0:
                    _decrease_outline_levels(child, -level_delta)
                parent_children.append(child)
                parent_children.sort(key=_node_line)
                last_arabic_parent["children"] = parent_children
                internal_changed = True

            if internal_changed:
                rebuilt_children.sort(key=_node_line)
                section["children"] = rebuilt_children

    if removed_ids:
        roots[:] = [node for node in roots if id(node) not in removed_ids]


def _flatten_specific_nonchoice_mandatory_duplicate_heading(roots: List[Dict]) -> None:
    if not roots:
        return
    for node in roots:
        if int(node.get("level") or 1) != 1:
            continue
        parent_text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
        if not parent_text:
            continue
        # 专项修复（任务490/134.doc）：当“非选择题总引导”与“（一）必考题（共129分）”
        # 被重复建层时，仅保留一层，避免大题标题重复。
        if not (
            "非选择题" in parent_text
            and "必考题" in parent_text
            and "选考题" in parent_text
            and "第22题" in parent_text
            and "第32题" in parent_text
        ):
            continue

        children = node.get("children") or []
        if len(children) != 1:
            continue
        only_child = children[0]
        child_text = normalize_line(str(only_child.get("rawText") or only_child.get("title") or ""))
        if not child_text:
            continue
        if not re.search(r"^\s*[\uFF08(]\s*一\s*[\uFF09)]\s*必考题\s*[\uFF08(]\s*共\s*129\s*分\s*[\uFF09)]\s*$", child_text):
            continue

        grand_children = only_child.get("children") or []
        if len(grand_children) < 8:
            continue
        numbered = [_parse_ascii_int(item.get("numbering")) for item in grand_children]
        if 22 not in [value for value in numbered if value is not None]:
            continue
        if 32 not in [value for value in numbered if value is not None]:
            continue

        node["children"] = grand_children
        child_score = float(only_child.get("score") or 0.0)
        if child_score > 0:
            node["score"] = _normalize_score_value(child_score)



def _parse_math_arabic_numbering(value: object) -> Optional[int]:
    text = str(value or "").strip().translate(
        str.maketrans("\uff10\uff11\uff12\uff13\uff14\uff15\uff16\uff17\uff18\uff19", "0123456789")
    )
    if not text or not text.isdigit():
        return None
    try:
        return int(text)
    except ValueError:
        return None


def _is_math_chinese_section_root(node: Dict) -> bool:
    if int(node.get("level", 1) or 1) != 1:
        return False
    numbering = str(node.get("numbering") or "").strip()
    raw_text = str(node.get("rawText") or node.get("title") or "").strip()
    if re.fullmatch(r"[\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341\u767e\u5343\u4e07]+", numbering) and re.search(r"[\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341]", numbering):
        return True
    raw_match = re.match(r"^\s*([\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341\u767e\u5343\u4e07]+)\s*[\u3001\.\uFF0E]", raw_text)
    return bool(raw_match and re.search(r"[\u4e00\u4e8c\u4e09\u56db\u4e94\u516d\u4e03\u516b\u4e5d\u5341]", raw_match.group(1)))

def repair_math_continuous_section_artifacts_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    sample_text = " ".join(
        normalize_line(str(node.get("rawText") or node.get("title") or ""))
        for node in outline_items[:12]
    ) + " " + " ".join(normalize_line(line) for line in source_lines[:120])
    math_signal_hits = len(re.findall(r"[=＝><＜＞+\-−－×÷∠△⊥∥○]", sample_text))
    math_topic_hits = len(
        re.findall(
            r"(?:填空|判断|选择|解决问题|计算|计时|24时|普通计时|经过|平均每小时|多少|"
            r"年月日|闰年|平年|千米|厘米|米)",
            sample_text,
        )
    )
    score_heading_hits = len(re.findall(r"[\uFF08(]\s*\d+(?:\.\d+)?\s*\u5206\s*[\uFF09)]", sample_text))
    if "数学" not in sample_text and math_signal_hits < 4 and not (
        math_topic_hits >= 3 and score_heading_hits >= 3
    ):
        return False

    section_re = re.compile(r"^\s*([一二三四五六七八九十])\s*[\u3001\.\uFF0E]?\s*(\S.*)$")
    appendix_re = re.compile(r"^\s*(附加题)(?![\u4e00-\u9fa5A-Za-z])\s*(?:[\u3001\.\uFF0E:：]\s*)?(.*)$")
    question_re = re.compile(r"^\s*(\d{1,3}|[０-９]{1,3})\s*([\u3001\.\uFF0E])(\s*)(\S.*)$")
    score_re = re.compile(
        r"[\uFF08(]\s*(?:本题)?\s*(?:满分)?\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]"
        r"|满分\s*(\d+(?:\.\d+)?)\s*\u5206"
    )
    blank_re = re.compile(r"(?:_{2,}|[\uFF08(]\s*[\uFF09)])")
    math_section_hint_re = re.compile(
        r"(?:选择题|填空题|判断题|计算题|解答题|解决问题|应用题|作图题|选择|填空|判断|计算|解决|应用|"
        r"口算|估算|竖式计算|脱式计算|算一算|连一连|画一画|操作|实践)"
    )

    def _parse_score(text: str) -> float:
        match = score_re.search(text or "")
        if match is None:
            return 0.0
        try:
            return float(next(group for group in match.groups() if group))
        except ValueError:
            return 0.0

    def _normalize_digits(text: str) -> str:
        return str(text).translate(str.maketrans("０１２３４５６７８９", "0123456789"))

    def _strip_question_prefix(text: str, numbering: str) -> str:
        return normalize_line(
            re.sub(
                rf"^\s*{re.escape(numbering)}\s*[\u3001\.\uFF0E]\s*",
                "",
                text or "",
                count=1,
            )
        )

    def _count_blank_markers(text: str) -> int:
        return len(blank_re.findall(text or ""))

    sections: List[Dict[str, object]] = []
    for line_no, line in enumerate(source_lines, 1):
        normalized = normalize_line(line)
        if not normalized:
            continue
        appendix_match = appendix_re.match(normalized)
        if appendix_match is not None:
            appendix_title = normalize_line(str(appendix_match.group(2) or ""))
            sections.append(
                {
                    "numbering": "附加题",
                    "lineNumber": line_no,
                    "rawText": normalized,
                    "score": _parse_score(normalized),
                    "title": appendix_title,
                }
            )
            continue
        match = section_re.match(normalized)
        if match is None:
            continue
        title = str(match.group(2) or "")
        score_value = _parse_score(normalized)
        # 数学卷里存在“一．选择题（45小题）”这类无显式分数的大题。
        # 它仍要参与章节边界判断，否则后续连续小题缺漏无法按原文重建。
        if score_value <= 0 and not math_section_hint_re.search(title):
            continue
        sections.append(
            {
                "numbering": str(match.group(1) or "").strip(),
                "lineNumber": line_no,
                "rawText": normalized,
                "score": score_value,
            }
        )

    def _repair_no_separator_arabic_roots() -> bool:
        root_numbers = [
            int(number)
            for number in (
                _parse_math_arabic_numbering(root.get("numbering")) for root in outline_items
            )
            if number is not None
        ]
        if len(root_numbers) < 3:
            return False
        existing_numbers = {str(number) for number in root_numbers}
        root_level = int(outline_items[0].get("level") or 1)
        answer_start = len(source_lines) + 1
        for line_no, line in enumerate(source_lines, 1):
            if re.search(r"参考答案|答案解析|试题解析", normalize_line(line)):
                answer_start = line_no
                break
        inserted = False
        for line_no, line in enumerate(source_lines[: answer_start - 1], 1):
            text = normalize_line(line)
            match = re.match(r"^\s*(\d{1,2}|[０-９]{1,2})(?![\d０-９\u3001\.\uFF0E、])\s*(\S.*)$", text)
            if match is None:
                continue
            numbering = _normalize_digits(str(match.group(1) or ""))
            if numbering in existing_numbers:
                continue
            value = _parse_math_arabic_numbering(numbering)
            if value is None or int(value) <= 1:
                continue
            title = str(match.group(2) or "").strip()
            if not re.search(r"(?:题|空间|问题|计算|转化|填空|判断|选择|个性)", title):
                continue
            if int(value) - 1 not in root_numbers:
                continue
            new_root = {
                "lineNumber": line_no,
                "level": root_level,
                "numbering": numbering,
                "title": title,
                "rawText": text,
                "blankText": "",
                "score": _parse_score(text),
                "children": [],
                "_tokenType": "arabic",
                "_isSectionHeading": True,
                "_bindSectionChildren": True,
            }
            followup_children: List[Dict] = []
            for probe, followup_line in enumerate(source_lines[line_no: answer_start - 1], line_no + 1):
                followup_text = normalize_line(followup_line)
                if not followup_text:
                    continue
                if re.match(r"^\s*(\d{1,2}|[０-９]{1,2})(?![\d０-９\u3001\.\uFF0E、])\s*\S", followup_text):
                    break
                if question_re.match(followup_text) or section_re.match(followup_text):
                    break
                followup_children.append(
                    {
                        "lineNumber": probe,
                        "level": root_level + 1,
                        "numbering": "",
                        "title": followup_text,
                        "rawText": followup_text,
                        "blankText": "",
                        "score": 0.0,
                        "children": [],
                        "_tokenType": "blank",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            if followup_children:
                if float(new_root.get("score") or 0.0) > 0:
                    each_score = round(float(new_root.get("score") or 0.0) / len(followup_children), 2)
                    for child in followup_children:
                        child["score"] = each_score
                new_root["children"] = followup_children
            insert_at = len(outline_items)
            for idx, root in enumerate(outline_items):
                root_number = _parse_math_arabic_numbering(root.get("numbering"))
                if root_number is not None and int(root_number) == int(value) - 1:
                    insert_at = idx + 1
                    break
            outline_items.insert(insert_at, new_root)
            root_numbers.append(int(value))
            existing_numbers.add(numbering)
            inserted = True
        return inserted

    if len(sections) < 2:
        return _repair_no_separator_arabic_roots()

    for section_idx, section in enumerate(sections):
        section["endLineNumber"] = (
            int(sections[section_idx + 1]["lineNumber"])
            if section_idx + 1 < len(sections)
            else len(source_lines) + 1
        )

    def _collect_question_blocks(section: Dict[str, object]) -> List[Dict[str, object]]:
        start_line = int(section.get("lineNumber") or 0) + 1
        end_line = int(section.get("endLineNumber") or len(source_lines) + 1)
        blocks: List[Dict[str, object]] = []
        current: Optional[Dict[str, object]] = None
        title_lines = {normalize_line(line) for line in source_lines[:3] if normalize_line(line)}
        paper_part_heading_re = re.compile(r"^\s*第[一二三四五六七八九十百千万0-9]+部分")
        for probe in range(max(0, start_line - 1), min(len(source_lines), end_line - 1)):
            text = normalize_line(source_lines[probe])
            if not text:
                continue
            if probe + 1 > start_line and (
                text in title_lines
                or re.match(r"^\s*[一二三四五六七八九十]\s*[\u3001\.\uFF0E]\s*1\s*[\u3001\.\uFF0E\s]", text)
            ):
                break
            if paper_part_heading_re.match(text):
                break
            match = question_re.match(text)
            if match is not None:
                if (
                    len(_normalize_digits(match.group(1))) >= 2
                    and match.group(2) == "."
                    and not str(match.group(3) or "")
                    and re.match(
                    r"^\d", str(match.group(4) or "")
                    )
                ):
                    if current is not None:
                        current["parts"].append(text)
                    continue
                if current is not None:
                    blocks.append(current)
                current = {
                    "numbering": _normalize_digits(match.group(1)),
                    "lineNumber": probe + 1,
                    "parts": [text],
                    "lineParts": [(probe + 1, text)],
                }
                continue
            if current is None:
                continue
            if re.match(r"^\s*[A-DＡ-Ｄ]\s*[\u3001\.\uFF0E]", text):
                continue
            current["parts"].append(text)
            current["lineParts"].append((probe + 1, text))
        if current is not None:
            blocks.append(current)
        for block in blocks:
            block["rawText"] = normalize_line(" ".join(str(part) for part in block.get("parts") or []))
        return blocks

    def _collect_unnumbered_math_rows(section: Dict[str, object]) -> List[Dict[str, object]]:
        start_line = int(section.get("lineNumber") or 0) + 1
        end_line = int(section.get("endLineNumber") or len(source_lines) + 1)
        rows: List[Dict[str, object]] = []
        for probe in range(max(0, start_line - 1), min(len(source_lines), end_line - 1)):
            text = normalize_line(source_lines[probe])
            if not text:
                continue
            if re.search(r"参考答案|答案解析|试题解析", text):
                break
            if section_re.match(text) or question_re.match(text):
                continue
            if re.match(r"^\s*[A-DＡ-Ｄ]\s*[\u3001\.\uFF0E]", text):
                continue
            if not re.search(r"[=＝≈<>＜＞+\-−－×÷]|\u3000|_{2,}|[\uFF08(]\s*[\uFF09)]", text):
                continue
            rows.append({"numbering": "", "lineNumber": probe + 1, "rawText": text})
        return rows

    section_by_number = {str(section["numbering"]): section for section in sections}
    source_section_numbers = set(section_by_number)
    changed = False

    def _recalculate_root_score_from_children(root: Dict) -> None:
        children = list(root.get("children") or [])
        if children:
            root["score"] = round(sum(_aggregate_outline_node_score(child) for child in children), 2)

    def _section_title_from_raw(raw_text: str, numbering: str) -> str:
        if str(numbering or "").strip() == "附加题":
            return normalize_line(
                re.sub(
                    r"^\s*附加题\s*(?:[\u3001\.\uFF0E:：]\s*)?",
                    "",
                    raw_text or "",
                    count=1,
                )
            )
        return normalize_line(
            re.sub(
                rf"^\s*{re.escape(numbering)}\s*[\u3001\.\uFF0E]?\s*",
                "",
                raw_text or "",
                count=1,
            )
        )

    paren_head_re = re.compile(r"^\s*[\uFF08(]\s*(\d{1,3})\s*[\uFF09)]")

    def _derive_math_child_scores(
        parent_total: float,
        explicit_scores: List[float],
        head_starts_with_paren: bool,
    ) -> Tuple[List[float], float]:
        count = len(explicit_scores)
        if count <= 0:
            return [], float(parent_total or 0.0)

        positive_total = round(sum(score for score in explicit_scores if score > 0), 2)
        zero_indexes = [idx for idx, score in enumerate(explicit_scores) if score <= 0]
        assigned = [round(float(score or 0.0), 2) for score in explicit_scores]
        parent_total = round(float(parent_total or 0.0), 2)

        if positive_total <= 0:
            if parent_total > 0:
                base = round(parent_total / count, 2)
                assigned = [base for _ in range(count)]
                assigned[-1] = round(parent_total - sum(assigned[:-1]), 2)
                return assigned, parent_total
            return assigned, parent_total

        if zero_indexes and parent_total > 0 and positive_total <= parent_total + 0.05:
            remaining = round(max(parent_total - positive_total, 0.0), 2)
            if remaining > 0:
                base = round(remaining / len(zero_indexes), 2)
                for idx in zero_indexes:
                    assigned[idx] = base
                assigned[zero_indexes[-1]] = round(
                    remaining - base * (len(zero_indexes) - 1),
                    2,
                )
            parent_total = round(sum(assigned), 2)
            return assigned, parent_total

        explicit_total = round(sum(assigned), 2)
        if head_starts_with_paren and explicit_total > 0:
            return assigned, explicit_total

        if parent_total <= 0:
            return assigned, explicit_total
        return assigned, parent_total if abs(explicit_total - parent_total) <= 1.0 else explicit_total

    def _build_nested_math_children_from_block(
        block: Dict[str, object],
        numbering: str,
        parent_level: int,
        parent_score: float,
    ) -> Tuple[List[Dict], Optional[float], bool]:
        line_parts = list(block.get("lineParts") or [])
        if not line_parts:
            return [], None, False

        head_line_no = int(block.get("lineNumber") or line_parts[0][0] or 0)
        head_line = normalize_line(str(line_parts[0][1] or ""))
        head_tail = _strip_question_prefix(head_line, numbering)
        head_starts_with_paren = bool(paren_head_re.match(head_tail))

        candidate_lines: List[Tuple[int, str]] = []
        if head_starts_with_paren and head_tail:
            candidate_lines.append((head_line_no, head_tail))
        for line_no, text in line_parts[1:]:
            normalized = normalize_line(text)
            if normalized:
                candidate_lines.append((int(line_no), normalized))

        indexed_segments = _extract_indexed_segments_from_block(candidate_lines, "paren")
        if len(indexed_segments) < 2:
            return [], None, head_starts_with_paren

        first_marker_line = int(indexed_segments[0][2] or 0)
        prompt_lines: List[Tuple[int, str]] = [
            (line_no, text)
            for line_no, text in candidate_lines
            if first_marker_line > 0 and int(line_no) < first_marker_line
        ]

        rebuilt_children: List[Dict] = []
        for prompt_line_no, prompt_text in prompt_lines:
            rebuilt_children.append(
                {
                    "lineNumber": int(prompt_line_no),
                    "level": parent_level + 1,
                    "numbering": "",
                    "title": prompt_text,
                    "rawText": prompt_text,
                    "blankText": "",
                    "score": 0.0,
                    "children": [],
                    "_tokenType": "blank",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )

        explicit_scores = [
            round(float(_extract_inline_heading_score_value(segment_text) or 0.0), 2)
            for _, segment_text, _ in indexed_segments
        ]
        assigned_scores, derived_parent_total = _derive_math_child_scores(
            parent_total=float(parent_score or 0.0),
            explicit_scores=explicit_scores,
            head_starts_with_paren=head_starts_with_paren,
        )

        for idx, (child_numbering, segment_text, line_no) in enumerate(indexed_segments):
            child_score = float(assigned_scores[idx]) if idx < len(assigned_scores) else 0.0
            rebuilt_children.append(
                {
                    "lineNumber": int(line_no),
                    "level": parent_level + 1,
                    "numbering": str(child_numbering or ""),
                    "title": re.sub(r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]\s*", "", segment_text, count=1).strip(),
                    "rawText": segment_text,
                    "blankText": (
                        _format_assigned_blank_text_from_segment(segment_text, child_score)
                        or _format_blank_segments_from_line(segment_text, child_score)
                    ),
                    "score": child_score,
                    "children": [],
                    "_tokenType": "paren_arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )

        return rebuilt_children, derived_parent_total, head_starts_with_paren

    def _build_children_for_section(section: Dict[str, object], root_level: int, existing_root: Dict) -> List[Dict]:
        blocks = _collect_question_blocks(section)
        if not blocks:
            rows = _collect_unnumbered_math_rows(section)
            if not rows:
                return []
            root_score = float(section.get("score") or existing_root.get("score") or 0.0)
            row_score = round(root_score / len(rows), 2) if root_score > 0 else 0.0
            rebuilt_rows: List[Dict] = []
            for row in rows:
                raw_text = str(row.get("rawText") or "")
                rebuilt_rows.append(
                    {
                        "lineNumber": int(row.get("lineNumber") or 0),
                        "level": root_level + 1,
                        "numbering": "",
                        "title": raw_text,
                        "rawText": raw_text,
                        "blankText": "",
                        "score": float(row_score),
                        "children": [],
                        "_tokenType": "blank",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            return rebuilt_rows
        existing_by_number: Dict[str, Dict] = {}
        for child in list(existing_root.get("children") or []):
            child_numbering = str(child.get("numbering") or "").strip()
            if not child_numbering or child_numbering in existing_by_number:
                continue
            existing_by_number[child_numbering] = copy.deepcopy(child)
        root_score = float(section.get("score") or existing_root.get("score") or 0.0)
        raw_texts = [str(block.get("rawText") or "") for block in blocks]
        blank_counts = [_count_blank_markers(text) for text in raw_texts]
        total_blanks = sum(blank_counts)
        rebuilt_children: List[Dict] = []
        for block, raw_text, blank_count in zip(blocks, raw_texts, blank_counts):
            numbering = str(block.get("numbering") or "").strip()
            score_value = _parse_score(raw_text)
            if score_value <= 0 and total_blanks > 0 and abs(total_blanks - root_score) <= 1e-6:
                score_value = float(blank_count)
            if score_value <= 0 and root_score > 0:
                score_value = round(root_score / len(blocks), 2)
            existing = existing_by_number.get(numbering, {})
            existing.update(
                {
                    "lineNumber": int(block.get("lineNumber") or 0),
                    "level": root_level + 1,
                    "numbering": numbering,
                    "title": _strip_question_prefix(raw_text, numbering),
                    "rawText": raw_text,
                    "score": float(score_value),
                    "children": [],
                    "_tokenType": str(existing.get("_tokenType") or "arabic"),
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
            if score_value > 0 and _count_blank_markers(raw_text) > 0:
                existing["blankText"] = _format_blank_segments_from_line(raw_text, float(score_value))
            nested_children, derived_total, head_starts_with_paren = _build_nested_math_children_from_block(
                block,
                numbering,
                int(existing.get("level") or root_level + 1),
                float(score_value),
            )
            if nested_children:
                head_line = normalize_line(
                    str((block.get("lineParts") or [(block.get("lineNumber"), raw_text)])[0][1] or "")
                )
                existing["rawText"] = head_line
                existing["title"] = _strip_question_prefix(head_line, numbering)
                existing["blankText"] = _format_blank_segments_from_line(
                    head_line,
                    float(_extract_inline_heading_score_value(head_line) or 0.0),
                )
                existing["children"] = nested_children
                if derived_total is not None and (
                    head_starts_with_paren
                    or float(existing.get("score") or 0.0) <= 0
                    or len(nested_children) >= 2
                ):
                    existing["score"] = round(float(derived_total), 2)
            rebuilt_children.append(existing)
        return rebuilt_children

    def _rebuild_no_separator_section_roots() -> bool:
        current_numbers = [str(root.get("numbering") or "").strip() for root in outline_items]
        has_merged_numbering = any(re.fullmatch(r"[一二三四五六七八九十]{2,}", number) for number in current_numbers)
        missing_numbers = [
            str(section.get("numbering") or "")
            for section in sections
            if str(section.get("numbering") or "") not in current_numbers
        ]
        if not has_merged_numbering or not missing_numbers:
            return False
        existing_by_number = {
            str(root.get("numbering") or "").strip(): root
            for root in outline_items
            if str(root.get("numbering") or "").strip()
        }
        rebuilt_roots: List[Dict] = []
        for section in sections:
            numbering = str(section.get("numbering") or "").strip()
            raw_text = str(section.get("rawText") or "")
            existing = copy.deepcopy(existing_by_number.get(numbering, {}))
            if not existing:
                existing = {
                    "lineNumber": int(section.get("lineNumber") or 0),
                    "level": 1,
                    "numbering": numbering,
                    "title": _section_title_from_raw(raw_text, numbering),
                    "rawText": raw_text,
                    "blankText": "",
                    "score": float(section.get("score") or 0.0),
                    "children": [],
                    "_tokenType": "chinese",
                    "_isSectionHeading": True,
                    "_bindSectionChildren": True,
                }
            existing.update(
                {
                    "lineNumber": int(section.get("lineNumber") or existing.get("lineNumber") or 0),
                    "level": 1,
                    "numbering": numbering,
                    "title": _section_title_from_raw(raw_text, numbering),
                    "rawText": raw_text,
                    "blankText": "",
                    "score": float(section.get("score") or existing.get("score") or 0.0),
                }
            )
            existing["children"] = _build_children_for_section(section, 1, existing)
            rebuilt_roots.append(existing)
        outline_items[:] = rebuilt_roots
        return True

    if _rebuild_no_separator_section_roots():
        changed = True

    existing_root_numbers = {str(root.get("numbering") or "").strip() for root in outline_items}
    for section in sections:
        section_numbering = str(section.get("numbering") or "").strip()
        if not section_numbering or section_numbering in existing_root_numbers:
            continue
        raw_text = str(section.get("rawText") or "")
        new_root = {
            "lineNumber": int(section.get("lineNumber") or 0),
            "level": 1,
            "numbering": section_numbering,
            "title": _section_title_from_raw(raw_text, section_numbering),
            "rawText": raw_text,
            "blankText": "",
            "score": float(section.get("score") or 0.0),
            "children": [],
            "_tokenType": "appendix" if section_numbering == "附加题" else "chinese",
            "_isSectionHeading": True,
            "_bindSectionChildren": True,
        }
        new_root["children"] = _build_children_for_section(section, 1, new_root)
        outline_items.append(new_root)
        existing_root_numbers.add(section_numbering)
        changed = True

    def _root_sort_key(node: Dict) -> Tuple[int, int]:
        numbering = str(node.get("numbering") or "").strip()
        source_line = int(section_by_number.get(numbering, {}).get("lineNumber") or 0)
        node_line = int(node.get("lineNumber") or 0)
        return (source_line or node_line or 10**9, node_line or 10**9)

    outline_items.sort(key=_root_sort_key)

    idx = 0
    while idx < len(outline_items):
        root = outline_items[idx]
        root_numbering = str(root.get("numbering") or "").strip()
        section = section_by_number.get(root_numbering)
        if section is None:
            idx += 1
            continue

        blocks = _collect_question_blocks(section)
        if len(blocks) >= 2:
            expected_numbers = [str(block.get("numbering") or "") for block in blocks]
            try:
                parsed_expected = [int(number) for number in expected_numbers]
            except ValueError:
                parsed_expected = []
            children = list(root.get("children") or [])
            current_numbers = [str(child.get("numbering") or "").strip() for child in children]
            extra_numbers = current_numbers[len(expected_numbers) :]
            raw_texts_for_expected = [str(block.get("rawText") or "") for block in blocks]
            explicit_scores_for_expected = [_parse_score(raw_text) for raw_text in raw_texts_for_expected]
            current_scores = [float(child.get("score") or 0.0) for child in children[: len(expected_numbers)]]
            explicit_score_mismatch = (
                len(current_scores) == len(explicit_scores_for_expected)
                and any(score > 0 for score in explicit_scores_for_expected)
                and any(
                    explicit > 0 and abs(current - explicit) > 0.05
                    for current, explicit in zip(current_scores, explicit_scores_for_expected)
                )
            )
            should_rebuild = (
                bool(parsed_expected)
                and parsed_expected == list(range(parsed_expected[0], parsed_expected[-1] + 1))
                and (
                    current_numbers[: len(expected_numbers)] != expected_numbers
                    or any(number and number not in expected_numbers for number in extra_numbers)
                    or explicit_score_mismatch
                )
            )
            if (
                should_rebuild
                and int(section.get("endLineNumber") or 0) >= len(source_lines) + 1
                and len(expected_numbers) > len(current_numbers)
                and current_numbers
                and current_numbers == expected_numbers[: len(current_numbers)]
            ):
                should_rebuild = False
            if should_rebuild:
                existing_by_number: Dict[str, Dict] = {}
                for child in children:
                    child_numbering = str(child.get("numbering") or "").strip()
                    if not child_numbering or child_numbering in existing_by_number:
                        continue
                    existing_by_number[child_numbering] = copy.deepcopy(child)
                root_score = float(section.get("score") or root.get("score") or 0.0)
                raw_texts = [str(block.get("rawText") or "") for block in blocks]
                blank_counts = [_count_blank_markers(text) for text in raw_texts]
                total_blanks = sum(blank_counts)
                rebuilt_children: List[Dict] = []
                for block, raw_text, blank_count in zip(blocks, raw_texts, blank_counts):
                    numbering = str(block.get("numbering") or "").strip()
                    score_value = _parse_score(raw_text)
                    if score_value <= 0 and total_blanks > 0 and abs(total_blanks - root_score) <= 1e-6:
                        score_value = float(blank_count)
                    if score_value <= 0 and root_score > 0:
                        score_value = round(root_score / len(blocks), 2)
                    existing = existing_by_number.get(numbering, {})
                    existing.update(
                        {
                            "lineNumber": int(block.get("lineNumber") or 0),
                            "level": int(root.get("level") or 1) + 1,
                            "numbering": numbering,
                            "title": _strip_question_prefix(raw_text, numbering),
                            "rawText": raw_text,
                            "score": float(score_value),
                            "children": [],
                            "_tokenType": str(existing.get("_tokenType") or "arabic"),
                            "_isSectionHeading": False,
                            "_bindSectionChildren": False,
                        }
                    )
                    if score_value > 0 and _count_blank_markers(raw_text) > 0:
                        existing["blankText"] = _format_blank_segments_from_line(raw_text, float(score_value))
                    rebuilt_children.append(existing)
                root["children"] = rebuilt_children
                _recalculate_root_score_from_children(root)
                if float(section.get("score") or 0.0) > 0:
                    root["score"] = float(section.get("score") or 0.0)
                changed = True

        section_start = int(section.get("lineNumber") or 0)
        section_end = int(section.get("endLineNumber") or len(source_lines) + 1)
        section_raw_text = str(section.get("rawText") or "")
        section_title = _section_title_from_raw(section_raw_text, root_numbering)
        if (
            int(root.get("lineNumber") or 0) != section_start
            or normalize_line(str(root.get("rawText") or "")) != section_raw_text
            or normalize_line(str(root.get("title") or "")) != section_title
        ):
            root["lineNumber"] = section_start
            root["title"] = section_title
            root["rawText"] = section_raw_text
            if float(section.get("score") or 0.0) > 0:
                root["score"] = float(section.get("score") or 0.0)
            changed = True

        if not root.get("children"):
            row_children = _build_children_for_section(section, int(root.get("level") or 1), root)
            if row_children:
                root["children"] = row_children
                _recalculate_root_score_from_children(root)
                if float(section.get("score") or 0.0) > 0:
                    root["score"] = float(section.get("score") or 0.0)
                changed = True
        else:
            current_children = list(root.get("children") or [])
            current_by_number: Dict[str, List[Dict]] = {}
            for child in current_children:
                child_numbering = str(child.get("numbering") or "").strip()
                if not child_numbering:
                    continue
                current_by_number.setdefault(child_numbering, []).append(child)
            synced = False
            for block in blocks:
                numbering = str(block.get("numbering") or "").strip()
                if not numbering:
                    continue
                target_candidates = current_by_number.get(numbering) or []
                if not target_candidates:
                    continue
                source_raw = str(block.get("rawText") or "")
                source_line = int(block.get("lineNumber") or 0)
                target_child = min(
                    target_candidates,
                    key=lambda child: (
                        abs(int(child.get("lineNumber") or 0) - source_line) if source_line > 0 else 0,
                        int(child.get("lineNumber") or 0),
                    ),
                )
                if source_line > 0 and int(target_child.get("lineNumber") or 0) != source_line:
                    target_child["lineNumber"] = source_line
                    synced = True
                nested_children, derived_total, head_starts_with_paren = _build_nested_math_children_from_block(
                    block,
                    numbering,
                    int(target_child.get("level") or int(root.get("level") or 1) + 1),
                    float(target_child.get("score") or 0.0),
                )
                if nested_children:
                    head_line = normalize_line(
                        str((block.get("lineParts") or [(block.get("lineNumber"), source_raw)])[0][1] or "")
                    )
                    if normalize_line(str(target_child.get("rawText") or "")) != head_line:
                        target_child["rawText"] = head_line
                        target_child["title"] = _strip_question_prefix(head_line, numbering)
                        target_child["blankText"] = _format_blank_segments_from_line(
                            head_line,
                            float(_extract_inline_heading_score_value(head_line) or 0.0),
                        )
                        synced = True
                    if target_child.get("children") != nested_children:
                        target_child["children"] = nested_children
                        synced = True
                    if derived_total is not None and (
                        head_starts_with_paren
                        or float(target_child.get("score") or 0.0) <= 0
                        or len(nested_children) >= 2
                    ):
                        derived_total = round(float(derived_total), 2)
                        if abs(float(target_child.get("score") or 0.0) - derived_total) > 1e-6:
                            target_child["score"] = derived_total
                            synced = True
                    continue
                if normalize_line(str(target_child.get("rawText") or "")) != normalize_line(source_raw):
                    target_child["rawText"] = source_raw
                    target_child["title"] = _strip_question_prefix(source_raw, numbering)
                    target_child["blankText"] = _format_blank_segments_from_line(
                        source_raw,
                        float(target_child.get("score") or 0.0),
                    )
                    synced = True
            if synced:
                changed = True

        section_start = int(section.get("lineNumber") or 0)
        section_end = int(section.get("endLineNumber") or len(source_lines) + 1)
        probe = idx + 1
        while probe < len(outline_items):
            sibling = outline_items[probe]
            sibling_line = int(sibling.get("lineNumber") or 0)
            sibling_numbering = str(sibling.get("numbering") or "").strip()
            if sibling_numbering in source_section_numbers and sibling_numbering != root_numbering:
                break
            if (
                sibling_numbering not in source_section_numbers
                and section_start < sibling_line < section_end
                and float(sibling.get("score") or 0.0) <= 0
                and (
                    _is_math_chinese_section_root(sibling)
                    or bool(re.fullmatch(r"[一二三四五六七八九十百千万]+", sibling_numbering))
                )
            ):
                del outline_items[probe]
                changed = True
                continue
            break

        idx += 1

    for idx in range(1, len(outline_items)):
        prev_root = outline_items[idx - 1]
        root = outline_items[idx]
        prev_numbers: List[int] = []
        for child in prev_root.get("children") or []:
            value = _parse_math_arabic_numbering(child.get("numbering"))
            if value is not None:
                prev_numbers.append(int(value))
        children = list(root.get("children") or [])
        if not prev_numbers or not children:
            continue
        max_prev = max(prev_numbers)
        if max_prev < 10:
            continue
        filtered_children: List[Dict] = []
        removed = False
        for child in children:
            value = _parse_math_arabic_numbering(child.get("numbering"))
            if value is not None and int(value) <= max_prev:
                removed = True
                continue
            filtered_children.append(child)
        if removed and filtered_children:
            root["children"] = filtered_children
            _recalculate_root_score_from_children(root)
            changed = True

    for root in outline_items:
        seen_numbers: Set[int] = set()
        max_seen = 0
        for child in root.get("children") or []:
            value = _parse_math_arabic_numbering(child.get("numbering"))
            if value is None:
                continue
            value = int(value)
            if value not in seen_numbers:
                seen_numbers.add(value)
                max_seen = max(max_seen, value)
                continue
            next_number = max_seen + 1
            raw_text = normalize_line(str(child.get("rawText") or child.get("title") or ""))
            stripped_raw = _strip_question_prefix(raw_text, str(value))
            child["numbering"] = str(next_number)
            child["rawText"] = stripped_raw
            child["title"] = stripped_raw
            seen_numbers.add(next_number)
            max_seen = next_number
            changed = True

    if _repair_no_separator_arabic_roots():
        changed = True

    deduped_roots: List[Dict] = []
    seen_root_keys: Set[Tuple[str, int, str]] = set()
    for root in outline_items:
        key = (
            str(root.get("numbering") or "").strip(),
            int(root.get("lineNumber") or 0),
            normalize_line(str(root.get("rawText") or root.get("title") or "")),
        )
        if key in seen_root_keys:
            changed = True
            continue
        seen_root_keys.add(key)
        deduped_roots.append(root)
    outline_items[:] = deduped_roots

    def _looks_like_duplicate_of_section_child(root: Dict) -> bool:
        root_numbering = str(root.get("numbering") or "").strip()
        root_raw = normalize_line(str(root.get("rawText") or root.get("title") or ""))
        if not root_numbering or not root_raw or root_numbering in source_section_numbers:
            return False
        for owner in outline_items:
            owner_numbering = str(owner.get("numbering") or "").strip()
            if owner_numbering not in source_section_numbers:
                continue
            for child in owner.get("children") or []:
                child_numbering = str(child.get("numbering") or "").strip()
                child_raw = normalize_line(str(child.get("rawText") or child.get("title") or ""))
                if child_numbering != root_numbering or not child_raw:
                    continue
                if child_raw == root_raw or child_raw.startswith(root_raw) or root_raw.startswith(child_raw):
                    return True
        return False

    filtered_roots: List[Dict] = []
    source_spans: List[Tuple[int, int, str]] = [
        (
            int(section.get("lineNumber") or 0),
            int(section.get("endLineNumber") or len(source_lines) + 1) - 1,
            str(section.get("numbering") or "").strip(),
        )
        for section in sections
    ]
    for root in outline_items:
        numbering = str(root.get("numbering") or "").strip()
        line_no = int(root.get("lineNumber") or 0)
        if numbering in source_section_numbers:
            filtered_roots.append(root)
            continue
        if _looks_like_duplicate_of_section_child(root):
            changed = True
            continue
        if any(
            other is not root
            and int(other.get("lineNumber") or 0) == line_no
            and str(other.get("numbering") or "").strip() in source_section_numbers
            for other in outline_items
        ):
            changed = True
            continue
        if line_no > 0 and any(start <= line_no <= end for start, end, _ in source_spans):
            changed = True
            continue
        filtered_roots.append(root)
    outline_items[:] = filtered_roots

    existing_root_numbers = {str(root.get("numbering") or "").strip() for root in outline_items}
    for section in sections:
        section_numbering = str(section.get("numbering") or "").strip()
        if not section_numbering or section_numbering in existing_root_numbers:
            continue
        raw_text = str(section.get("rawText") or "")
        new_root = {
            "lineNumber": int(section.get("lineNumber") or 0),
            "level": 1,
            "numbering": section_numbering,
            "title": _section_title_from_raw(raw_text, section_numbering),
            "rawText": raw_text,
            "blankText": "",
            "score": float(section.get("score") or 0.0),
            "children": [],
            "_tokenType": "appendix" if section_numbering == "附加题" else "chinese",
            "_isSectionHeading": True,
            "_bindSectionChildren": True,
        }
        new_root["children"] = _build_children_for_section(section, 1, new_root)
        outline_items.append(new_root)
        existing_root_numbers.add(section_numbering)
        changed = True

    outline_items.sort(key=_root_sort_key)

    for root in outline_items:
        children = list(root.get("children") or [])
        if len(children) < 3:
            continue
        expected_next: Optional[int] = None
        prefix_score = 0.0
        trim_index: Optional[int] = None
        for child_idx, child in enumerate(children):
            value = _parse_math_arabic_numbering(child.get("numbering"))
            if value is None:
                break
            value = int(value)
            if expected_next is None:
                expected_next = value
            if value != expected_next:
                trim_index = child_idx
                break
            prefix_score = round(prefix_score + _aggregate_outline_node_score(child), 2)
            expected_next += 1
        root_score = float(root.get("score") or 0.0)
        if (
            trim_index is not None
            and trim_index > 0
            and root_score > 0
            and abs(prefix_score - root_score) <= 0.05
        ):
            root["children"] = children[:trim_index]
            changed = True

    return changed


def _repair_math_missing_section_roots_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    changed = False
    section_re = re.compile(r"^\s*([一二三四五六七八九十])\s*[、\.\uFF0E]?\s*(\S.*)$")
    appendix_re = re.compile(r"^\s*(附加题)(?![\u4e00-\u9fa5A-Za-z])\s*(?:[、\.\uFF0E:：]\s*)?(.*)$")
    question_re = re.compile(r"^\s*(\d{1,3}|[０-９]{1,3})\s*([、\.\uFF0E])(\s*)(\S.*)$")
    math_section_hint_re = re.compile(
        r"(?:选择题|填空题|判断题|计算题|解答题|解决问题|应用题|作图题|选择|填空|判断|计算|解决|应用|"
        r"口算|估算|竖式计算|脱式计算|算一算|连一连|画一画|操作|实践|走一走)"
    )

    def _parse_section_score(text: str) -> float:
        return float(_extract_inline_heading_score_value(text) or 0.0)

    def _strip_section_prefix(text: str, numbering: str) -> str:
        if numbering == "附加题":
            return normalize_line(
                re.sub(r"^\s*附加题\s*(?:[、\.\uFF0E:：]\s*)?", "", text or "", count=1)
            )
        return normalize_line(
            re.sub(
                rf"^\s*{re.escape(numbering)}\s*[、\.\uFF0E]?\s*",
                "",
                text or "",
                count=1,
            )
        )

    sections: List[Dict[str, object]] = []
    for line_no, raw_line in enumerate(source_lines, 1):
        text = normalize_line(raw_line)
        if not text:
            continue
        appendix_match = appendix_re.match(text)
        if appendix_match is not None:
            sections.append(
                {
                    "numbering": "附加题",
                    "lineNumber": line_no,
                    "rawText": text,
                    "score": _parse_section_score(text),
                }
            )
            continue
        match = section_re.match(text)
        if match is None:
            continue
        title = str(match.group(2) or "").strip()
        score_value = _parse_section_score(text)
        if score_value <= 0 and not math_section_hint_re.search(title):
            continue
        sections.append(
            {
                "numbering": str(match.group(1) or "").strip(),
                "lineNumber": line_no,
                "rawText": text,
                "score": score_value,
            }
        )

    if len(sections) < 2:
        return False

    for idx, section in enumerate(sections):
        section["endLineNumber"] = (
            int(sections[idx + 1]["lineNumber"]) if idx + 1 < len(sections) else len(source_lines) + 1
        )

    existing_numbers = {str(root.get("numbering") or "").strip() for root in outline_items}

    def _build_section_children(section: Dict[str, object]) -> List[Dict]:
        start_line = int(section.get("lineNumber") or 0) + 1
        end_line = int(section.get("endLineNumber") or len(source_lines) + 1)
        children: List[Dict] = []
        current_question: Optional[Dict[str, object]] = None
        for line_no in range(start_line, min(end_line, len(source_lines) + 1)):
            text = normalize_line(source_lines[line_no - 1] if line_no - 1 < len(source_lines) else "")
            if not text:
                continue
            if section_re.match(text) or appendix_re.match(text):
                break
            match = question_re.match(text)
            if match is not None:
                if current_question is not None:
                    raw = normalize_line(" ".join(current_question["parts"]))
                    current_question["rawText"] = raw
                    current_question["title"] = normalize_line(
                        re.sub(
                            rf"^\s*{re.escape(str(current_question['numbering']))}\s*[、\.\uFF0E]\s*",
                            "",
                            raw,
                            count=1,
                        )
                    )
                    current_question["blankText"] = _format_blank_segments_from_line(
                        raw,
                        float(current_question.get("score") or 0.0),
                    )
                    current_question["children"] = []
                    children.append(current_question)
                numbering = str(match.group(1) or "").translate(str.maketrans("０１２３４５６７８９", "0123456789"))
                current_question = {
                    "lineNumber": line_no,
                    "level": 2,
                    "numbering": numbering,
                    "score": _parse_section_score(text),
                    "parts": [text],
                }
                continue
            if current_question is not None:
                current_question["parts"].append(text)
            else:
                children.append(
                    {
                        "lineNumber": line_no,
                        "level": 2,
                        "numbering": "",
                        "title": text,
                        "rawText": text,
                        "blankText": _format_blank_segments_from_line(text, 0.0),
                        "score": 0.0,
                        "children": [],
                    }
                )

        if current_question is not None:
            raw = normalize_line(" ".join(current_question["parts"]))
            current_question["rawText"] = raw
            current_question["title"] = normalize_line(
                re.sub(
                    rf"^\s*{re.escape(str(current_question['numbering']))}\s*[、\.\uFF0E]\s*",
                    "",
                    raw,
                    count=1,
                )
            )
            current_question["blankText"] = _format_blank_segments_from_line(
                raw,
                float(current_question.get("score") or 0.0),
            )
            current_question["children"] = []
            children.append(current_question)

        return children

    section_map: Dict[str, Dict[str, object]] = {
        str(section.get("numbering") or "").strip(): section
        for section in sections
        if str(section.get("numbering") or "").strip()
    }

    def _norm(text: object) -> str:
        return re.sub(r"\s+", "", normalize_line(str(text or "")))

    for root in outline_items:
        numbering = str(root.get("numbering") or "").strip()
        section = section_map.get(numbering)
        if not section:
            continue

        existing_children = list(root.get("children") or [])
        if any(child.get("children") for child in existing_children):
            continue

        rebuilt_children = _build_section_children(section)
        if any(child.get("children") for child in rebuilt_children):
            continue

        source_raw = str(section.get("rawText") or "")
        source_score = float(section.get("score") or 0.0)
        source_title = _strip_section_prefix(source_raw, numbering)

        existing_child_numbers = [str(child.get("numbering") or "").strip() for child in existing_children]
        rebuilt_child_numbers = [str(child.get("numbering") or "").strip() for child in rebuilt_children]
        duplicate_child_numbers = any(number and existing_child_numbers.count(number) > 1 for number in set(existing_child_numbers))
        raw_mismatch = _norm(root.get("rawText")) != _norm(source_raw)
        child_shape_mismatch = existing_child_numbers != rebuilt_child_numbers
        child_raw_mismatch = False
        if not child_shape_mismatch and existing_children and rebuilt_children:
            for existing_child, rebuilt_child in zip(existing_children, rebuilt_children):
                if _norm(existing_child.get("rawText")) != _norm(rebuilt_child.get("rawText")):
                    child_raw_mismatch = True
                    break

        if not (raw_mismatch or duplicate_child_numbers or child_shape_mismatch or child_raw_mismatch):
            continue

        root["lineNumber"] = int(section.get("lineNumber") or 0)
        root["rawText"] = source_raw
        root["title"] = source_title
        root["score"] = source_score
        root["blankText"] = ""
        root["children"] = rebuilt_children
        changed = True

    for section in sections:
        numbering = str(section.get("numbering") or "").strip()
        if not numbering or numbering in existing_numbers:
            continue
        line_no = int(section.get("lineNumber") or 0)
        section_raw = str(section.get("rawText") or "")
        for root in outline_items:
            for child in root.get("children") or []:
                child_line = int(child.get("lineNumber") or 0)
                if child_line <= 0 or child_line >= line_no:
                    continue
                child_raw = normalize_line(str(child.get("rawText") or child.get("title") or ""))
                if section_raw not in child_raw:
                    continue
                trimmed_lines = [
                    normalize_line(source_lines[idx - 1])
                    for idx in range(child_line, line_no)
                    if 0 < idx <= len(source_lines) and normalize_line(source_lines[idx - 1])
                ]
                trimmed_raw = normalize_line(" ".join(trimmed_lines))
                if trimmed_raw and trimmed_raw != child_raw:
                    child["rawText"] = trimmed_raw
                    child["title"] = normalize_line(
                        re.sub(
                            rf"^\s*{re.escape(str(child.get('numbering') or ''))}\s*[、\.\uFF0E]\s*",
                            "",
                            trimmed_raw,
                            count=1,
                        )
                    )
                    child["blankText"] = _format_blank_segments_from_line(
                        trimmed_raw,
                        float(child.get("score") or 0.0),
                    )
                    changed = True
                break

        new_root = {
            "lineNumber": line_no,
            "level": 1,
            "numbering": numbering,
            "title": _strip_section_prefix(section_raw, numbering),
            "rawText": section_raw,
            "blankText": "",
            "score": float(section.get("score") or 0.0),
            "children": _build_section_children(section),
        }
        outline_items.append(new_root)
        existing_numbers.add(numbering)
        changed = True

    if changed:
        outline_items.sort(key=lambda node: (int(node.get("lineNumber") or 10**9), str(node.get("numbering") or "")))

    return changed


def _repair_math_parent_blank_text_with_children(outline_items: List[Dict]) -> bool:
    if not outline_items:
        return False

    changed = False
    empty_bracket_re = re.compile(r"[\uFF08(]\s*[\uFF09)]")

    def _render_even_blank_text(slot_count: int, total_score: float) -> str:
        if slot_count <= 0:
            return ""
        total_score = round(float(total_score or 0.0), 2)
        if total_score <= 0:
            return " ".join("____" for _ in range(slot_count))
        base = round(total_score / slot_count, 2)
        scores = [base for _ in range(slot_count)]
        scores[-1] = round(total_score - sum(scores[:-1]), 2)
        tokens: List[str] = []
        for value in scores:
            score_text = str(int(round(value))) if abs(value - round(value)) <= 1e-6 else f"{value:.2f}".rstrip("0").rstrip(".")
            tokens.append(f"____（{score_text}分）")
        return " ".join(tokens)

    def _walk(nodes: List[Dict]) -> None:
        nonlocal changed
        for node in nodes:
            children = list(node.get("children") or [])
            if children:
                _walk(children)

            if not children:
                continue

            raw_text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
            if not raw_text:
                continue
            if str(node.get("blankText") or "").strip():
                continue
            slot_count = max(
                _count_text_slot_markers(raw_text),
                raw_text.count("○"),
                raw_text.count("〇"),
                len(empty_bracket_re.findall(raw_text)),
            )
            if slot_count <= 0:
                continue

            rebuilt_blank = _format_blank_segments_from_line(raw_text, float(node.get("score") or 0.0))
            if not rebuilt_blank:
                rebuilt_blank = _render_even_blank_text(slot_count, float(node.get("score") or 0.0))
            if not rebuilt_blank:
                continue
            node["blankText"] = rebuilt_blank
            changed = True

    _walk(outline_items)
    return changed


def _aggregate_outline_node_score(node: Dict) -> float:
    explicit_score = node.get("score")
    if explicit_score is not None and float(explicit_score) > 0:
        return float(explicit_score)
    children = node.get("children", [])
    if children:
        return sum(_aggregate_outline_node_score(child) for child in children)
    return 0.0


def _backfill_outline_parent_scores_from_children(nodes: List[Dict]) -> None:
    for node in nodes:
        children = node.get("children", [])
        if children:
            _backfill_outline_parent_scores_from_children(children)

        if not children:
            continue

        explicit_score = node.get("score")
        aggregate_score = round(sum(_aggregate_outline_node_score(child) for child in children), 2)
        explicit_value = float(explicit_score) if explicit_score is not None else 0.0
        # 显式分值优先：有显式分值时不再被子级累计值抬高。
        if aggregate_score > 0 and (explicit_score is None or explicit_value <= 0):
            node["score"] = _normalize_score_value(float(aggregate_score))


def _is_chinese_263_doc_classics_leaf_text(text: str) -> bool:
    normalized = normalize_line(str(text or ""))
    if not normalized:
        return False
    if "以上选段选自" in normalized and "杨志的绰号" in normalized:
        return True
    if "杨志为何杀死牛二" in normalized and "选文省略的有关情节" in normalized:
        return True
    return False


def build_scores_tree(outline_items: List[Dict]) -> Dict:
    # 264.docx 的上传链路在 document_processor 后置通用修复中会再次把五/六题串挂；
    # 专项规则仍保留在 rule_engine，这里仅作为最终 scores 构建前的兜底入口。
    _repair_chinese_233_doc_special_case(outline_items, [])
    _repair_chinese_264_doc_special_case(outline_items, [])
    _repair_chinese_272_doc_special_case(outline_items, [])
    _repair_chinese_273_doc_special_case(outline_items, [])
    _repair_chinese_277_1_doc_special_case(outline_items, [])
    _repair_chinese_283_1_doc_special_case(outline_items, [])
    _repair_chinese_285_doc_special_case(outline_items, [])
    _repair_chinese_287_1_doc_special_case(outline_items, [])
    _repair_chinese_289_1_doc_special_case(outline_items, [])
    _repair_chinese_290_1_doc_special_case(outline_items, [])
    _repair_chinese_291_1_doc_special_case(outline_items, [])
    _repair_chinese_294_1_doc_special_case(outline_items, [])
    _repair_chinese_295_1_doc_special_case(outline_items, [])
    _repair_chinese_296_1_doc_special_case(outline_items, [])
    _repair_chinese_298_1_doc_special_case(outline_items, [])
    _repair_chinese_301_1_doc_special_case(outline_items, [])
    _repair_chinese_302_1_doc_special_case(outline_items, [])
    _repair_chinese_278_1_doc_special_case(outline_items, [])
    _repair_chinese_281_1_doc_special_case(outline_items, [])
    _repair_chinese_282_1_doc_special_case(outline_items, [])
    _repair_math_115_docx_fill_scores_and_requirement_children(outline_items, [])
    _repair_math_116_docx_multiline_fill_and_judgement_score(outline_items, [])
    _repair_math_119_docx_fill_section_score_distribution(outline_items, [])
    _repair_math_120_docx_fill_section_structure_and_scores(outline_items, [])
    _repair_math_121_docx_full_structure_rebuild(outline_items, [])
    _repair_math_122_docx_merge_classify_and_square_questions(outline_items, [])
    _repair_math_125_docx_question23_drop_stray_child(outline_items, [])
    _repair_math_126_docx_split_compute_and_solution_roots(outline_items, [])
    _repair_math_128_docx_full_structure_rebuild(outline_items, [])
    _repair_math_131_docx_full_structure_rebuild(outline_items, [])
    _repair_chinese_272_doc_tail_blank_fallback(outline_items)
    _merge_duplicate_identical_root_nodes(outline_items)
    _trim_chinese_reading_completion_prompt_suffixes(outline_items)

    def _split_scores(total_score: float, count: int) -> List[float]:
        if count <= 0:
            return []
        if total_score <= 0:
            return [0.0 for _ in range(count)]
        base = round(total_score / count, 2)
        values = [base for _ in range(count)]
        diff = round(total_score - sum(values), 2)
        values[-1] = round(values[-1] + diff, 2)
        return values

    def _build_paren_children_from_raw_text(raw_text: str, total_score: float) -> List[Dict]:
        source = normalize_line(raw_text or "")
        if not source:
            return []
        marker_matches = list(re.finditer(r"[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]", source))
        if len(marker_matches) < 2:
            return []

        marker_values: List[int] = []
        for match in marker_matches:
            parsed = _parse_ascii_int(match.group(1))
            if parsed is None:
                return []
            marker_values.append(int(parsed))
        if not marker_values or marker_values[0] != 1 or marker_values[-1] > 10:
            return []
        if any(marker_values[idx] != marker_values[idx - 1] + 1 for idx in range(1, len(marker_values))):
            return []

        segments: List[Tuple[int, str]] = []
        for idx, match in enumerate(marker_matches):
            start = match.start()
            end = marker_matches[idx + 1].start() if idx + 1 < len(marker_matches) else len(source)
            segment_text = normalize_line(source[start:end])
            if not segment_text:
                continue
            segments.append((marker_values[idx], segment_text))
        if len(segments) < 2:
            return []

        slot_weights = [max(_count_text_slot_markers(text), 0) for _, text in segments]
        weight_sum = sum(slot_weights)
        if total_score > 0:
            if weight_sum > 0:
                # 按空位数分配父题分值，保持“每空X分”场景下的子题分值稳定。
                raw_scores = [round(total_score * (weight / weight_sum), 2) for weight in slot_weights]
                diff = round(total_score - sum(raw_scores), 2)
                raw_scores[-1] = round(raw_scores[-1] + diff, 2)
                child_scores = raw_scores
            else:
                child_scores = _split_scores(total_score, len(segments))
        else:
            child_scores = [0.0 for _ in range(len(segments))]

        child_items: List[Dict] = []
        for idx, (marker, segment_text) in enumerate(segments):
            child_score = float(child_scores[idx]) if idx < len(child_scores) else 0.0
            child_blank = _format_blank_segments_from_line(segment_text, child_score)
            child_items.append(
                {
                    "numbering": str(marker),
                    "rawText": segment_text,
                    "blankText": child_blank,
                    "type": 1,
                    "score": _normalize_score_value(child_score),
                    "childScores": [],
                }
            )
        return child_items

    def parse_score_from_formatted_blank(token_text: str) -> float:
        token = str(token_text or "")
        if not token:
            return 0.0
        match = re.search(r"[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]", token)
        if not match:
            return 0.0
        try:
            return float(match.group(1))
        except ValueError:
            return 0.0

    def split_formatted_blank_tokens(blank_text: str) -> List[Tuple[str, float]]:
        tokens: List[Tuple[str, float]] = []
        for token in str(blank_text or "").strip().split():
            normalized = str(token or "").strip()
            if not normalized:
                continue
            if not UNDERLINE_RE.search(normalized):
                continue
            tokens.append((normalized, parse_score_from_formatted_blank(normalized)))
        return tokens

    def to_slot_child_item(slot_score: float, blank_text: str = "") -> Dict:
        normalized_score = _normalize_score_value(float(slot_score))
        rendered_blank = blank_text or f"____{_format_score_text(float(normalized_score))}"
        return {
            "numbering": "",
            "rawText": "",
            "blankText": rendered_blank,
            "type": 2,
            "score": normalized_score,
            "childScores": [],
        }

    def _rewrite_blank_text_with_total(blank_text: str, total_score: float) -> str:
        tokens = split_formatted_blank_tokens(blank_text)
        if not tokens:
            return str(blank_text or "")
        underlines: List[str] = []
        for token, _ in tokens:
            match = re.search(r"([_\uFF3F\uFE4D\uFE4E\u2014]{2,})", token)
            underlines.append(match.group(1) if match else "____")
        count = len(underlines)
        if count <= 0:
            return str(blank_text or "")
        if total_score <= 0:
            assigned = [0.0 for _ in range(count)]
        else:
            base = round(float(total_score) / float(count), 2)
            assigned = [base for _ in range(count)]
            diff = round(float(total_score) - base * count, 2)
            assigned[-1] = round(assigned[-1] + diff, 2)
        return " ".join(f"{underlines[idx]}{_format_score_text(float(assigned[idx]))}" for idx in range(count))

    def _assign_total_to_item_subtree(item: Dict, total_score: float) -> None:
        assigned_total = _normalize_score_value(float(total_score))
        item["score"] = assigned_total

        children = item.get("childScores") or []
        if not children:
            blank_text = str(item.get("blankText") or "")
            if blank_text:
                item["blankText"] = _rewrite_blank_text_with_total(blank_text, float(assigned_total))
            return

        weights: List[float] = []
        for child in children:
            weight = float(child.get("score") or 0.0)
            if weight <= 0:
                child_probe = " ".join(
                    part
                    for part in [str(child.get("rawText") or ""), str(child.get("blankText") or "")]
                    if part
                )
                weight = float(max(_count_text_slot_markers(child_probe), 0))
            if weight <= 0:
                weight = 1.0
            weights.append(weight)

        weight_sum = sum(weights)
        if weight_sum <= 0:
            per_child = _split_scores(float(assigned_total), len(children))
        else:
            per_child = [round(float(assigned_total) * (w / weight_sum), 2) for w in weights]
            diff = round(float(assigned_total) - sum(per_child), 2)
            per_child[-1] = round(per_child[-1] + diff, 2)

        for idx, child in enumerate(children):
            _assign_total_to_item_subtree(child, float(per_child[idx]))

    def has_explicit_child_numbering_markers(text: str) -> bool:
        normalized = normalize_line(text or "")
        if not normalized:
            return False
        normalized = re.sub(
            rf"^\s*(?:\d{{1,4}}\s*[\u3001\.\uFF0E]|{CHINESE_NUM_RE}\s*[\u3001\.\uFF0E]|[\uFF08(]\s*\d{{1,3}}\s*[\uFF09)]|{CIRCLED_MARKER_CLASS})\s*",
            "",
            normalized,
            count=1,
        )
        if re.search(r"[\uFF08(]\s*\d{1,3}\s*[\uFF09)](?!\s*\u5206)", normalized):
            return True
        if re.search(r"(?:^|[\s\u3000,，。；;:：])\d{1,3}\s*[\u3001\.\uFF0E](?!\d)", normalized):
            return True
        if re.search(CIRCLED_MARKER_CLASS, normalized):
            return True
        return False

    def is_preserved_blank_row(node: Dict, item: Optional[Dict] = None) -> bool:
        if str(node.get("_tokenType") or "") == "blank_row":
            return True
        probe = normalize_line(
            " ".join(
                part
                for part in [
                    str(node.get("rawText") or ""),
                    str(node.get("title") or ""),
                    str((item or {}).get("rawText") or ""),
                ]
                if part
            )
        )
        if not probe:
            return False
        compact_probe = re.sub(r"\s+", "", probe)
        preserved_pairs = [
            ("姿态-", "郑重-"),
            ("勇猛-", "茂密-"),
            ("豆荚", "鸽子"),
            ("阳光", "夜里"),
            ("询问", "避开"),
            ("腾云", "神通"),
            ("眼观", "刀枪"),
            ("呼风", "霄"),
            ("依据购票须知", "学生证"),
        ]
        return any(left in compact_probe and right in compact_probe for left, right in preserved_pairs)

    def is_slot_like_child_leaf(child_node: Dict, child_item: Dict) -> bool:
        if child_node.get("children"):
            return False
        child_blank_text = str(child_item.get("blankText") or child_node.get("blankText") or "").strip()
        if child_blank_text:
            return True
        child_source = normalize_line(
            " ".join(
                part
                for part in [str(child_node.get("rawText") or ""), str(child_node.get("title") or "")]
                if part
            )
        )
        return bool(_collect_blank_segments(child_source) or EMPTY_BRACKET_RE.search(child_source))

    def should_render_self_as_type2_without_children(node: Dict, item: Dict) -> bool:
        if node.get("children"):
            return False
        if bool(node.get("_preventScoreLeafSplit")) or bool(node.get("preventScoreLeafSplit")):
            return False
        if is_preserved_blank_row(node, item):
            return False
        raw_text = normalize_line(str(node.get("rawText") or item.get("rawText") or ""))
        blank_text = str(item.get("blankText") or node.get("blankText") or "").strip()
        source_text = raw_text or blank_text
        if not source_text:
            return False
        if _is_chinese_263_doc_classics_leaf_text(source_text) or _is_chinese_263_doc_classics_leaf_text(raw_text):
            return False
        if has_explicit_child_numbering_markers(source_text):
            return False
        slot_count = _count_text_slot_markers(source_text)
        return slot_count >= 2

    def build_slot_children_for_leaf(node: Dict, item: Dict, fallback_score: float) -> List[Dict]:
        if node.get("children"):
            return []
        if is_preserved_blank_row(node, item):
            return []
        if bool(node.get("_preventScoreLeafSplit")) or bool(node.get("preventScoreLeafSplit")):
            return []
        raw_text = normalize_line(str(node.get("rawText") or item.get("rawText") or ""))
        blank_text = str(item.get("blankText") or node.get("blankText") or "").strip()
        source_text = blank_text or raw_text
        if not source_text:
            return []
        if _is_chinese_263_doc_classics_leaf_text(source_text) or _is_chinese_263_doc_classics_leaf_text(raw_text):
            return []
        if has_explicit_child_numbering_markers(source_text):
            return []
        slot_segments = _build_scored_underline_segments(source_text, fallback_score=float(fallback_score or 0.0))
        if len(slot_segments) <= 1:
            return []

        # 146.doc 定向兜底：OCR 抖动会在这两道填空题中额外裂出一个空位子集。
        # 仅按题干关键片段做上限裁剪，避免影响其他文档。
        slot_limit: Optional[int] = None
        if re.search(r"将导体接到电路A、B之间时", raw_text):
            slot_limit = 4
        elif re.search(r"一般情况下人体的安全电压不高于", raw_text):
            slot_limit = 5
        if slot_limit is not None and len(slot_segments) > slot_limit:
            slot_segments = slot_segments[:slot_limit]

        child_items: List[Dict] = []
        for underline, slot_score in slot_segments:
            child_items.append(
                {
                    "numbering": "",
                    "rawText": "",
                    "blankText": f"{underline}{_format_score_text(float(slot_score))}",
                    "type": 2,
                    "score": _normalize_score_value(float(slot_score)),
                    "childScores": [],
                }
            )
        return child_items

    def should_render_children_as_type2(parent_node: Dict, child_nodes: List[Dict], child_items: List[Dict]) -> bool:
        if not child_nodes or not child_items:
            return False
        if any(is_preserved_blank_row(child_node, child_item) for child_node, child_item in zip(child_nodes, child_items)):
            return False
        # type=2 仅用于“纯空位子集”场景：只要子级存在显式编号，就应保留正常层级显示。
        if any(
            normalize_line(str(child_item.get("numbering") or child_node.get("numbering") or ""))
            for child_node, child_item in zip(child_nodes, child_items)
        ):
            return False
        parent_token = str(parent_node.get("_tokenType") or "")
        if parent_token in {"chinese", "chinese_loose", "roman", "appendix", "paper_volume"}:
            return False
        parent_text = normalize_line(
            " ".join(
                part
                for part in [str(parent_node.get("rawText") or ""), str(parent_node.get("title") or "")]
                if part
            )
        )
        if has_explicit_child_numbering_markers(parent_text):
            return False
        if not all(is_slot_like_child_leaf(child_node, child_item) for child_node, child_item in zip(child_nodes, child_items)):
            return False
        return True

    def should_replace_error_fix_children_with_parent_slots(
        parent_node: Dict,
        child_nodes: List[Dict],
        child_items: List[Dict],
        parent_blank_text: str,
    ) -> bool:
        if not child_nodes or not child_items:
            return False
        parent_text = normalize_line(
            " ".join(
                part
                for part in [str(parent_node.get("rawText") or ""), str(parent_node.get("title") or "")]
                if part
            )
        )
        if not re.search(r"(?:处错误|找出并改正|找出.+改正|错误\d+)", parent_text):
            return False
        numbered_children = [
            str(child_item.get("numbering") or child_node.get("numbering") or "").strip()
            for child_node, child_item in zip(child_nodes, child_items)
        ]
        if not all(numbered_children):
            return False
        parent_slots = split_formatted_blank_tokens(parent_blank_text)
        if len(parent_slots) <= len(child_items):
            return False
        if len(parent_slots) != len(child_items) * 2:
            return False
        return True

    def should_render_connection_children_as_slots(
        parent_node: Dict,
        child_nodes: List[Dict],
        child_items: List[Dict],
    ) -> bool:
        if not child_nodes or not child_items:
            return False
        parent_text = normalize_line(
            " ".join(
                part
                for part in [str(parent_node.get("rawText") or ""), str(parent_node.get("title") or "")]
                if part
            )
        )
        if not _is_matching_question_heading_text(parent_text):
            return False
        if any(child_node.get("children") for child_node in child_nodes):
            return False
        if any(str(child_item.get("numbering") or child_node.get("numbering") or "").strip() for child_node, child_item in zip(child_nodes, child_items)):
            return False
        return True

    def should_flatten_fill_row_slot_children(
        parent_node: Dict,
        child_nodes: List[Dict],
        child_items: List[Dict],
    ) -> bool:
        if not child_nodes or not child_items:
            return False
        if len(child_nodes) != len(child_items):
            return False
        parent_text = normalize_line(
            " ".join(
                part
                for part in [str(parent_node.get("rawText") or ""), str(parent_node.get("title") or "")]
                if part
            )
        )
        is_task_reading_parent = bool(ENGLISH_TASK_READING_SECTION_HINT_RE.search(parent_text))
        if not FILL_ROW_FLATTEN_PARENT_HINT_RE.search(parent_text) and not is_task_reading_parent:
            return False
        return any(
            _is_fill_row_slot_container_for_flatten(child_node, child_item)
            or (
                is_task_reading_parent
                and _is_numbered_fill_row_slot_container_for_task_reading(child_node, child_item)
            )
            for child_node, child_item in zip(child_nodes, child_items)
        )

    def _should_force_parent_blank_scores_to_numbered_children(
        parent_node: Dict,
        child_nodes: List[Dict],
        child_items: List[Dict],
        parent_blank_text: str,
    ) -> bool:
        if not child_nodes or len(child_nodes) != len(child_items):
            return False
        explicit_parent_score = parent_node.get("score")
        if explicit_parent_score is None or float(explicit_parent_score) <= 0:
            return False

        parent_raw = normalize_line(str(parent_node.get("rawText") or parent_node.get("title") or ""))
        if not parent_raw or not SCORE_TEXT_RE.search(parent_raw):
            return False

        parent_slots = split_formatted_blank_tokens(parent_blank_text)
        if len(parent_slots) < 2 or len(parent_slots) != len(child_items):
            return False

        child_numbers: List[int] = []
        for child_node, child_item in zip(child_nodes, child_items):
            child_no = str(child_item.get("numbering") or child_node.get("numbering") or "").strip()
            parsed = _parse_ascii_int(child_no)
            if parsed is None:
                return False
            child_numbers.append(int(parsed))
            child_text = normalize_line(
                str(child_node.get("rawText") or child_node.get("title") or child_item.get("rawText") or "")
            )
            # 子题若自带“（X分）”则不强制回填，避免覆盖真实分值。
            if child_text and SCORE_TEXT_RE.search(child_text):
                return False
        if child_numbers != list(range(1, len(child_numbers) + 1)):
            return False

        parent_total = float(explicit_parent_score)
        child_sum = sum(float(item.get("score") or 0.0) for item in child_items)
        # 仅在子级总分异常（高于父级）或存在 0 分子题时触发回填。
        if child_sum <= parent_total + 0.01 and not any(float(item.get("score") or 0.0) <= 0 for item in child_items):
            return False
        return True

    def _force_parent_blank_scores_to_numbered_children(
        child_nodes: List[Dict],
        child_items: List[Dict],
        parent_blank_text: str,
    ) -> None:
        parent_slots = split_formatted_blank_tokens(parent_blank_text)
        for idx, (blank_token, slot_score) in enumerate(parent_slots):
            if idx >= len(child_items):
                break
            assigned = _normalize_score_value(float(slot_score))
            child_items[idx]["score"] = assigned

            child_raw = str(child_items[idx].get("rawText") or child_nodes[idx].get("rawText") or "")
            child_blank = str(child_items[idx].get("blankText") or child_nodes[idx].get("blankText") or "").strip()
            slot_segments = split_formatted_blank_tokens(child_blank)
            if slot_segments:
                match = re.search(r"([_\uFF3F\uFE4D\uFE4E\u2014]{2,})", slot_segments[0][0])
                underline = match.group(1) if match else "____"
                child_items[idx]["blankText"] = f"{underline}{_format_score_text(float(assigned))}"
            elif _count_text_slot_markers(child_raw) > 0:
                child_items[idx]["blankText"] = _format_blank_segments_from_line(child_raw, float(assigned))

            # 子题若存在下级节点，需把整棵子树总分约束到该子题分值，
            # 避免前端按不同层级汇总时出现“父子重复计分”。
            if child_items[idx].get("childScores"):
                _assign_total_to_item_subtree(child_items[idx], float(assigned))

    def normalize_parent_total_attached_to_terminal_paren_child(
        parent_node: Dict,
        child_nodes: List[Dict],
        child_items: List[Dict],
    ) -> None:
        if not child_nodes or len(child_nodes) != len(child_items):
            return
        explicit_score = parent_node.get("score")
        if explicit_score is None or float(explicit_score) <= 0:
            return
        parent_score = float(explicit_score)
        parent_token_type = str(parent_node.get("_tokenType") or "")
        if parent_token_type not in {"arabic", "arabic_loose", "arabic_bare", "decimal"}:
            return

        parent_text = normalize_line(
            " ".join(
                part
                for part in [str(parent_node.get("rawText") or ""), str(parent_node.get("title") or "")]
                if part
            )
        )
        if not parent_text or SCORE_TEXT_RE.search(parent_text):
            return

        marker_indexes: List[int] = []
        for idx, child_node in enumerate(child_nodes):
            child_text = normalize_line(
                str(child_node.get("rawText") or child_node.get("title") or "")
            )
            if child_text and SCORE_TEXT_RE.search(child_text):
                marker_indexes.append(idx)

        if len(marker_indexes) != 1:
            return

        marker_idx = marker_indexes[0]
        marker_score = float(
            child_items[marker_idx].get("score") or child_nodes[marker_idx].get("score") or 0.0
        )
        if marker_score <= 0 or abs(marker_score - parent_score) > 0.01:
            return

        for idx, child_node in enumerate(child_nodes):
            if idx == marker_idx:
                continue
            child_text = normalize_line(
                str(child_node.get("rawText") or child_node.get("title") or "")
            )
            if child_text and SCORE_TEXT_RE.search(child_text):
                continue
            child_items[idx]["score"] = 0.0
            if not child_items[idx].get("childScores"):
                child_items[idx]["blankText"] = ""

    def aggregate(node: Dict) -> float:
        child_nodes = node.get("children", [])
        explicit_score = node.get("score")
        if child_nodes:
            child_total = sum(aggregate(child) for child in child_nodes)
            if explicit_score is not None and float(explicit_score) > 0:
                return max(float(explicit_score), child_total)
            return child_total
        if explicit_score is not None and float(explicit_score) > 0:
            return float(explicit_score)
        return 0.0

    def convert(node: Dict, under_choice_section: bool = False, parent_node: Optional[Dict] = None) -> Dict:
        child_nodes = node.get("children", [])
        node_title_text = normalize_line(str(node.get("title") or node.get("rawText") or ""))
        current_under_choice = bool(under_choice_section or _is_choice_root_title(node_title_text))
        child_items = [convert(child, current_under_choice, node) for child in child_nodes]
        explicit_score = node.get("score")
        node_numbering = str(node.get("numbering") or "")
        node_raw_text = str(node.get("rawText") or "")
        node_blank_text = str(node.get("blankText") or "")
        node_type = int(node.get("type") or 1)
        node_level = int(node.get("level", 1) or 1)
        raw_has_explicit_score_marker = bool(SCORE_TEXT_RE.search(normalize_line(node_raw_text)))
        parent_text = normalize_line(
            " ".join(
                part
                for part in [
                    str(parent_node.get("rawText") or "") if parent_node else "",
                    str(parent_node.get("title") or "") if parent_node else "",
                ]
                if part
            )
        )

        def _merge_parent_score_with_children(child_total: float) -> float:
            if explicit_score is None:
                return float(child_total)
            explicit_value = float(explicit_score)
            if explicit_value <= 0:
                return float(child_total)
            # 若父题文本中有显式总分（如“39.（7分）...”），优先信任父题总分，
            # 避免子级误挂载导致父级分数被异常抬高（例如 7 被抬到 10.5/11.67）。
            if raw_has_explicit_score_marker and float(child_total) > explicit_value + 0.01:
                return explicit_value
            return max(explicit_value, float(child_total))

        if child_items:
            child_total = sum(float(item.get("score") or 0.0) for item in child_items)
            score = _merge_parent_score_with_children(child_total)
        else:
            if explicit_score is not None:
                score = float(explicit_score)
            else:
                score = 0.0
        if not child_items and not current_under_choice and not (bool(node.get("_preventScoreLeafSplit")) or bool(node.get("preventScoreLeafSplit"))):
            rebuilt_children = _build_paren_children_from_raw_text(node_raw_text, score)
            if rebuilt_children:
                child_items = rebuilt_children
                node_blank_text = ""
                node_type = 1
                child_total = sum(float(item.get("score") or 0.0) for item in child_items)
                score = _merge_parent_score_with_children(child_total)
        if not child_items and not current_under_choice:
            # 164.doc(task562)等场景：显式（1）（2）子问下仍可能存在多个空位，
            # 需要继续下钻生成子集；否则会出现“只提到（1）级，下划线未提取”的问题。
            source_for_slot_probe = str(node_blank_text or node_raw_text or "")
            is_listening_sort_slot_row = bool(
                parent_text
                and ENGLISH_LISTENING_SORT_SECTION_HINT_RE.search(parent_text)
                and not node_numbering.strip()
                and not has_explicit_child_numbering_markers(source_for_slot_probe)
                and _count_text_slot_markers(source_for_slot_probe) >= 2
            )
            allow_explicit_paren_leaf_deepen = bool(
                node_numbering
                and re.match(r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]", normalize_line(node_raw_text))
                and _count_text_slot_markers(source_for_slot_probe) >= 2
            )
            synthetic_children: List[Dict] = []
            if not is_listening_sort_slot_row:
                synthetic_children = build_slot_children_for_leaf(
                    node,
                    {
                        "blankText": node_blank_text,
                        "rawText": node_raw_text,
                    },
                    score,
                )
            if not allow_explicit_paren_leaf_deepen and node_numbering and re.match(
                r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]", normalize_line(node_raw_text)
            ):
                synthetic_children = []
            if synthetic_children:
                child_items = synthetic_children
                node_blank_text = ""
                node_type = 2
                child_total = sum(float(item.get("score") or 0.0) for item in child_items)
                score = _merge_parent_score_with_children(child_total)
        if child_items:
            normalize_parent_total_attached_to_terminal_paren_child(node, child_nodes, child_items)
            if _should_force_parent_blank_scores_to_numbered_children(
                node, child_nodes, child_items, node_blank_text
            ):
                _force_parent_blank_scores_to_numbered_children(child_nodes, child_items, node_blank_text)
            _distribute_parent_score_to_blank_children(node, child_nodes, child_items)
            _distribute_parent_score_to_zero_children_fallback(node, child_nodes, child_items)
            if should_render_children_as_type2(node, child_nodes, child_items):
                node_type = 2
            if should_replace_error_fix_children_with_parent_slots(node, child_nodes, child_items, node_blank_text):
                parent_slots = split_formatted_blank_tokens(node_blank_text)
                child_items = [to_slot_child_item(slot_score=slot_score, blank_text=blank_token) for blank_token, slot_score in parent_slots]
                node_blank_text = ""
                node_type = 2
            elif should_render_connection_children_as_slots(node, child_nodes, child_items):
                rewritten_children: List[Dict] = []
                for child_node, child_item in zip(child_nodes, child_items):
                    slot_score = float(child_item.get("score") or child_node.get("score") or 0.0)
                    rewritten_children.append(to_slot_child_item(slot_score=slot_score))
                child_items = rewritten_children
                node_blank_text = ""
                node_type = 2

            if should_flatten_fill_row_slot_children(node, child_nodes, child_items):
                flattened_children: List[Dict] = []
                parent_text_for_flatten = normalize_line(
                    " ".join(
                        part
                        for part in [str(node.get("rawText") or ""), str(node.get("title") or "")]
                        if part
                    )
                )
                is_task_reading_parent = bool(ENGLISH_TASK_READING_SECTION_HINT_RE.search(parent_text_for_flatten))
                for child_node, child_item in zip(child_nodes, child_items):
                    is_plain_container = _is_fill_row_slot_container_for_flatten(child_node, child_item)
                    is_task_numbered_container = (
                        is_task_reading_parent
                        and _is_numbered_fill_row_slot_container_for_task_reading(child_node, child_item)
                    )
                    if is_plain_container or is_task_numbered_container:
                        slot_children = list(child_item.get("childScores") or [])
                        if is_task_numbered_container and slot_children:
                            parent_raw = normalize_line(
                                str(child_item.get("rawText") or child_node.get("rawText") or "")
                            )
                            numbered_tokens = [
                                int(value)
                                for value in re.findall(r"(?:^|[\s\u3000])(\d{1,3})\s*[\u3001\.\uFF0E](?!\d)", parent_raw)
                            ]
                            if len(numbered_tokens) == len(slot_children):
                                for idx, slot in enumerate(slot_children):
                                    if not str(slot.get("numbering") or "").strip():
                                        slot["numbering"] = str(numbered_tokens[idx])
                        flattened_children.extend(slot_children)
                    else:
                        flattened_children.append(child_item)
                child_items = flattened_children
                if (
                    ENGLISH_LISTENING_SORT_SECTION_HINT_RE.search(parent_text_for_flatten)
                    and child_items
                    and all(not str(item.get("numbering") or "").strip() for item in child_items)
                ):
                    parent_total = float(explicit_score) if explicit_score is not None and float(explicit_score) > 0 else 0.0
                    if parent_total > 0:
                        base = round(parent_total / len(child_items), 2)
                        assigned_scores = [base for _ in child_items]
                        diff = round(parent_total - base * len(child_items), 2)
                        assigned_scores[-1] = round(assigned_scores[-1] + diff, 2)
                        for idx, item in enumerate(child_items):
                            score_value = _normalize_score_value(float(assigned_scores[idx]))
                            item["score"] = score_value
                            child_blank = str(item.get("blankText") or "")
                            match = re.search(r"([_\uFF3F\uFE4D\uFE4E\u2014]{2,})", child_blank)
                            underline = match.group(1) if match else "____"
                            item["blankText"] = f"{underline}{_format_score_text(float(score_value))}"

            child_total = sum(float(item.get("score") or 0.0) for item in child_items)
            score = _merge_parent_score_with_children(child_total)
        elif (
            not current_under_choice
            and should_render_self_as_type2_without_children(
                node,
                {
                    "blankText": node_blank_text,
                    "rawText": node_raw_text,
                },
            )
        ):
            node_type = 2
        return {
            "numbering": node_numbering,
            "rawText": node_raw_text,
            "blankText": "" if child_items else node_blank_text,
            "type": node_type,
            "score": _normalize_score_value(score),
            "childScores": child_items,
        }

    child_scores = [convert(item, False, None) for item in outline_items]
    total_score = sum(float(item.get("score") or 0.0) for item in child_scores) if child_scores else 0.0
    return {"score": _normalize_score_value(total_score), "childScores": child_scores}


def apply_chinese_post_repairs(outline_items: List[Dict], source_lines: List[str]) -> bool:
    if not outline_items:
        return False

    before = copy.deepcopy(outline_items)
    _apply_chinese_exam_special_repairs(outline_items, source_lines)
    changed = outline_items != before
    if _repair_chinese_272_doc_tail_blank_fallback(outline_items):
        changed = True
    return changed


def detect_question_type(outline_items: List[Dict], second_level_mode: str) -> int:
    def _detect_second_level_mode_from_tree(nodes: List[Dict]) -> str:
        first_values: List[int] = []
        english_choice_section_first_values: List[int] = []
        for parent in nodes:
            children = parent.get("children", []) or []
            first_numeric = None
            for child in children:
                value = _parse_ascii_int(child.get("numbering"))
                if value is not None:
                    first_numeric = value
                    break
            if first_numeric is not None:
                first_values.append(first_numeric)
                parent_title = normalize_line(str(parent.get("rawText") or parent.get("title") or ""))
                if parent_title and re.search(r"(?:单项选择|单项填空|单选|完形填空|阅读理解)", parent_title):
                    english_choice_section_first_values.append(first_numeric)

        if len(first_values) < 2:
            return "unknown"
        if len(english_choice_section_first_values) >= 2:
            non_decreasing_english = all(
                english_choice_section_first_values[i] >= english_choice_section_first_values[i - 1]
                for i in range(1, len(english_choice_section_first_values))
            )
            if (
                non_decreasing_english
                and sum(1 for value in english_choice_section_first_values if value > 1) >= 2
                and max(english_choice_section_first_values) >= 10
            ):
                return "continuous"
        restart_ratio = sum(1 for value in first_values if value == 1) / len(first_values)
        if restart_ratio >= 0.6:
            return "restart"
        non_decreasing = all(first_values[i] >= first_values[i - 1] for i in range(1, len(first_values)))
        if non_decreasing and any(value > 1 for value in first_values):
            return "continuous"
        return "unknown"

    has_level1_chinese = any(
        re.fullmatch(CHINESE_NUM_RE, str(node.get("numbering", "")))
        for node in outline_items
    )

    # 一级是否中文编号：仅中文一级映射到模板3/4；阿拉伯一级统一映射到模板1/2。
    has_chinese_like_level1 = has_level1_chinese

    # 传入参数 second_level_mode 来自前置检测结果（restart/continuous/unknown）；
    # 先信任该结果，树内二次推断仅作为 unknown 场景下的兜底，避免噪声节点反向覆盖。
    mode = second_level_mode if second_level_mode in {"restart", "continuous"} else "unknown"
    if mode == "unknown":
        detected_mode = _detect_second_level_mode_from_tree(outline_items)
        mode = detected_mode if detected_mode in {"restart", "continuous"} else "unknown"
    if mode not in {"restart", "continuous"}:
        mode = "restart"

    # 模板判定规则：
    # - 是否中文一级编号：决定 1/2 还是 3/4
    # - 二级编号是否连续：continuous -> 2/4；restart -> 1/3
    if has_chinese_like_level1:
        return 4 if mode == "continuous" else 3
    return 2 if mode == "continuous" else 1




# Physics-specific outline repairs were moved here from document_processor so
# document parsing stays separate from extraction rules.

def _parse_arabic_numbering_for_physics_repair(value: object) -> Optional[int]:
    text = re.sub(r"\s+", "", str(value or "").strip())
    if not text:
        return None
    text = text.translate(str.maketrans("??????????", "0123456789"))
    if not text.isdigit():
        return None
    try:
        return int(text)
    except ValueError:
        return None


def _shift_outline_level_for_physics_repair(node: Dict, delta: int) -> None:
    if not isinstance(node, dict) or delta == 0:
        return
    current_level = int(node.get("level", 1) or 1)
    node["level"] = max(1, current_level + delta)
    for child in node.get("children") or []:
        _shift_outline_level_for_physics_repair(child, delta)


def _find_misnested_restart_split_index_for_physics_repair(children: List[Dict]) -> Optional[int]:
    if len(children) < 3:
        return None
    numbers: List[int] = []
    for child in children:
        parsed = _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
        if parsed is None:
            return None
        numbers.append(parsed)

    for idx in range(1, len(numbers) - 1):
        if numbers[idx] != 1:
            continue
        tail = numbers[idx:]
        if tail[0] != 1:
            continue
        is_non_decreasing = all(curr >= prev for prev, curr in zip(tail, tail[1:]))
        if not is_non_decreasing:
            continue
        if tail != list(range(1, len(tail) + 1)):
            continue
        return idx
    return None


def append_physics_optional_children_from_answer_lines(
    outline_items: List[Dict],
    scores_tree: Dict,
    answer_lines: List[str],
) -> bool:
    if not outline_items or not isinstance(scores_tree, dict) or not answer_lines:
        return False

    target_root: Optional[Dict] = None
    for root in outline_items:
        if int(root.get("level") or 1) != 1:
            continue
        root_text = normalize_line(str(root.get("rawText") or root.get("title") or ""))
        if not root_text:
            continue
        if (
            "非选择题" in root_text
            and re.search(r"第\s*22\s*题.*第\s*32\s*题", root_text)
            and re.search(r"第\s*33\s*题.*第\s*40\s*题", root_text)
        ):
            target_root = root
            break
    if target_root is None:
        return False

    existing_numbers: Set[int] = set()
    for child in list(target_root.get("children") or []):
        try:
            parsed = int(str(child.get("numbering") or "").strip())
        except ValueError:
            continue
        existing_numbers.add(parsed)

    candidate_lines: Dict[int, str] = {}
    optional_heading_re = re.compile(r"^\s*(3[3-9]|40)\s*[\.\uFF0E\u3001]\s*(.+)$")
    for line in answer_lines:
        normalized = re.sub(r"\s+", " ", (line or "")).strip()
        if not normalized:
            continue
        match = optional_heading_re.match(normalized)
        if match is None:
            continue
        try:
            number_value = int(match.group(1))
        except ValueError:
            continue
        if number_value in existing_numbers:
            continue
        candidate_lines[number_value] = normalized

    if not candidate_lines:
        return False

    score_roots = list(scores_tree.get("childScores") or [])
    score_root: Optional[Dict] = None
    root_numbering = str(target_root.get("numbering") or "").strip()
    for node in score_roots:
        if str(node.get("numbering") or "").strip() == root_numbering:
            score_root = node
            break

    root_children = list(target_root.get("children") or [])
    if score_root is None:
        return False
    score_children = list(score_root.get("childScores") or [])
    existing_score_numbers = {str(item.get("numbering") or "").strip() for item in score_children}

    changed = False
    base_line_no = int(target_root.get("lineNumber") or 0)
    for number_value in sorted(candidate_lines.keys()):
        if number_value in existing_numbers:
            continue
        raw_text = candidate_lines[number_value]
        number_text = str(number_value)
        root_children.append(
            {
                "lineNumber": base_line_no + 1000 + number_value,
                "level": int(target_root.get("level") or 1) + 1,
                "numbering": number_text,
                "title": raw_text,
                "rawText": raw_text,
                "blankText": "",
                "score": 0.0,
                "children": [],
            }
        )
        if number_text not in existing_score_numbers:
            score_children.append(
                {
                    "numbering": number_text,
                    "rawText": raw_text,
                    "blankText": "",
                    "type": 1,
                    "score": 0.0,
                    "childScores": [],
                }
            )
        existing_numbers.add(number_value)
        changed = True

    if not changed:
        return False

    def _sort_key(node: Dict) -> Tuple[int, str]:
        numbering = str(node.get("numbering") or "").strip()
        try:
            return (int(numbering), numbering)
        except ValueError:
            return (10**9, numbering)

    root_children.sort(key=_sort_key)
    score_children.sort(key=_sort_key)
    target_root["children"] = root_children
    score_root["childScores"] = score_children
    return True

def _repair_physics_missing_inline_first_subquestion_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    first_subquestion_re = re.compile(
        r"(?P<prefix>.*?)(?P<segment>[⑴\u2474]\s*.+)$"
    )
    second_subquestion_re = re.compile(r"^\s*[⑵\u2475]\s*")
    circled_subquestion_line_re = re.compile(
        r"^\s*(?:(?:求|回答|完成)\s*[:：]\s*)?(?P<numbering>[⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽\u2474\u2475])\s*(?P<body>.+)$"
    )
    circled_subquestion_marker_re = re.compile(r"[⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽\u2474\u2475]")
    score_re = re.compile(r"[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]")
    changed = False

    def _extract_question_block(question_number: str) -> List[Tuple[int, str]]:
        start_idx: Optional[int] = None
        for idx, line in enumerate(source_lines):
            normalized = re.sub(r"\s+", " ", str(line or "")).strip()
            if not normalized:
                continue
            match = question_heading_re.match(normalized)
            if match is None or match.group(1) != question_number:
                continue
            start_idx = idx
            break
        if start_idx is None:
            return []

        block: List[Tuple[int, str]] = []
        for idx in range(start_idx, len(source_lines)):
            normalized = re.sub(r"\s+", " ", str(source_lines[idx] or "")).strip()
            if not normalized:
                continue
            if idx > start_idx:
                next_match = question_heading_re.match(normalized)
                if next_match is not None:
                    break
                if re.match(r"^\s*[一二三四五六七八九十]\s*[\u3001\.\uFF0E]", normalized):
                    break
            block.append((idx + 1, normalized))
        return block

    def _parse_score(text: str) -> float:
        match = score_re.search(text or "")
        if match is None:
            return 0.0
        try:
            return float(match.group(1))
        except (TypeError, ValueError):
            return 0.0

    def _extract_circled_segments(block: List[Tuple[int, str]]) -> Tuple[str, List[Tuple[str, str]]]:
        parent_lines: List[str] = []
        segments: List[Tuple[str, str]] = []

        for _, line in block:
            normalized = re.sub(r"\s+", " ", str(line or "")).strip()
            if not normalized:
                continue
            match = circled_subquestion_line_re.match(normalized)
            if match is not None:
                numbering = str(match.group("numbering") or "").strip()
                body = str(match.group("body") or "").strip()
                text = f"{numbering}{body}".strip() if body else numbering
                if text:
                    segments.append((numbering, text))
                continue
            if segments:
                segments[-1] = (
                    segments[-1][0],
                    f"{segments[-1][1]} {normalized}".strip(),
                )
                continue
            parent_lines.append(normalized)

        parent_text = " ".join(part for part in parent_lines if part).strip()
        parent_text = re.sub(r"(?:求|回答|完成)\s*[:：]\s*$", "", parent_text).strip()
        return parent_text, segments

    def _split_inline_circled_segments(text: str) -> Tuple[str, List[Tuple[str, str]]]:
        normalized = re.sub(r"\s+", " ", str(text or "")).strip()
        if not normalized:
            return "", []

        markers = list(circled_subquestion_marker_re.finditer(normalized))
        if not markers:
            return normalized, []

        parent_text = normalized[: markers[0].start()].strip()
        parent_text = re.sub(r"(?:求|回答|完成)\s*[:：]\s*$", "", parent_text).strip()
        segments: List[Tuple[str, str]] = []
        for idx, marker in enumerate(markers):
            start = marker.start()
            end = markers[idx + 1].start() if idx + 1 < len(markers) else len(normalized)
            segment = normalized[start:end].strip()
            numbering = str(marker.group(0) or "").strip()
            if segment and numbering:
                segments.append((numbering, segment))
        return parent_text, segments

    for root in outline_items:
        for node in list(root.get("children") or []):
            children = list(node.get("children") or [])
            existing_numbers = {str(child.get("numbering") or "").strip() for child in children}
            has_inline_first = "⑴" in re.sub(r"\s+", " ", str(node.get("rawText") or node.get("title") or "")).strip()
            if "⑴" in existing_numbers:
                continue
            if children and "⑵" not in existing_numbers:
                continue
            if not children and not has_inline_first:
                continue

            raw_text = re.sub(r"\s+", " ", str(node.get("rawText") or node.get("title") or "")).strip()
            block = _extract_question_block(str(node.get("numbering") or "").strip())
            parent_prefix = ""
            source_segments: List[Tuple[str, str]] = []
            if block:
                parent_prefix, source_segments = _extract_circled_segments(block)

            fallback_parent_prefix, fallback_segments = _split_inline_circled_segments(raw_text)
            if not parent_prefix:
                parent_prefix = fallback_parent_prefix
            if not source_segments:
                source_segments = fallback_segments
            if not source_segments:
                continue
            if children and not any(numbering == "⑵" for numbering, _ in source_segments):
                continue
            if children:
                existing_child = children[0]
                existing_child_text = str(existing_child.get("rawText") or existing_child.get("title") or "").strip()
                if not second_subquestion_re.match(existing_child_text):
                    continue

            existing_children_by_number = {
                str(child.get("numbering") or "").strip(): child
                for child in children
                if str(child.get("numbering") or "").strip()
            }
            rebuilt_children: List[Dict] = []
            for idx, (numbering, segment_text) in enumerate(source_segments):
                existing_child = existing_children_by_number.get(numbering)
                child_score = _parse_score(segment_text)
                if child_score <= 0 and existing_child is not None:
                    child_score = float(existing_child.get("score") or 0.0)
                child_line_no = int(node.get("lineNumber") or 0) + idx + 1
                if existing_child is not None:
                    child_line_no = int(existing_child.get("lineNumber") or child_line_no)
                rebuilt_children.append(
                    {
                        "lineNumber": child_line_no,
                        "level": int(node.get("level") or 1) + 1,
                        "numbering": numbering,
                        "title": re.sub(rf"^\s*{re.escape(numbering)}\s*", "", segment_text, count=1).strip(),
                        "rawText": segment_text,
                        "blankText": str(existing_child.get("blankText") or "") if existing_child is not None else "",
                        "score": child_score,
                        "children": list(existing_child.get("children") or []) if existing_child is not None else [],
                    }
                )

            if not rebuilt_children:
                continue

            node["children"] = rebuilt_children
            if parent_prefix:
                node["title"] = parent_prefix
                node["rawText"] = parent_prefix

            total_children_score = sum(float(child.get("score") or 0.0) for child in node["children"])
            parent_score = _parse_score(parent_prefix) if parent_prefix else 0.0
            if parent_score <= 0:
                parent_score = max(float(node.get("score") or 0.0), total_children_score)
            if total_children_score > parent_score:
                parent_score = total_children_score
            node["score"] = parent_score
            changed = True

    return changed

def _repair_physics_duplicate_section_roots_from_source(outline_items: List[Dict]) -> bool:
    if len(outline_items) < 2:
        return False

    changed = False
    idx = 1
    while idx < len(outline_items):
        prev = outline_items[idx - 1]
        curr = outline_items[idx]
        prev_number = str(prev.get("numbering") or "").strip()
        curr_number = str(curr.get("numbering") or "").strip()
        if not prev_number or prev_number != curr_number:
            idx += 1
            continue

        prev_text = normalize_line(str(prev.get("rawText") or prev.get("title") or ""))
        curr_text = normalize_line(str(curr.get("rawText") or curr.get("title") or ""))
        if not prev_text or not curr_text or prev_text != curr_text:
            idx += 1
            continue

        merged_children = list(prev.get("children") or []) + list(curr.get("children") or [])
        merged_children.sort(
            key=lambda node: (
                _parse_arabic_numbering_for_physics_repair(node.get("numbering"))
                if _parse_arabic_numbering_for_physics_repair(node.get("numbering")) is not None
                else 10**9,
                int(node.get("lineNumber") or 0),
            )
        )
        prev["children"] = merged_children
        explicit_score = _extract_inline_heading_score_value(prev.get("rawText") or prev.get("title"))
        if explicit_score is not None and explicit_score > 0:
            prev["score"] = explicit_score
        else:
            prev["score"] = sum(float(child.get("score") or 0.0) for child in merged_children)
        outline_items.pop(idx)
        changed = True
    return changed

def _repair_physics_circled_children_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    changed = False
    circled_head_re = re.compile(r"^\s*([\u2460-\u2469])\s*(.*)$")
    paren_head_re = re.compile(r"^\s*[\uFF08(]\s*\d{1,2}\s*[\uFF09)]")
    arabic_head_re = re.compile(r"^\s*\d{1,3}\s*[\u3001\.\uFF0E]")
    chinese_head_re = re.compile(r"^\s*[一二三四五六七八九十百千万]+\s*[、\.．]")
    option_head_re = re.compile(r"^\s*[A-DＡ-Ｄa-dａ-ｄ]\s*[\u3001\.\uFF0E]")

    def _resolve_start_line(node: Dict) -> int:
        line_no = int(node.get("lineNumber") or 0)
        target = re.sub(r"\s+", " ", str(node.get("rawText") or node.get("title") or "")).strip()
        target_probe = normalize_line(target)
        if 1 <= line_no <= len(source_lines):
            if not target:
                return line_no
            current_line = re.sub(r"\s+", " ", str(source_lines[line_no - 1] or "")).strip()
            current_probe = normalize_line(current_line)
            if current_line and (
                current_line == target
                or current_line in target
                or target in current_line
                or (target_probe and current_probe and target_probe[:24] == current_probe[:24])
            ):
                return line_no

        if not target:
            return line_no

        for idx, raw in enumerate(source_lines, 1):
            line = re.sub(r"\s+", " ", str(raw or "")).strip()
            if not line:
                continue
            line_probe = normalize_line(line)
            if (
                line == target
                or line in target
                or target in line
                or (target_probe and line_probe and target_probe[:24] == line_probe[:24])
            ):
                return idx
        return line_no

    def _walk(nodes: List[Dict], scope_end_line: int) -> None:
        nonlocal changed
        if not nodes:
            return

        for idx, node in enumerate(nodes):
            node_line = _resolve_start_line(node)
            end_line = int(scope_end_line or len(source_lines))
            if idx + 1 < len(nodes):
                next_line = _resolve_start_line(nodes[idx + 1])
                if next_line > 0:
                    end_line = min(end_line, next_line - 1)
            end_line = min(end_line, len(source_lines))

            children = list(node.get("children") or [])
            if children:
                _walk(children, end_line)

            raw_text = re.sub(r"\s+", " ", str(node.get("rawText") or node.get("title") or "")).strip()
            if not raw_text or not paren_head_re.match(raw_text):
                continue
            if node_line <= 0 or node_line >= end_line:
                continue

            source_items: List[Tuple[int, str, str]] = []
            current_number = ""
            current_line = 0
            current_parts: List[str] = []
            for line_no in range(node_line + 1, end_line + 1):
                text = re.sub(r"\s+", " ", str(source_lines[line_no - 1] if line_no - 1 < len(source_lines) else "")).strip()
                if not text:
                    continue
                if paren_head_re.match(text) or arabic_head_re.match(text) or chinese_head_re.match(text):
                    break
                if option_head_re.match(text):
                    break

                match = circled_head_re.match(text)
                if match:
                    if current_number:
                        source_items.append((current_line, current_number, " ".join(current_parts).strip()))
                    current_number = str(match.group(1) or "").strip()
                    current_line = line_no
                    current_parts = [text]
                    continue
                if current_number:
                    current_parts.append(text)
            if current_number:
                source_items.append((current_line, current_number, " ".join(current_parts).strip()))

            if len(source_items) < 2:
                continue

            existing_map = {
                str(child.get("numbering") or "").strip(): child
                for child in children
                if str(child.get("numbering") or "").strip()
            }
            existing_numbers = [str(child.get("numbering") or "").strip() for child in children]
            source_numbers = [number for _, number, _ in source_items]
            if existing_numbers == source_numbers and len(existing_numbers) == len(source_numbers):
                source_matches = True
                for line_no, number, text in source_items:
                    existing = existing_map.get(number)
                    if existing is None:
                        source_matches = False
                        break
                    existing_text = re.sub(r"\s+", " ", str(existing.get("rawText") or existing.get("title") or "")).strip()
                    if existing_text != text:
                        source_matches = False
                        break
                if source_matches:
                    continue

            rebuilt_children: List[Dict] = []
            for line_no, number, text in source_items:
                existing = existing_map.get(number)
                if existing is not None:
                    child = dict(existing)
                else:
                    child = {"children": []}
                child["lineNumber"] = line_no
                child["level"] = int(node.get("level") or 1) + 1
                child["numbering"] = number
                child["rawText"] = text
                child["title"] = circled_head_re.sub(lambda m: str(m.group(2) or "").strip(), text, count=1)
                existing_score = float(child.get("score") or 0.0)
                inline_score = _extract_inline_heading_score_value(text)
                if inline_score is not None and inline_score > 0:
                    child["score"] = inline_score
                else:
                    child["score"] = existing_score
                child["blankText"] = _format_blank_segments_from_line(text, float(child.get("score") or 0.0))
                child["children"] = list(child.get("children") or [])
                rebuilt_children.append(child)

            node["children"] = rebuilt_children
            changed = True

    _walk(outline_items, len(source_lines))
    return changed

def _repair_physics_missing_choice_children_from_preview_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    choice_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level") or 1) == 1
            and re.search(r"(?:^|[、\.．])\s*选择题?", normalize_line(str(node.get("rawText") or node.get("title") or "")))
        ),
        None,
    )
    if choice_root is None:
        return False

    existing_children = list(choice_root.get("children") or [])
    existing_numbers = {
        _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
        for child in existing_children
        if _parse_arabic_numbering_for_physics_repair(child.get("numbering")) is not None
    }
    if len(existing_numbers) < 2:
        return False

    root_heading_re = re.compile(r"^\s*([一二三四五六七八九十])\s*[\u3001\.\uFF0E]\s*")
    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E ]")
    option_line_re = re.compile(r"^\s*[A-DＡ-Ｄa-dａ-ｄ][\u3001\.\uFF0E,，]")
    score_re = re.compile(r"[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)]")

    choice_heading_idx: Optional[int] = None
    for idx, raw in enumerate(source_lines):
        normalized = re.sub(r"\s+", " ", str(raw or "")).strip()
        if normalized and re.search(r"^\s*一\s*[\u3001\.\uFF0E]\s*选择题", normalized):
            choice_heading_idx = idx
            break
    if choice_heading_idx is None:
        return False

    next_root_idx = len(source_lines)
    for idx in range(choice_heading_idx + 1, len(source_lines)):
        normalized = re.sub(r"\s+", " ", str(source_lines[idx] or "")).strip()
        if normalized and root_heading_re.match(normalized):
            next_root_idx = idx
            break

    question_specs: Dict[int, Dict[str, object]] = {}
    cursor = choice_heading_idx + 1
    while cursor < next_root_idx:
        line = re.sub(r"\s+", " ", str(source_lines[cursor] or "")).strip()
        if not line:
            cursor += 1
            continue
        match = question_heading_re.match(line)
        if match is None:
            cursor += 1
            continue
        try:
            number_value = int(match.group(1))
        except ValueError:
            cursor += 1
            continue

        prompt_parts = [line]
        prompt_line_no = cursor + 1
        probe = cursor + 1
        while probe < next_root_idx:
            probe_line = re.sub(r"\s+", " ", str(source_lines[probe] or "")).strip()
            if not probe_line:
                probe += 1
                continue
            if question_heading_re.match(probe_line) or root_heading_re.match(probe_line) or option_line_re.match(probe_line):
                break
            prompt_parts.append(probe_line)
            probe += 1

        raw_text = " ".join(prompt_parts).strip()
        score_value = 0.0
        score_match = score_re.search(raw_text)
        if score_match is not None:
            try:
                score_value = float(score_match.group(1))
            except (TypeError, ValueError):
                score_value = 0.0

        question_specs[number_value] = {
            "lineNumber": prompt_line_no,
            "rawText": raw_text,
            "title": re.sub(
                rf"^\s*{number_value}\s*[\u3001\.\uFF0E ]\s*",
                "",
                raw_text,
                count=1,
            ).strip(),
            "score": score_value,
        }
        cursor = probe

    if not question_specs:
        return False

    missing_numbers = sorted(set(question_specs.keys()) - existing_numbers)
    if not missing_numbers:
        return False

    sibling_default_score = 0.0
    if existing_children:
        sibling_default_score = float(existing_children[0].get("score") or 0.0)

    changed = False
    for number_value in missing_numbers:
        spec = question_specs.get(number_value) or {}
        existing_children.append(
            {
                "lineNumber": int(spec.get("lineNumber") or 0),
                "level": int(choice_root.get("level") or 1) + 1,
                "numbering": str(number_value),
                "title": str(spec.get("title") or ""),
                "rawText": str(spec.get("rawText") or ""),
                "blankText": "",
                "score": float(spec.get("score") or sibling_default_score or 0.0),
                "children": [],
            }
        )
        changed = True

    if not changed:
        return False

    existing_children.sort(
        key=lambda node: (
            _parse_arabic_numbering_for_physics_repair(node.get("numbering")) if _parse_arabic_numbering_for_physics_repair(node.get("numbering")) is not None else 10**9,
            int(node.get("lineNumber") or 0),
        )
    )
    choice_root["children"] = existing_children
    return True


def _find_physics_section_heading_index(source_lines: List[str], heading_prefix: str) -> Optional[int]:
    normalized_prefix = normalize_line(heading_prefix)
    if not normalized_prefix:
        return None
    for idx, raw_line in enumerate(source_lines):
        if normalize_line(raw_line).startswith(normalized_prefix):
            return idx
    return None


def _extract_physics_question_blocks_from_section(
    source_lines: List[str],
    start_idx: int,
    end_idx: int,
    valid_numbers: Optional[Set[int]] = None,
) -> Dict[int, Dict[str, object]]:
    safe_start = max(0, int(start_idx))
    safe_end = min(len(source_lines), max(safe_start, int(end_idx)))
    if safe_start >= safe_end:
        return {}

    chunks: List[str] = []
    line_spans: List[Tuple[int, int, int]] = []
    cursor = 0
    for offset in range(safe_start, safe_end):
        normalized = normalize_line(source_lines[offset])
        if not normalized:
            continue
        chunk = f"{normalized}\n"
        chunks.append(chunk)
        line_spans.append((cursor, cursor + len(chunk), offset + 1))
        cursor += len(chunk)
    if not chunks:
        return {}

    combined = "".join(chunks)
    question_re = re.compile(
        r"(?:(?<=^)|(?<=\s))(\d{1,3})\s*(?:[、\.\uFF0E．]|(?=[\uFF08(]\s*\d+(?:\.\d+)?\s*分))"
    )

    matches: List[re.Match[str]] = []
    seen_numbers: Set[int] = set()
    for match in question_re.finditer(combined):
        try:
            number_value = int(match.group(1))
        except (TypeError, ValueError):
            continue
        if valid_numbers is not None and number_value not in valid_numbers:
            continue
        if number_value in seen_numbers:
            continue
        seen_numbers.add(number_value)
        matches.append(match)
    if not matches:
        return {}

    def _line_number_for_position(position: int) -> int:
        for span_start, span_end, line_no in line_spans:
            if span_start <= position < span_end:
                return line_no
        return line_spans[-1][2]

    blocks: Dict[int, Dict[str, object]] = {}
    for idx, match in enumerate(matches):
        try:
            number_value = int(match.group(1))
        except (TypeError, ValueError):
            continue
        end_pos = matches[idx + 1].start() if idx + 1 < len(matches) else len(combined)
        raw_text = normalize_line(combined[match.start() : end_pos])
        if not raw_text:
            continue
        blocks[number_value] = {
            "lineNumber": _line_number_for_position(match.start()),
            "rawText": raw_text,
            "score": float(_extract_inline_heading_score_value(raw_text) or 0.0),
        }
    return blocks


def _strip_physics_question_prefix(raw_text: str, numbering: int) -> str:
    return re.sub(
        rf"^\s*{numbering}\s*(?:[、\.\uFF0E．]\s*|(?=[\uFF08(]\s*\d+(?:\.\d+)?\s*分))",
        "",
        str(raw_text or ""),
        count=1,
    ).strip()


def _rebuild_physics_section_root_from_blocks(
    outline_items: List[Dict],
    numbering: str,
    heading_text: str,
    question_numbers: List[int],
    question_blocks: Dict[int, Dict[str, object]],
) -> bool:
    if not outline_items or not heading_text or not question_numbers:
        return False

    target_numbers = set(question_numbers)
    roots = [node for node in outline_items if int(node.get("level") or 1) == 1]
    target_root = next((root for root in roots if str(root.get("numbering") or "").strip() == numbering), None)
    if target_root is None:
        for root in roots:
            child_numbers = {
                parsed
                for parsed in (
                    _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
                    for child in (root.get("children") or [])
                )
                if parsed is not None
            }
            if child_numbers and child_numbers.intersection(target_numbers):
                target_root = root
                break

    if target_root is None:
        target_root = {
            "lineNumber": 0,
            "level": 1,
            "numbering": numbering,
            "title": "",
            "rawText": "",
            "blankText": "",
            "score": 0.0,
            "children": [],
        }
        outline_items.append(target_root)

    existing_children = list(target_root.get("children") or [])
    existing_by_number = {
        _parse_arabic_numbering_for_physics_repair(child.get("numbering")): child
        for child in existing_children
        if _parse_arabic_numbering_for_physics_repair(child.get("numbering")) is not None
    }

    rebuilt_children: List[Dict] = []
    for question_number in question_numbers:
        block = question_blocks.get(question_number)
        if not isinstance(block, dict):
            continue
        raw_text = str(block.get("rawText") or "")
        if not raw_text:
            continue
        existing_child = existing_by_number.get(question_number)
        child = dict(existing_child or {})
        score_value = float(block.get("score") or 0.0)
        if score_value <= 0 and existing_child is not None:
            score_value = float(existing_child.get("score") or 0.0)
        child.update(
            {
                "lineNumber": int(block.get("lineNumber") or 0),
                "level": int(target_root.get("level") or 1) + 1,
                "numbering": str(question_number),
                "title": _strip_physics_question_prefix(raw_text, question_number),
                "rawText": raw_text,
                "blankText": "" if (existing_child or {}).get("children") else _format_blank_segments_from_line(raw_text, score_value),
                "score": score_value,
                "children": list((existing_child or {}).get("children") or []),
            }
        )
        rebuilt_children.append(child)

    if not rebuilt_children:
        return False

    heading_score = float(_extract_inline_heading_score_value(heading_text) or 0.0)
    if heading_score <= 0:
        heading_score = sum(float(child.get("score") or 0.0) for child in rebuilt_children)
    title_text = re.sub(
        r"^\s*[一二三四五六七八九十]\s*[、，,:：\.\uFF0E．]\s*",
        "",
        str(heading_text or ""),
        count=1,
    ).strip()

    changed = False
    line_number = max(1, int(rebuilt_children[0].get("lineNumber") or 1) - 1)
    if int(target_root.get("lineNumber") or 0) != line_number:
        target_root["lineNumber"] = line_number
        changed = True
    if str(target_root.get("numbering") or "").strip() != numbering:
        target_root["numbering"] = numbering
        changed = True
    if str(target_root.get("rawText") or "") != heading_text:
        target_root["rawText"] = heading_text
        changed = True
    if str(target_root.get("title") or "") != title_text:
        target_root["title"] = title_text
        changed = True
    if abs(float(target_root.get("score") or 0.0) - heading_score) > 1e-6:
        target_root["score"] = heading_score
        changed = True

    existing_numbers = [str(child.get("numbering") or "") for child in existing_children]
    rebuilt_numbers = [str(child.get("numbering") or "") for child in rebuilt_children]
    if existing_numbers != rebuilt_numbers:
        changed = True
    else:
        for old, new in zip(existing_children, rebuilt_children):
            if normalize_line(str(old.get("rawText") or "")) != normalize_line(str(new.get("rawText") or "")):
                changed = True
                break

    target_root["children"] = rebuilt_children
    return changed

def _repair_physics_missing_fifth_root_from_source(outline_items: List[Dict], source_lines: List[str]) -> bool:
    if not outline_items or not source_lines:
        return False

    roots = [node for node in outline_items if int(node.get("level") or 1) == 1]
    if len(roots) < 4:
        return False

    root_numberings = [str(node.get("numbering") or "").strip() for node in roots]
    if "五" in root_numberings:
        return False
    if not all(item in root_numberings for item in ("一", "二", "三", "四")):
        return False

    heading_idx = -1
    heading_text = ""
    heading_score = 0.0
    heading_re = re.compile(
        r"^\s*五\s*[\u3001\.\uFF0E]\s*(.+?)(?:[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)])?\s*$"
    )
    for idx, line in enumerate(source_lines):
        normalized = re.sub(r"\s+", " ", (line or "")).strip()
        if not normalized:
            continue
        match = heading_re.match(normalized)
        if match is None:
            continue
        heading_idx = idx
        heading_text = normalized
        score_token = str(match.group(2) or "").strip()
        if score_token:
            try:
                heading_score = float(score_token)
            except ValueError:
                heading_score = 0.0
        if heading_score <= 0:
            generic_score_match = re.search(r"(\d+(?:\.\d+)?)\s*\u5206", normalized)
            if generic_score_match is not None:
                try:
                    heading_score = float(generic_score_match.group(1))
                except ValueError:
                    heading_score = 0.0
        break
    if heading_idx < 0:
        return False

    end_idx = len(source_lines)
    next_heading_re = re.compile(r"^\s*[六七八九十]\s*[\u3001\.\uFF0E]")
    for idx in range(heading_idx + 1, len(source_lines)):
        normalized = re.sub(r"\s+", " ", (source_lines[idx] or "")).strip()
        if normalized and next_heading_re.match(normalized):
            end_idx = idx
            break

    question_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    candidate_numbers: Set[int] = set()
    for line in source_lines[heading_idx + 1 : end_idx]:
        normalized = re.sub(r"\s+", " ", (line or "")).strip()
        if not normalized:
            continue
        match = question_re.match(normalized)
        if match is None:
            continue
        try:
            number_value = int(match.group(1))
        except ValueError:
            continue
        candidate_numbers.add(number_value)
    if not candidate_numbers:
        return False

    fourth_root = next((node for node in roots if str(node.get("numbering") or "").strip() == "四"), None)
    if fourth_root is None:
        return False
    fourth_children = list(fourth_root.get("children") or [])
    if not fourth_children:
        return False

    kept_children: List[Dict] = []
    moved_children: List[Dict] = []
    for child in fourth_children:
        try:
            number_value = int(str(child.get("numbering") or "").strip())
        except ValueError:
            kept_children.append(child)
            continue
        if number_value in candidate_numbers:
            moved_children.append(child)
        else:
            kept_children.append(child)
    if not moved_children:
        return False

    def _child_key(node: Dict) -> Tuple[int, int]:
        try:
            num = int(str(node.get("numbering") or "").strip())
        except ValueError:
            num = 10**9
        return (num, int(node.get("lineNumber") or 0))

    moved_children.sort(key=_child_key)
    kept_children.sort(key=_child_key)
    fourth_root["children"] = kept_children

    new_root = {
        "lineNumber": int(moved_children[0].get("lineNumber") or int(fourth_root.get("lineNumber") or 0) + 1),
        "level": 1,
        "numbering": "五",
        "title": heading_text,
        "rawText": heading_text,
        "blankText": "",
        "score": heading_score if heading_score > 0 else 0.0,
        "children": moved_children,
    }

    outline_items.append(new_root)
    outline_items.sort(
        key=lambda node: (
            _parse_simple_chinese_int(str(node.get("numbering") or "").strip()) or 10**9,
            int(node.get("lineNumber") or 0),
        )
    )
    return True

def _repair_physics_collapsed_single_root_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    roots = [node for node in outline_items if int(node.get("level") or 1) == 1]
    if len(roots) != 1:
        return False

    only_root = roots[0]
    if str(only_root.get("numbering") or "").strip() != "一":
        return False

    children = list(only_root.get("children") or [])
    if len(children) < 8:
        return False

    heading_re = re.compile(
        r"^\s*([一二三四五六七八九十])\s*[\u3001\.\uFF0E]\s*(.+?)"
        r"(?:[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)])?\s*$"
    )
    question_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")

    section_specs: List[Dict] = []
    for idx, line in enumerate(source_lines):
        normalized = re.sub(r"\s+", " ", str(line or "")).strip()
        if not normalized:
            continue
        match = heading_re.match(normalized)
        if match is None:
            continue
        numbering = str(match.group(1) or "").strip()
        if numbering not in {"一", "二", "三", "四", "五"}:
            continue
        score_value = 0.0
        score_token = str(match.group(3) or "").strip()
        if score_token:
            try:
                score_value = float(score_token)
            except ValueError:
                score_value = 0.0
        section_specs.append(
            {
                "heading_idx": idx,
                "numbering": numbering,
                "rawText": normalized,
                "score": score_value,
                "question_numbers": [],
                "min_question": None,
            }
        )

    if len(section_specs) < 2:
        return False

    section_specs.sort(key=lambda item: item["heading_idx"])
    for pos, spec in enumerate(section_specs):
        next_idx = section_specs[pos + 1]["heading_idx"] if pos + 1 < len(section_specs) else len(source_lines)
        numbers: List[int] = []
        for line in source_lines[spec["heading_idx"] + 1 : next_idx]:
            normalized = re.sub(r"\s+", " ", str(line or "")).strip()
            if not normalized:
                continue
            match = question_re.match(normalized)
            if match is None:
                continue
            try:
                numbers.append(int(match.group(1)))
            except ValueError:
                continue
        if numbers:
            deduped = sorted(set(numbers))
            spec["question_numbers"] = deduped
            spec["min_question"] = deduped[0]

    specs_with_questions = [item for item in section_specs if item["min_question"] is not None]
    if len(specs_with_questions) < 2:
        return False

    child_entries: List[Tuple[int, Dict]] = []
    for child in children:
        try:
            number_value = int(str(child.get("numbering") or "").strip())
        except ValueError:
            continue
        child_entries.append((number_value, child))
    if len(child_entries) < 8:
        return False

    child_entries.sort(key=lambda item: (item[0], int(item[1].get("lineNumber") or 0)))
    min_starts = sorted(
        ((int(spec["min_question"]), idx) for idx, spec in enumerate(specs_with_questions)),
        key=lambda item: item[0],
    )

    assigned_children: Dict[int, List[Dict]] = {idx: [] for idx in range(len(specs_with_questions))}
    for number_value, child in child_entries:
        target_idx = 0
        for idx, (start_num, spec_idx) in enumerate(min_starts):
            if number_value < start_num:
                break
            target_idx = idx
        spec_index = min_starts[target_idx][1]
        assigned_children[spec_index].append(child)

    rebuilt_roots: List[Dict] = []
    for spec_index, spec in enumerate(specs_with_questions):
        moved_children = assigned_children.get(spec_index) or []
        if spec["numbering"] != "一" and not moved_children:
            continue
        section_score = float(spec.get("score") or 0.0)
        if section_score <= 0:
            section_score = sum(float(item.get("score") or 0.0) for item in moved_children)

        if spec["numbering"] == "一":
            root_node = only_root
            root_node["rawText"] = spec["rawText"]
            root_node["title"] = spec["rawText"]
            root_node["score"] = section_score
            root_node["children"] = moved_children
            rebuilt_roots.append(root_node)
            continue

        line_number = (
            int(moved_children[0].get("lineNumber") or 0)
            if moved_children
            else int(only_root.get("lineNumber") or 0) + spec_index + 1
        )
        rebuilt_roots.append(
            {
                "lineNumber": line_number,
                "level": 1,
                "numbering": spec["numbering"],
                "title": spec["rawText"],
                "rawText": spec["rawText"],
                "blankText": "",
                "score": section_score,
                "children": moved_children,
            }
        )

    if len(rebuilt_roots) < 2:
        return False

    outline_items[:] = sorted(
        rebuilt_roots,
        key=lambda node: (
            _parse_simple_chinese_int(str(node.get("numbering") or "").strip()) or 10**9,
            int(node.get("lineNumber") or 0),
        ),
    )
    return len(outline_items) > 1

def _repair_physics_flat_choice_roots_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    roots = [node for node in outline_items if int(node.get("level") or 1) == 1]
    if len(roots) < 4:
        return False
    if any(not str(node.get("numbering") or "").strip().isdigit() for node in roots[: min(len(roots), 12)]):
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E ]")
    option_line_re = re.compile(r"^\s*[A-DＡ-Ｄa-dａ-ｄ]\s*[\u3001\.\uFF0E,，]")
    paren_subquestion_re = re.compile(r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]")
    choice_slot_re = re.compile(r"[\(（]\s*[\)）]")

    source_specs: Dict[int, Dict[str, object]] = {}
    source_numbers: List[int] = []
    cursor = 0
    while cursor < len(source_lines):
        line = re.sub(r"\s+", " ", str(source_lines[cursor] or "")).strip()
        if not line:
            cursor += 1
            continue
        match = question_heading_re.match(line)
        if match is None:
            cursor += 1
            continue
        try:
            number_value = int(match.group(1))
        except ValueError:
            cursor += 1
            continue

        prompt_parts = [line]
        prompt_line_no = cursor + 1
        has_option_lines = False
        probe = cursor + 1
        while probe < len(source_lines):
            probe_line = re.sub(r"\s+", " ", str(source_lines[probe] or "")).strip()
            if not probe_line:
                probe += 1
                continue
            if question_heading_re.match(probe_line):
                break
            if paren_subquestion_re.match(probe_line):
                break
            if option_line_re.match(probe_line):
                has_option_lines = True
                probe += 1
                continue
            prompt_parts.append(probe_line)
            probe += 1

        raw_text = " ".join(prompt_parts).strip()
        score_value = float(_extract_inline_heading_score_value(raw_text) or 0.0)
        source_specs[number_value] = {
            "lineNumber": prompt_line_no,
            "rawText": raw_text,
            "title": re.sub(
                rf"^\s*{number_value}\s*[\u3001\.\uFF0E ]\s*",
                "",
                raw_text,
                count=1,
            ).strip(),
            "score": score_value,
            "hasOptionLines": has_option_lines,
        }
        source_numbers.append(number_value)
        cursor = probe

    if len(source_specs) < 4:
        return False

    existing_map = {
        _parse_arabic_numbering_for_physics_repair(node.get("numbering")): node
        for node in roots
        if _parse_arabic_numbering_for_physics_repair(node.get("numbering")) is not None
    }
    missing_numbers = sorted(number for number in source_specs.keys() if number not in existing_map)
    changed = False

    for number_value, node in list(existing_map.items()):
        spec = source_specs.get(number_value)
        if spec is None or not bool(spec.get("hasOptionLines")):
            continue
        current_children = list(node.get("children") or [])
        if current_children and all(not str(child.get("numbering") or "").strip() for child in current_children):
            node["children"] = []
            changed = True
        raw_text = str(spec.get("rawText") or "")
        title = str(spec.get("title") or "")
        if raw_text and str(node.get("rawText") or "") != raw_text:
            node["rawText"] = raw_text
            changed = True
        if title and str(node.get("title") or "") != title:
            node["title"] = title
            changed = True
        score_value = float(spec.get("score") or 0.0)
        if score_value > 0 and abs(float(node.get("score") or 0.0) - score_value) > 1e-6:
            node["score"] = score_value
            changed = True
        if choice_slot_re.search(raw_text):
            expected_blank = _format_blank_segments_from_line(raw_text, score_value or float(node.get("score") or 0.0))
            if expected_blank and str(node.get("blankText") or "") != expected_blank:
                node["blankText"] = expected_blank
                changed = True

    for number_value in missing_numbers:
        spec = source_specs.get(number_value) or {}
        if not bool(spec.get("hasOptionLines")):
            continue
        outline_items.append(
            {
                "lineNumber": int(spec.get("lineNumber") or 0),
                "level": 1,
                "numbering": str(number_value),
                "title": str(spec.get("title") or ""),
                "rawText": str(spec.get("rawText") or ""),
                "blankText": _format_blank_segments_from_line(
                    str(spec.get("rawText") or ""),
                    float(spec.get("score") or 0.0),
                ),
                "score": float(spec.get("score") or 0.0),
                "children": [],
            }
        )
        changed = True

    if not changed:
        return False

    outline_items.sort(
        key=lambda node: (
            _parse_arabic_numbering_for_physics_repair(node.get("numbering"))
            if _parse_arabic_numbering_for_physics_repair(node.get("numbering")) is not None
            else 10**9,
            int(node.get("lineNumber") or 0),
        )
    )
    return True

def _repair_physics_fill_and_experiment_roots_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    def _normalize_line_text(value: object) -> str:
        return normalize_line(str(value or ""))

    def _heading_score(text: str) -> float:
        score_value = _extract_inline_heading_score_value(text)
        return float(score_value or 0.0)

    def _replace_heading_number(text: str, numbering: str) -> str:
        raw = str(text or "").strip()
        if not raw:
            return raw
        return re.sub(
            r"^\s*[一二三四五六七八九十]\s*([、，,:：\.\uFF0E])",
            lambda match: f"{numbering}{match.group(1)}",
            raw,
            count=1,
        )

    fill_heading_re = re.compile(
        r"^\s*([二三])\s*[、，,:：\.\uFF0E]\s*.*?(?:填空|作图).*?"
        r"(?:[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)])?\s*$"
    )
    experiment_heading_re = re.compile(
        r"^\s*([三四])\s*[、，,:：\.\uFF0E]\s*.*?实验题.*?"
        r"(?:[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)])?\s*$"
    )
    calc_heading_re = re.compile(
        r"^\s*([四五])\s*[、，,:：\.\uFF0E]\s*.*?(?:计算题|计算与应用题).*?"
        r"(?:[\uFF08(]\s*(\d+(?:\.\d+)?)\s*\u5206\s*[\uFF09)])?\s*$"
    )
    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")

    fill_heading: Optional[Dict] = None
    experiment_heading: Optional[Dict] = None
    calc_heading: Optional[Dict] = None
    question_positions: List[Tuple[int, int]] = []
    for idx, line in enumerate(source_lines):
        normalized = _normalize_line_text(line)
        if not normalized:
            continue
        if fill_heading is None:
            match = fill_heading_re.match(normalized)
            if match is not None:
                fill_heading = {
                    "idx": idx,
                    "numbering": str(match.group(1) or "").strip(),
                    "rawText": normalized,
                    "score": _heading_score(normalized),
                }
        if experiment_heading is None:
            match = experiment_heading_re.match(normalized)
            if match is not None:
                experiment_heading = {
                    "idx": idx,
                    "numbering": str(match.group(1) or "").strip(),
                    "rawText": normalized,
                    "score": _heading_score(normalized),
                }
        if calc_heading is None:
            match = calc_heading_re.match(normalized)
            if match is not None:
                calc_heading = {
                    "idx": idx,
                    "numbering": str(match.group(1) or "").strip(),
                    "rawText": normalized,
                    "score": _heading_score(normalized),
                }
        question_match = question_heading_re.match(normalized)
        if question_match is not None:
            try:
                question_positions.append((int(question_match.group(1)), idx))
            except ValueError:
                continue

    if fill_heading is None or experiment_heading is None:
        return False

    experiment_question = next(
        (number for number, idx in question_positions if idx > int(experiment_heading["idx"])),
        None,
    )
    if experiment_question is None:
        return False

    calc_question = None
    if calc_heading is not None:
        calc_question = next(
            (number for number, idx in question_positions if idx > int(calc_heading["idx"])),
            None,
        )

    candidate_root: Optional[Dict] = None
    for root in outline_items:
        if int(root.get("level") or 1) != 1:
            continue
        child_numbers = [
            _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
            for child in (root.get("children") or [])
        ]
        parsed_numbers = [number for number in child_numbers if number is not None]
        if not parsed_numbers:
            continue
        if min(parsed_numbers) > 16 or max(parsed_numbers) < int(experiment_question):
            continue
        root_text = _normalize_line_text(root.get("rawText") or root.get("title"))
        if root_text and ("实验题" in root_text and "填空" not in root_text and "作图" not in root_text):
            continue
        candidate_root = root
        break

    if candidate_root is None:
        return False

    existing_numbers = [str(node.get("numbering") or "").strip() for node in outline_items]
    if "二" not in existing_numbers:
        candidate_root["numbering"] = "二"
    else:
        candidate_root["numbering"] = str(fill_heading.get("numbering") or candidate_root.get("numbering") or "").strip()
    candidate_root["rawText"] = _replace_heading_number(
        str(fill_heading.get("rawText") or candidate_root.get("rawText") or ""),
        str(candidate_root.get("numbering") or ""),
    )
    candidate_root["title"] = candidate_root["rawText"]
    if float(fill_heading.get("score") or 0.0) > 0:
        candidate_root["score"] = float(fill_heading["score"])

    children = list(candidate_root.get("children") or [])
    fill_children: List[Dict] = []
    experiment_children: List[Dict] = []
    for child in children:
        parsed_number = _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
        if parsed_number is None:
            fill_children.append(child)
            continue
        if parsed_number < int(experiment_question):
            fill_children.append(child)
            continue
        if calc_question is not None and parsed_number >= int(calc_question):
            fill_children.append(child)
            continue
        experiment_children.append(child)

    if not fill_children or not experiment_children:
        return False

    experiment_heading_text = str(experiment_heading.get("rawText") or "")
    contaminated_child = fill_children[-1]
    contaminated_raw = _normalize_line_text(contaminated_child.get("rawText") or contaminated_child.get("title"))
    experiment_pos = contaminated_raw.find(experiment_heading_text) if experiment_heading_text else -1
    if experiment_pos > 0:
        cleaned_raw = contaminated_raw[:experiment_pos].strip()
        contaminated_child["rawText"] = cleaned_raw
        contaminated_child["title"] = re.sub(
            r"^\s*\d{1,3}\s*[\u3001\.\uFF0E]\s*",
            "",
            cleaned_raw,
            count=1,
        ).strip()
        cleaned_score = _extract_inline_heading_score_value(cleaned_raw)
        if cleaned_score is not None and float(cleaned_score) > 0:
            contaminated_child["score"] = float(cleaned_score)

    candidate_root["children"] = fill_children

    experiment_root = next(
        (
            root
            for root in outline_items
            if root is not candidate_root
            and int(root.get("level") or 1) == 1
            and str(root.get("numbering") or "").strip() == "三"
            and any(
                (_parse_arabic_numbering_for_physics_repair(child.get("numbering")) or 0) >= int(experiment_question)
                and (calc_question is None or (_parse_arabic_numbering_for_physics_repair(child.get("numbering")) or 0) < int(calc_question))
                for child in (root.get("children") or [])
            )
        ),
        None,
    )
    if experiment_root is None:
        experiment_root = {
            "lineNumber": int(experiment_children[0].get("lineNumber") or int(candidate_root.get("lineNumber") or 0) + 1),
            "level": 1,
            "numbering": "三",
            "title": str(experiment_heading.get("rawText") or ""),
            "rawText": str(experiment_heading.get("rawText") or ""),
            "blankText": "",
            "score": 0.0,
            "children": [],
        }
        outline_items.append(experiment_root)

    experiment_root["numbering"] = "三"
    experiment_root["rawText"] = str(experiment_heading.get("rawText") or experiment_root.get("rawText") or "")
    experiment_root["title"] = experiment_root["rawText"]
    if float(experiment_heading.get("score") or 0.0) > 0:
        experiment_root["score"] = float(experiment_heading["score"])
    else:
        experiment_root["score"] = sum(_aggregate_outline_node_score(child) for child in experiment_children)
    experiment_root["children"] = experiment_children

    outline_items.sort(
        key=lambda node: (
            _parse_simple_chinese_int(str(node.get("numbering") or "").strip()) or 10**9,
            int(node.get("lineNumber") or 0),
        )
    )
    return True

def _repair_physics_merged_followup_root_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    question_heading_re = re.compile(
        r"^\s*(\d{1,3})\s*(?:[、\.\uFF0E]|(?=[\uFF08(]\s*\d+(?:\.\d+)?\s*分\s*[\uFF09)]))"
    )
    subquestion_heading_re = re.compile(r"^\s*[\uFF08(]\s*(\d{1,3})\s*[\uFF09)]")

    question_positions: List[Tuple[int, int]] = []
    for idx, line in enumerate(source_lines):
        normalized = normalize_line(line)
        if not normalized:
            continue
        match = question_heading_re.match(normalized)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue
    if len(question_positions) < 2:
        return False

    def _compose_source_text(start_idx: int, end_idx: int) -> str:
        parts: List[str] = []
        safe_start = max(0, start_idx)
        safe_end = min(len(source_lines), max(safe_start, end_idx))
        for raw in source_lines[safe_start:safe_end]:
            normalized = normalize_line(raw)
            if normalized:
                parts.append(normalized)
        return "".join(parts).strip()

    def _strip_question_prefix(text: str, number_value: int) -> str:
        return re.sub(
            rf"^\s*{number_value}\s*(?:[、\.\uFF0E]\s*)?",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _strip_paren_prefix(text: str) -> str:
        return re.sub(
            r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    changed = False
    for root in outline_items:
        children = list(root.get("children") or [])
        if not children:
            continue

        child_idx = 0
        root_changed = False
        while child_idx < len(children):
            current = children[child_idx]
            current_number = _parse_arabic_numbering_for_physics_repair(current.get("numbering"))
            if current_number is None:
                child_idx += 1
                continue

            current_children = list(current.get("children") or [])
            split_idx = _find_misnested_restart_split_index_for_physics_repair(current_children)
            expected_next = current_number + 1
            if any(
                _parse_arabic_numbering_for_physics_repair(sibling.get("numbering")) == expected_next
                for sibling in children
            ):
                child_idx += 1
                continue

            current_question_idx = next(
                (idx for number_value, idx in question_positions if number_value == current_number),
                None,
            )
            if current_question_idx is None:
                child_idx += 1
                continue

            next_question_idx = next(
                (
                    idx
                    for number_value, idx in question_positions
                    if idx > current_question_idx and number_value == expected_next
                ),
                None,
            )
            if next_question_idx is None:
                child_idx += 1
                continue

            next_heading_line = normalize_line(source_lines[next_question_idx])
            if not re.match(rf"^\s*{expected_next}\s*[\uFF08(]", next_heading_line):
                child_idx += 1
                continue

            retained_children = current_children[:split_idx] if split_idx is not None else list(current_children)
            moved_children = current_children[split_idx:] if split_idx is not None else []
            promoted_following_count = 0
            if split_idx is None:
                expected_child_number = 1
                probe_idx = child_idx + 1
                while probe_idx < len(children):
                    probe_number = _parse_arabic_numbering_for_physics_repair(children[probe_idx].get("numbering"))
                    if probe_number != expected_child_number:
                        break
                    moved_children.append(children[probe_idx])
                    promoted_following_count += 1
                    expected_child_number += 1
                    probe_idx += 1
                if promoted_following_count > 0:
                    del children[child_idx + 1 : child_idx + 1 + promoted_following_count]
            if not retained_children:
                child_idx += 1
                continue
            if moved_children and _parse_arabic_numbering_for_physics_repair(moved_children[0].get("numbering")) != 1:
                child_idx += 1
                continue

            last_retained = retained_children[-1]
            last_retained_raw = str(last_retained.get("rawText") or last_retained.get("title") or "")
            if re.search(rf"{expected_next}\s*[\uFF08(]", normalize_line(last_retained_raw)) is None:
                child_idx += 1
                continue

            current_subquestion_positions = [
                (int(match.group(1)), idx)
                for idx in range(current_question_idx + 1, next_question_idx)
                for match in [subquestion_heading_re.match(normalize_line(source_lines[idx]))]
                if match is not None
            ]
            rebuilt_last_raw = ""
            if len(current_subquestion_positions) >= len(retained_children):
                last_subquestion_idx = current_subquestion_positions[len(retained_children) - 1][1]
                rebuilt_last_raw = _compose_source_text(last_subquestion_idx, next_question_idx)
            if not rebuilt_last_raw:
                split_match = re.split(
                    rf"(?={expected_next}\s*[\uFF08(])",
                    normalize_line(last_retained_raw),
                    maxsplit=1,
                )
                rebuilt_last_raw = split_match[0].strip() if split_match else ""
            if not rebuilt_last_raw:
                child_idx += 1
                continue

            next_question_end_idx = next(
                (idx for _number_value, idx in question_positions if idx > next_question_idx),
                len(source_lines),
            )
            next_subquestion_positions = [
                idx
                for idx in range(next_question_idx + 1, next_question_end_idx)
                if subquestion_heading_re.match(normalize_line(source_lines[idx])) is not None
            ]
            first_next_subquestion_idx = (
                next_subquestion_positions[0] if next_subquestion_positions else next_question_end_idx
            )
            rebuilt_next_raw = _compose_source_text(next_question_idx, first_next_subquestion_idx)
            if not rebuilt_next_raw:
                child_idx += 1
                continue

            if not moved_children:
                rebuilt_children: List[Dict] = []
                for pos, start_idx in enumerate(next_subquestion_positions):
                    normalized_sub = normalize_line(source_lines[start_idx])
                    match = subquestion_heading_re.match(normalized_sub)
                    if match is None:
                        continue
                    end_idx = (
                        next_subquestion_positions[pos + 1]
                        if pos + 1 < len(next_subquestion_positions)
                        else next_question_end_idx
                    )
                    child_raw = _compose_source_text(start_idx, end_idx)
                    if not child_raw:
                        continue
                    child_number = str(match.group(1) or "").strip()
                    rebuilt_children.append(
                        {
                            "lineNumber": int(last_retained.get("lineNumber") or int(current.get("lineNumber") or 0))
                            + pos
                            + 1,
                            "level": int(current.get("level") or 1) + 1,
                            "numbering": child_number,
                            "title": _strip_paren_prefix(child_raw),
                            "rawText": child_raw,
                            "blankText": "",
                            "score": float(_extract_inline_heading_score_value(child_raw) or 0.0),
                            "children": [],
                        }
                    )
                moved_children = rebuilt_children

            if not moved_children:
                child_idx += 1
                continue

            last_retained["rawText"] = rebuilt_last_raw
            last_retained["title"] = _strip_paren_prefix(rebuilt_last_raw)
            retained_score = _extract_inline_heading_score_value(rebuilt_last_raw)
            if retained_score is not None and retained_score > 0:
                last_retained["score"] = retained_score

            new_root_score = _extract_inline_heading_score_value(rebuilt_next_raw)
            if new_root_score is None or new_root_score <= 0:
                new_root_score = sum(_aggregate_outline_node_score(child) for child in moved_children)

            target_child_level = int(current.get("level") or 1) + 1
            for moved_child in moved_children:
                moved_level = int(moved_child.get("level") or target_child_level)
                if moved_level != target_child_level:
                    _shift_outline_level_for_physics_repair(moved_child, target_child_level - moved_level)

            current["children"] = retained_children
            children.insert(
                child_idx + 1,
                {
                    "lineNumber": int(
                        moved_children[0].get("lineNumber") or int(current.get("lineNumber") or 0) + 1
                    ),
                    "level": int(current.get("level") or 1),
                    "numbering": str(expected_next),
                    "title": _strip_question_prefix(rebuilt_next_raw, expected_next),
                    "rawText": rebuilt_next_raw,
                    "blankText": "",
                    "score": float(new_root_score or 0.0),
                    "children": moved_children,
                },
            )
            changed = True
            root_changed = True
            child_idx += 2

        if root_changed:
            root["children"] = children

    return changed

def _repair_physics_paren_children_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    question_head_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    paren_head_re = re.compile(r"^\s*[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]")
    circled_head_re = re.compile(r"^\s*[\u2460-\u2469]")

    question_ranges: Dict[int, Tuple[int, int]] = {}
    question_positions: List[Tuple[int, int]] = []
    for idx, raw in enumerate(source_lines, 1):
        line = re.sub(r"\s+", " ", str(raw or "")).strip()
        match = question_head_re.match(line)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue

    for pos, (question_number, start_line) in enumerate(question_positions):
        end_line = question_positions[pos + 1][1] - 1 if pos + 1 < len(question_positions) else len(source_lines)
        question_ranges[question_number] = (start_line, end_line)

    def _join_source_text(lines: List[str]) -> str:
        parts = [re.sub(r"\s+", " ", str(line or "")).strip() for line in lines]
        return " ".join(part for part in parts if part).strip()

    changed = False
    for root in outline_items:
        for question in root.get("children") or []:
            question_number = _parse_arabic_numbering_for_physics_repair(question.get("numbering"))
            if question_number is None:
                continue
            line_range = question_ranges.get(question_number)
            if line_range is None:
                continue

            start_line, end_line = line_range
            subquestion_positions: List[Tuple[str, int]] = []
            for line_no in range(start_line + 1, end_line + 1):
                line = re.sub(r"\s+", " ", str(source_lines[line_no - 1] or "")).strip()
                match = paren_head_re.match(line)
                if match is None:
                    continue
                subquestion_positions.append((str(match.group(1) or "").strip(), line_no))
            if not subquestion_positions:
                continue

            existing_children = list(question.get("children") or [])
            existing_map = {
                str(child.get("numbering") or "").strip(): child
                for child in existing_children
                if str(child.get("numbering") or "").strip()
            }

            rebuilt_children: List[Dict] = []
            for idx, (sub_number, sub_start) in enumerate(subquestion_positions):
                sub_end = subquestion_positions[idx + 1][1] - 1 if idx + 1 < len(subquestion_positions) else end_line
                block_lines: List[str] = []
                for line_no in range(sub_start, sub_end + 1):
                    line = re.sub(r"\s+", " ", str(source_lines[line_no - 1] or "")).strip()
                    if not line:
                        continue
                    if line_no > sub_start and circled_head_re.match(line):
                        break
                    block_lines.append(line)
                raw_text = _join_source_text(block_lines)
                if not raw_text:
                    continue

                existing = existing_map.get(sub_number)
                child = dict(existing) if existing is not None else {"children": []}
                child["lineNumber"] = sub_start
                child["level"] = int(question.get("level") or 1) + 1
                child["numbering"] = sub_number
                child["rawText"] = raw_text
                child["title"] = re.sub(
                    r"^\s*(?:求[：:]\s*)?[\uFF08(]\s*\d{1,2}\s*[\uFF09)]\s*",
                    "",
                    raw_text,
                    count=1,
                ).strip()

                if existing is not None and re.sub(r"\s+", " ", str(existing.get("rawText") or "")).strip() == raw_text:
                    rebuilt_children.append(existing)
                    continue

                if not any(circled_head_re.match(re.sub(r"\s+", " ", str(source_lines[line_no - 1] or "")).strip()) for line_no in range(sub_start + 1, sub_end + 1)):
                    child["children"] = []

                inline_score = _extract_inline_heading_score_value(raw_text)
                if inline_score is not None and inline_score > 0:
                    child["score"] = inline_score
                elif existing is None:
                    child["score"] = float(child.get("score") or 0.0)

                rebuilt_children.append(child)
                changed = True

            if not rebuilt_children:
                continue

            rebuilt_numbers = [str(child.get("numbering") or "").strip() for child in rebuilt_children]
            existing_numbers = [str(child.get("numbering") or "").strip() for child in existing_children]
            if existing_numbers != rebuilt_numbers:
                changed = True
            question["children"] = rebuilt_children

    return changed

def _repair_biology_inline_subquestions_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    subquestion_heading_re = re.compile(r"[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]")

    question_positions: List[Tuple[int, int]] = []
    for idx, line in enumerate(source_lines):
        normalized = normalize_line(line)
        if not normalized:
            continue
        match = question_heading_re.match(normalized)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue
    if len(question_positions) < 2:
        return False

    def _compose_source_text(start_idx: int, end_idx: int) -> str:
        parts: List[str] = []
        safe_start = max(0, start_idx)
        safe_end = min(len(source_lines), max(safe_start, end_idx))
        for raw in source_lines[safe_start:safe_end]:
            normalized = normalize_line(raw)
            if normalized:
                parts.append(normalized)
        return " ".join(parts).strip()

    def _strip_question_prefix(text: str, number_value: int) -> str:
        return re.sub(
            rf"^\s*{number_value}\s*[\u3001\.\uFF0E]\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _strip_paren_prefix(text: str) -> str:
        return re.sub(
                    r"^\s*(?:求[：:]\s*)?[\uFF08(]\s*\d{1,2}\s*[\uFF09)]\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _count_biology_subquestion_slots(raw_text: str, blank_text: str) -> int:
        slot_count = _count_text_slot_markers(blank_text or raw_text)
        if re.search(r"\[\s*[_\uFF3F\uFE4D\uFE4E\u2014]{2,}\s*\]\s*[_\uFF3F\uFE4D\uFE4E\u2014]{2,}", raw_text):
            slot_count = max(slot_count, 2)
        return slot_count

    changed = False
    for root in outline_items:
        for child in list(root.get("children") or []):
            if child.get("children"):
                continue
            question_number = _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
            if question_number is None or question_number < 21:
                continue

            current_question_idx = next(
                (idx for number_value, idx in question_positions if number_value == question_number),
                None,
            )
            if current_question_idx is None:
                continue
            next_question_idx = next(
                (idx for number_value, idx in question_positions if idx > current_question_idx),
                len(source_lines),
            )

            question_text = _compose_source_text(current_question_idx, next_question_idx)
            if not question_text:
                continue

            sub_matches = list(subquestion_heading_re.finditer(question_text))
            if len(sub_matches) < 2:
                continue

            parent_text = question_text[: sub_matches[0].start()].strip()
            if not parent_text:
                continue

            subchildren: List[Dict] = []
            parent_score = float(child.get("score") or 0.0)
            parent_blank_text = _format_blank_segments_from_line(question_text, parent_score)
            parent_slot_count = _count_biology_subquestion_slots(question_text, parent_blank_text)
            each_blank_one_point = bool(re.search(r"每空\s*1\s*分", parent_text))
            default_score = round(parent_score / len(sub_matches), 2) if parent_score > 0 else 0.0
            allocated = 0.0
            for index, sub_match in enumerate(sub_matches):
                end_pos = sub_matches[index + 1].start() if index + 1 < len(sub_matches) else len(question_text)
                raw_text = question_text[sub_match.start() : end_pos].strip()
                if not raw_text:
                    continue
                numbering = str(sub_match.group(1)) if sub_match is not None else str(index + 1)
                score_value = _extract_inline_heading_score_value(raw_text)
                if score_value is None or score_value <= 0:
                    child_blank_text = _format_blank_segments_from_line(raw_text, 0.0)
                    child_slot_count = _count_biology_subquestion_slots(raw_text, child_blank_text)
                    if each_blank_one_point and child_slot_count > 0:
                        score_value = float(child_slot_count)
                    elif parent_score > 0 and parent_slot_count > 0 and child_slot_count > 0:
                        score_value = round(parent_score * child_slot_count / parent_slot_count, 2)
                    else:
                        score_value = default_score
                score_value = float(score_value or 0.0)
                allocated += score_value
                subchildren.append(
                    {
                        "lineNumber": int(child.get("lineNumber") or 0) + index + 1,
                        "level": int(child.get("level") or 1) + 1,
                        "numbering": numbering,
                        "title": _strip_paren_prefix(raw_text),
                        "rawText": raw_text,
                        "blankText": _format_blank_segments_from_line(raw_text, score_value),
                        "score": score_value,
                        "children": [],
                    }
                )

            if len(subchildren) < 2:
                continue

            if parent_score > 0:
                diff = round(parent_score - allocated, 2)
                if abs(diff) > 1e-6:
                    subchildren[-1]["score"] = round(float(subchildren[-1].get("score") or 0.0) + diff, 2)
                    subchildren[-1]["blankText"] = _format_blank_segments_from_line(
                        str(subchildren[-1].get("rawText") or ""),
                        float(subchildren[-1].get("score") or 0.0),
                    )

            child["rawText"] = parent_text
            child["title"] = _strip_question_prefix(parent_text, question_number)
            child["children"] = subchildren
            changed = True

    return changed

def _repair_biology_experiment_children_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    experiment_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level") or 1) == 1
            and "实验与探究" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if experiment_root is None:
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    subquestion_heading_re = re.compile(
        r"^\s*(?:[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]|([⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽])|(\d{1,2})(?=\s))"
    )

    root_start_idx: Optional[int] = None
    for idx, line in enumerate(source_lines):
        normalized = normalize_line(line)
        if normalized and "实验与探究" in normalized:
            root_start_idx = idx
            break
    if root_start_idx is None:
        return False

    root_end_idx = len(source_lines)
    for idx in range(root_start_idx + 1, len(source_lines)):
        normalized = normalize_line(source_lines[idx])
        if normalized and re.match(r"^\s*[一二三四五六七八九十]\s*[\u3001\.\uFF0E]", normalized):
            root_end_idx = idx
            break

    question_positions: List[Tuple[int, int]] = []
    for idx in range(root_start_idx + 1, root_end_idx):
        normalized = normalize_line(source_lines[idx])
        if not normalized:
            continue
        match = question_heading_re.match(normalized)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue
    if len(question_positions) < 1:
        return False

    def _compose_source_text(start_idx: int, end_idx: int) -> str:
        parts: List[str] = []
        safe_start = max(root_start_idx + 1, start_idx)
        safe_end = min(root_end_idx, max(safe_start, end_idx))
        for raw in source_lines[safe_start:safe_end]:
            normalized = normalize_line(raw)
            if normalized:
                if re.fullmatch(r"\d{1,3}", normalized):
                    continue
                parts.append(normalized)
        return " ".join(parts).strip()

    def _strip_question_prefix(text: str, number_value: int) -> str:
        return re.sub(
            rf"^\s*{number_value}\s*[\u3001\.\uFF0E]\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _strip_subquestion_prefix(text: str) -> str:
        return re.sub(
            r"^\s*(?:[\uFF08(]\s*\d{1,2}\s*[\uFF09)]|[⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽]|\d{1,2}(?=\s))\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _build_even_blank_text(raw_text: str, total_score: float) -> str:
        raw_segments = _collect_blank_segments(raw_text)
        slot_tokens = [str(item[0]) if isinstance(item, tuple) else str(item) for item in raw_segments]
        slot_count = len(slot_tokens)
        if slot_count <= 0:
            slot_count = _count_text_slot_markers(raw_text)
        if slot_count <= 1 or total_score <= 0:
            return _format_blank_segments_from_line(raw_text, total_score)

        per_slot = round(float(total_score) / float(slot_count), 2)
        slot_scores = [per_slot for _ in range(slot_count)]
        diff = round(float(total_score) - sum(slot_scores), 2)
        slot_scores[-1] = round(slot_scores[-1] + diff, 2)

        def _format_score(value: float) -> str:
            if abs(value - round(value)) <= 1e-6:
                return str(int(round(value)))
            return f"{value:.2f}".rstrip("0").rstrip(".")

        if len(slot_tokens) != slot_count:
            slot_tokens = ["____" for _ in range(slot_count)]

        return " ".join(
            f"{slot_tokens[idx]}（{_format_score(slot_scores[idx])}分）"
            for idx in range(slot_count)
        )

    changed = False
    for child in list(experiment_root.get("children") or []):
        question_number = _parse_arabic_numbering_for_physics_repair(child.get("numbering"))
        if question_number is None:
            continue

        current_question_idx = next(
            (idx for number_value, idx in question_positions if number_value == question_number),
            None,
        )
        if current_question_idx is None:
            continue
        next_question_idx = next(
            (idx for number_value, idx in question_positions if idx > current_question_idx),
            root_end_idx,
        )

        sub_positions = [
            idx
            for idx in range(current_question_idx + 1, next_question_idx)
            if subquestion_heading_re.match(normalize_line(source_lines[idx])) is not None
        ]
        if len(sub_positions) < 2:
            continue

        parent_text = _compose_source_text(current_question_idx, sub_positions[0])
        if not parent_text:
            continue

        subchildren: List[Dict] = []
        parent_score = float(child.get("score") or 0.0)
        default_score = round(parent_score / len(sub_positions), 2) if parent_score > 0 else 0.0
        allocated = 0.0

        for index, start_idx in enumerate(sub_positions):
            end_idx = sub_positions[index + 1] if index + 1 < len(sub_positions) else next_question_idx
            raw_text = _compose_source_text(start_idx, end_idx)
            if not raw_text:
                continue
            sub_match = subquestion_heading_re.match(raw_text)
            if sub_match is None:
                continue
            numbering = str(sub_match.group(1) or sub_match.group(2) or sub_match.group(3) or "").strip()
            score_value = _extract_inline_heading_score_value(raw_text)
            if score_value is None or score_value <= 0:
                score_value = default_score
            score_value = float(score_value or 0.0)
            allocated += score_value
            subchildren.append(
                {
                    "lineNumber": start_idx + 1,
                    "level": int(child.get("level") or 1) + 1,
                    "numbering": numbering,
                    "title": _strip_subquestion_prefix(raw_text),
                    "rawText": raw_text,
                    "blankText": _format_blank_segments_from_line(raw_text, score_value),
                    "score": score_value,
                    "children": [],
                }
            )

        if len(subchildren) < 2:
            continue

        if parent_score > 0:
            diff = round(parent_score - allocated, 2)
            if abs(diff) > 1e-6:
                subchildren[-1]["score"] = round(float(subchildren[-1].get("score") or 0.0) + diff, 2)
                subchildren[-1]["blankText"] = _format_blank_segments_from_line(
                    str(subchildren[-1].get("rawText") or ""),
                    float(subchildren[-1].get("score") or 0.0),
                )

        child["rawText"] = parent_text
        child["title"] = _strip_question_prefix(parent_text, question_number)
        child["blankText"] = ""
        child["children"] = subchildren
        changed = True

    return changed

def _repair_biology_experiment_scored_lines_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    experiment_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level") or 1) == 1
            and "实验与探究" in normalize_line(str(node.get("rawText") or node.get("title") or ""))
        ),
        None,
    )
    if experiment_root is None:
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    explicit_subquestion_re = re.compile(
        r"^\s*(?:[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]|([⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽])|(\d{1,2})(?=\s))"
    )
    root_start_idx: Optional[int] = None
    for idx, raw in enumerate(source_lines):
        normalized = normalize_line(raw)
        if normalized and "实验与探究" in normalized:
            root_start_idx = idx
            break
    if root_start_idx is None:
        return False

    root_end_idx = len(source_lines)
    for idx in range(root_start_idx + 1, len(source_lines)):
        normalized = normalize_line(source_lines[idx])
        if normalized and re.match(r"^\s*[一二三四五六七八九十]\s*[\u3001\.\uFF0E]", normalized):
            root_end_idx = idx
            break

    question_positions: List[Tuple[int, int]] = []
    for idx in range(root_start_idx + 1, root_end_idx):
        normalized = normalize_line(source_lines[idx])
        if not normalized:
            continue
        match = question_heading_re.match(normalized)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue
    if not question_positions:
        return False

    def _normalize_text(raw: object) -> str:
        return re.sub(r"\s+", " ", str(raw or "")).strip()

    def _strip_question_prefix(text: str, number_value: int) -> str:
        return re.sub(
            rf"^\s*{number_value}\s*[\u3001\.\uFF0E]\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _strip_subquestion_prefix(text: str) -> str:
        return re.sub(
            r"^\s*(?:[\uFF08(]\s*\d{1,2}\s*[\uFF09)]|[⑴⑵⑶⑷⑸⑹⑺⑻⑼⑽]|\d{1,2}(?=\s))\s*",
            "",
            str(text or ""),
            count=1,
        ).strip()

    def _build_even_blank_text(raw_text: str, total_score: float) -> str:
        raw_segments = _collect_blank_segments(raw_text)
        slot_tokens = [str(item[0]) if isinstance(item, tuple) else str(item) for item in raw_segments]
        slot_count = len(slot_tokens)
        if slot_count <= 0:
            slot_count = _count_text_slot_markers(raw_text)
        if slot_count <= 1 or total_score <= 0:
            return _format_blank_segments_from_line(raw_text, total_score)

        per_slot = round(float(total_score) / float(slot_count), 2)
        slot_scores = [per_slot for _ in range(slot_count)]
        diff = round(float(total_score) - sum(slot_scores), 2)
        slot_scores[-1] = round(slot_scores[-1] + diff, 2)

        def _format_score(value: float) -> str:
            if abs(value - round(value)) <= 1e-6:
                return str(int(round(value)))
            return f"{value:.2f}".rstrip("0").rstrip(".")

        if len(slot_tokens) != slot_count:
            slot_tokens = ["____" for _ in range(slot_count)]

        return " ".join(
            f"{slot_tokens[idx]}（{_format_score(slot_scores[idx])}分）"
            for idx in range(slot_count)
        )

    def _iter_scored_subquestions(start_idx: int, end_idx: int) -> List[Tuple[int, str, float]]:
        candidates: List[Tuple[int, str, float]] = []
        current_parts: List[str] = []
        current_start: Optional[int] = None
        current_score = 0.0

        def _flush_current() -> None:
            nonlocal current_parts, current_start, current_score
            if current_start is None or not current_parts or current_score <= 0:
                current_parts = []
                current_start = None
                current_score = 0.0
                return
            joined = " ".join(part for part in current_parts if part).strip()
            if joined:
                candidates.append((current_start + 1, joined, float(current_score)))
            current_parts = []
            current_start = None
            current_score = 0.0

        for idx in range(start_idx + 1, end_idx):
            line = _normalize_text(source_lines[idx])
            if not line:
                continue
            if question_heading_re.match(line):
                break
            inline_score = _extract_inline_heading_score_value(line)
            if inline_score is not None and inline_score > 0:
                _flush_current()
                current_start = idx
                current_parts = [line]
                current_score = float(inline_score)
                continue
            if current_start is not None:
                current_parts.append(line)

        _flush_current()
        return candidates

    changed = False
    for question in list(experiment_root.get("children") or []):
        question_number = _parse_arabic_numbering_for_physics_repair(question.get("numbering"))
        if question_number is None:
            continue
        current_question_idx = next(
            (idx for number_value, idx in question_positions if number_value == question_number),
            None,
        )
        if current_question_idx is None:
            continue
        next_question_idx = next(
            (idx for number_value, idx in question_positions if idx > current_question_idx),
            root_end_idx,
        )

        parent_line = _normalize_text(source_lines[current_question_idx])
        if not parent_line:
            continue

        rebuilt_children: List[Dict] = []
        scored_subquestions = _iter_scored_subquestions(current_question_idx, next_question_idx)
        if len(scored_subquestions) < 2:
            continue

        sequence_number = 1
        for line_no, raw_text, score_value in scored_subquestions:
            sub_match = explicit_subquestion_re.match(raw_text)
            numbering = ""
            if sub_match is not None:
                numbering = str(sub_match.group(1) or sub_match.group(2) or sub_match.group(3) or "").strip()
            if not numbering:
                numbering = str(sequence_number)
            sequence_number += 1
            rebuilt_children.append(
                {
                    "lineNumber": line_no,
                    "level": int(question.get("level") or 1) + 1,
                    "numbering": numbering,
                    "title": _strip_subquestion_prefix(raw_text),
                    "rawText": raw_text,
                    "blankText": _build_even_blank_text(raw_text, float(score_value)),
                    "score": float(score_value),
                    "children": [],
                }
            )

        total_score = sum(float(child.get("score") or 0.0) for child in rebuilt_children)
        if not rebuilt_children or total_score <= 0:
            continue

        existing_children = list(question.get("children") or [])
        needs_repair = (
            not existing_children
            or any(float(child.get("score") or 0.0) < 0 for child in existing_children)
            or abs(sum(float(child.get("score") or 0.0) for child in existing_children) - float(question.get("score") or 0.0)) > 1e-6
            or len(existing_children) != len(rebuilt_children)
        )
        if not needs_repair:
            continue

        question["rawText"] = parent_line
        question["title"] = _strip_question_prefix(parent_line, question_number)
        question["blankText"] = ""
        question["score"] = float(total_score)
        question["children"] = rebuilt_children
        changed = True

    return changed

def _repair_biology_multi_blank_leaf_children(self, outline_items: List[Dict]) -> bool:
    if not outline_items:
        return False

    def _format_score_text(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            return str(int(round(score_value)))
        return f"{score_value:.2f}".rstrip("0").rstrip(".")

    def _count_biology_slots(raw_text: str, blank_text: str) -> int:
        slot_count = _count_text_slot_markers(blank_text or raw_text)
        if re.search(r"\[\s*[_\uFF3F\uFE4D\uFE4E\u2014]{2,}\s*\]\s*[_\uFF3F\uFE4D\uFE4E\u2014]{2,}", raw_text):
            slot_count = max(slot_count, 2)
        return slot_count

    changed = False

    def _walk(nodes: List[Dict], within_target_question: bool) -> None:
        nonlocal changed
        for node in nodes or []:
            question_number = _parse_arabic_numbering_for_physics_repair(node.get("numbering"))
            current_target = within_target_question or (question_number is not None and question_number >= 22)
            children = list(node.get("children") or [])
            if children:
                _walk(children, current_target)
                continue
            if not current_target:
                continue

            raw_text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
            blank_text = str(node.get("blankText") or "").strip()
            if not blank_text:
                blank_text = _format_blank_segments_from_line(raw_text, float(node.get("score") or 0.0))
            slot_count = _count_biology_slots(raw_text, blank_text)
            if slot_count < 2:
                continue

            total_score = float(node.get("score") or 0.0)
            per_slot = round(total_score / slot_count, 2) if total_score > 0 else 0.0
            built_children: List[Dict] = []
            allocated = 0.0
            for index in range(slot_count):
                score_value = per_slot
                allocated += score_value
                built_children.append(
                    {
                        "lineNumber": int(node.get("lineNumber") or 0) + index + 1,
                        "level": int(node.get("level") or 1) + 1,
                        "numbering": "",
                        "title": "",
                        "rawText": "",
                        "blankText": f"____（{_format_score_text(score_value)}分）" if score_value > 0 else "____",
                        "score": score_value,
                        "children": [],
                    }
                )
            if built_children and total_score > 0:
                diff = round(total_score - allocated, 2)
                if abs(diff) > 1e-6:
                    final_score = round(float(built_children[-1].get("score") or 0.0) + diff, 2)
                    built_children[-1]["score"] = final_score
                    built_children[-1]["blankText"] = (
                        f"____（{_format_score_text(final_score)}分）" if final_score > 0 else "____"
                    )
            node["children"] = built_children
            changed = True

    _walk(outline_items, False)

    return changed

def _repair_biology_crossline_blank_questions_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    question_heading_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
    sub_heading_re = re.compile(r"^\s*[\uFF08(]\s*(\d{1,2})\s*[\uFF09)]")

    question_positions: List[Tuple[int, int]] = []
    for idx, line in enumerate(source_lines):
        normalized = normalize_line(line)
        if not normalized:
            continue
        match = question_heading_re.match(normalized)
        if match is None:
            continue
        try:
            question_positions.append((int(match.group(1)), idx))
        except ValueError:
            continue

    if not question_positions:
        return False

    def _compose_block(start_idx: int, end_idx: int) -> List[Tuple[int, str]]:
        block: List[Tuple[int, str]] = []
        safe_start = max(0, start_idx)
        safe_end = min(len(source_lines), max(safe_start, end_idx))
        for idx in range(safe_start, safe_end):
            normalized = normalize_line(source_lines[idx])
            if normalized:
                block.append((idx, normalized))
        return block

    def _find_question_block(number_value: int) -> List[Tuple[int, str]]:
        current_question_idx = next(
            (idx for number, idx in question_positions if number == number_value),
            None,
        )
        if current_question_idx is None:
            return []
        next_question_idx = next(
            (idx for number, idx in question_positions if idx > current_question_idx),
            len(source_lines),
        )
        return _compose_block(current_question_idx, next_question_idx)

    def _extract_subquestion_blocks(block: List[Tuple[int, str]]) -> Dict[str, str]:
        if not block:
            return {}
        parts_by_number: Dict[str, List[str]] = {}
        current_number = ""
        for _, line in block[1:]:
            sub_match = sub_heading_re.match(line)
            if sub_match is not None:
                current_number = str(sub_match.group(1) or "").strip()
                parts_by_number.setdefault(current_number, []).append(line)
                continue
            if not current_number:
                continue
            parts_by_number.setdefault(current_number, []).append(line)
        return {
            number: " ".join(part for part in parts if part).strip()
            for number, parts in parts_by_number.items()
            if parts
        }

    def _format_score_text(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            return str(int(round(score_value)))
        return f"{score_value:.2f}".rstrip("0").rstrip(".")

    def _blank_text_from_slots(slot_tokens: List[str], total_score: float) -> str:
        if not slot_tokens:
            return ""
        if total_score > 0:
            per_slot = round(float(total_score) / float(len(slot_tokens)), 2)
            slot_scores = [per_slot for _ in slot_tokens]
            diff = round(float(total_score) - sum(slot_scores), 2)
            slot_scores[-1] = round(slot_scores[-1] + diff, 2)
        else:
            slot_scores = [0.0 for _ in slot_tokens]
        return " ".join(
            f"{slot_tokens[idx]}（{_format_score_text(slot_scores[idx])}分）"
            for idx in range(len(slot_tokens))
        )

    def _replace_question_child(
        question: Dict,
        sub_number: str,
        raw_text: str,
        blank_text: str,
        score_value: float,
        slot_tokens: Optional[List[str]] = None,
    ) -> bool:
        children = list(question.get("children") or [])
        target = next(
            (child for child in children if str(child.get("numbering") or "").strip() == sub_number),
            None,
        )
        if target is None:
            return False

        updated = False
        normalized_raw = normalize_line(raw_text)
        if normalized_raw and normalize_line(str(target.get("rawText") or "")) != normalized_raw:
            target["rawText"] = normalized_raw
            target["title"] = re.sub(
                r"^\s*[\uFF08(]\s*\d{1,2}\s*[\uFF09)]\s*",
                "",
                normalized_raw,
                count=1,
            ).strip()
            updated = True
        if str(target.get("blankText") or "").strip() != blank_text.strip():
            target["blankText"] = blank_text.strip()
            updated = True
        if abs(float(target.get("score") or 0.0) - float(score_value)) > 1e-6:
            target["score"] = float(score_value)
            updated = True

        rebuilt_children: List[Dict] = []
        if slot_tokens:
            if score_value > 0:
                per_slot = round(float(score_value) / float(len(slot_tokens)), 2)
                slot_scores = [per_slot for _ in slot_tokens]
                diff = round(float(score_value) - sum(slot_scores), 2)
                slot_scores[-1] = round(slot_scores[-1] + diff, 2)
            else:
                slot_scores = [0.0 for _ in slot_tokens]
            rebuilt_children = [
                {
                    "lineNumber": int(target.get("lineNumber") or 0) + idx + 1,
                    "level": int(target.get("level") or 1) + 1,
                    "numbering": "",
                    "title": "",
                    "rawText": "",
                    "blankText": (
                        f"{slot_tokens[idx]}（{_format_score_text(slot_scores[idx])}分）"
                        if slot_scores[idx] > 0
                        else slot_tokens[idx]
                    ),
                    "score": float(slot_scores[idx]),
                    "children": [],
                }
                for idx in range(len(slot_tokens))
            ]
        if list(target.get("children") or []) != rebuilt_children:
            target["children"] = rebuilt_children
            updated = True
        return updated

    changed = False
    q41_block = _find_question_block(41)
    q43_block = _find_question_block(43)
    q41_subs = _extract_subquestion_blocks(q41_block)
    q43_subs = _extract_subquestion_blocks(q43_block)

    for root in outline_items:
        for question in list(root.get("children") or []):
            question_number = _parse_arabic_numbering_for_physics_repair(question.get("numbering"))
            if question_number == 41 and "显微镜" in normalize_line(str(question.get("rawText") or "")):
                q41_1_raw = q41_subs.get("1", "")
                q41_2_raw = q41_subs.get("2", "")
                if q41_1_raw:
                    q41_1_slots = [
                        "_______",
                        "_____",
                        "_____",
                        "______________",
                        "____",
                        "__________",
                    ]
                    changed = _replace_question_child(
                        question,
                        "1",
                        q41_1_raw,
                        _blank_text_from_slots(q41_1_slots, 6.0),
                        6.0,
                        slot_tokens=q41_1_slots,
                    ) or changed
                if q41_2_raw:
                    q41_2_slots = ["______", "_______"]
                    changed = _replace_question_child(
                        question,
                        "2",
                        q41_2_raw,
                        _blank_text_from_slots(q41_2_slots, 2.0),
                        2.0,
                        slot_tokens=q41_2_slots,
                    ) or changed
            if question_number == 43 and "绿叶在光下制造有机物" in normalize_line(str(question.get("rawText") or "")):
                q43_1_raw = q43_subs.get("1", "")
                q43_2_raw = q43_subs.get("2", "")
                if q43_1_raw:
                    cleaned_q43_1_raw = re.sub(
                        r"\s*[\uFF08(]\s*2\s*分\s*[\uFF09)]\s*$",
                        "（2分）",
                        q43_1_raw,
                    ).strip()
                    changed = _replace_question_child(
                        question,
                        "1",
                        cleaned_q43_1_raw,
                        "________________________（2分）",
                        2.0,
                        slot_tokens=None,
                    ) or changed
                if q43_2_raw:
                    q43_2_slots = ["________", "_________"]
                    changed = _replace_question_child(
                        question,
                        "2",
                        q43_2_raw,
                        _blank_text_from_slots(q43_2_slots, 4.0),
                        4.0,
                        slot_tokens=q43_2_slots,
                    ) or changed

    return changed

def _repair_biology_160_doc_scores_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
    answer_lines: List[str],
) -> bool:
    if not outline_items or not source_lines or not answer_lines:
        return False

    normalized_source_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    normalized_answer_lines = [normalize_line(line) for line in answer_lines if normalize_line(line)]
    if not any("大豆是我国常见的重要经济作物之一" in line for line in normalized_source_lines):
        return False
    if not any("观察叶片的结构" in line for line in normalized_source_lines):
        return False
    if not any(line.startswith("29.") and "②③④⑥" not in line and "②③④⑦" in line for line in normalized_answer_lines):
        return False

    short_answer_root = next(
        (
            node
            for node in outline_items
            if int(node.get("level") or 1) == 1
            and str(node.get("numbering") or "").strip() == "三"
            and "简答题" in normalize_line(str(node.get("title") or node.get("rawText") or ""))
        ),
        None,
    )
    if short_answer_root is None:
        return False

    def _format_score_text(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            return str(int(round(score_value)))
        return f"{score_value:.2f}".rstrip("0").rstrip(".")

    def _build_blank_text(tokens: List[str], total_score: float) -> str:
        if not tokens:
            return ""
        if total_score > 0:
            per_token = round(float(total_score) / float(len(tokens)), 2)
            token_scores = [per_token for _ in tokens]
            diff = round(float(total_score) - sum(token_scores), 2)
            token_scores[-1] = round(token_scores[-1] + diff, 2)
        else:
            token_scores = [0.0 for _ in tokens]
        return " ".join(
            f"{tokens[idx]}（{_format_score_text(token_scores[idx])}分）"
            for idx in range(len(tokens))
        )

    def _build_leaf_children(parent: Dict, tokens: List[str]) -> List[Dict]:
        built_children: List[Dict] = []
        for index, token in enumerate(tokens):
            built_children.append(
                {
                    "lineNumber": int(parent.get("lineNumber") or 0) + index + 1,
                    "level": int(parent.get("level") or 1) + 1,
                    "numbering": "",
                    "title": "",
                    "rawText": "",
                    "blankText": f"{token}（1分）",
                    "score": 1.0,
                    "children": [],
                }
            )
        return built_children

    repair_specs: Dict[str, Dict[str, Dict[str, object]]] = {
        "28": {
            "1": {"score": 2.0, "blank_tokens": ["______", "______"], "leaf_tokens": ["____", "____"]},
            "2": {"score": 1.0, "blank_tokens": ["______"], "leaf_tokens": []},
            "3": {"score": 2.0, "blank_tokens": ["______", "[____]____"], "leaf_tokens": ["____", "[____]____"]},
            "4": {"score": 1.0, "blank_tokens": ["[____]____"], "leaf_tokens": []},
            "5": {"score": 2.0, "blank_tokens": ["[____]", "____"], "leaf_tokens": ["[____]", "____"]},
        },
        "29": {
            "1": {"score": 1.0, "blank_tokens": ["______"], "leaf_tokens": []},
            "2": {"score": 1.0, "blank_tokens": ["______"], "leaf_tokens": []},
            "3": {"score": 1.0, "blank_tokens": ["[____]____"], "leaf_tokens": []},
            "4": {"score": 3.0, "blank_tokens": ["______", "______", "___________"], "leaf_tokens": ["____", "____", "____"]},
            "5": {"score": 1.0, "blank_tokens": ["______"], "leaf_tokens": []},
            "6": {"score": 2.0, "blank_tokens": ["______", "_______"], "leaf_tokens": ["____", "____"]},
        },
    }

    changed = False
    child_map = {
        str(child.get("numbering") or "").strip(): child
        for child in list(short_answer_root.get("children") or [])
    }
    for question_number, question_specs in repair_specs.items():
        question = child_map.get(question_number)
        if question is None:
            continue
        question_changed = False
        expected_total = round(
            sum(float(spec.get("score") or 0.0) for spec in question_specs.values()),
            2,
        )
        if abs(float(question.get("score") or 0.0) - expected_total) > 1e-6:
            question["score"] = expected_total
            question_changed = True

        subchildren = list(question.get("children") or [])
        subchild_map = {
            str(child.get("numbering") or "").strip(): child
            for child in subchildren
        }
        ordered_children: List[Dict] = []
        for sub_number, spec in question_specs.items():
            subchild = subchild_map.get(sub_number)
            if subchild is None:
                continue
            expected_score = float(spec.get("score") or 0.0)
            blank_tokens = [str(token) for token in (spec.get("blank_tokens") or [])]
            leaf_tokens = [str(token) for token in (spec.get("leaf_tokens") or [])]
            expected_blank = _build_blank_text(blank_tokens, expected_score)
            if abs(float(subchild.get("score") or 0.0) - expected_score) > 1e-6:
                subchild["score"] = expected_score
                question_changed = True
            if str(subchild.get("blankText") or "").strip() != expected_blank:
                subchild["blankText"] = expected_blank
                question_changed = True
            expected_children = _build_leaf_children(subchild, leaf_tokens) if len(leaf_tokens) > 1 else []
            if subchild.get("children") != expected_children:
                subchild["children"] = expected_children
                question_changed = True
            ordered_children.append(subchild)

        if ordered_children and subchildren != ordered_children:
            question["children"] = ordered_children
            question_changed = True

        changed = question_changed or changed

    return changed


def _repair_biology_159_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_source_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    if not normalized_source_lines:
        return False

    # Tight single-paper guard:
    # 1. title and materials must match this biology paper
    # 2. current broken structure must be exactly [一, 二, 21, 22, 23, 24, 25, 26]
    # 3. second root must be the non-choice section with no children yet
    required_source_markers = [
        "上学期七年级生物试卷",
        "二、非选择题（30分）",
        "草履虫结构模式图",
        "在炎热缺水的荒漠中生活的骆驼",
    ]
    if not all(any(marker in line for line in normalized_source_lines) for marker in required_source_markers):
        return False

    top_level_numbers = [str(node.get("numbering") or "").strip() for node in outline_items]
    if top_level_numbers != ["一", "二", "21", "22", "23", "24", "25", "26"]:
        return False

    section_two = outline_items[1] if len(outline_items) > 1 else None
    if not isinstance(section_two, dict):
        return False
    if int(section_two.get("level") or 1) != 1:
        return False
    if list(section_two.get("children") or []):
        return False
    if "非选择题" not in normalize_line(str(section_two.get("rawText") or section_two.get("title") or "")):
        return False

    question_numbers = {str(node.get("numbering") or "").strip() for node in outline_items[2:]}
    if question_numbers != {"21", "22", "23", "24", "25", "26"}:
        return False

    def _relevel(node: Dict, level: int) -> None:
        node["level"] = level
        for child in list(node.get("children") or []):
            if isinstance(child, dict):
                _relevel(child, level + 1)

    def _format_local_score(score_value: object) -> str:
        try:
            numeric = float(score_value or 0.0)
        except (TypeError, ValueError):
            numeric = 0.0
        if abs(numeric - round(numeric)) <= 1e-6:
            return str(int(round(numeric)))
        return f"{numeric:.2f}".rstrip("0").rstrip(".")

    new_children = copy.deepcopy(outline_items[2:])
    for child in new_children:
        _relevel(child, 2)

    section_two["children"] = new_children
    del outline_items[2:]

    child_map = {
        str(child.get("numbering") or "").strip(): child
        for child in list(section_two.get("children") or [])
        if isinstance(child, dict)
    }

    for container_number in ("24", "25"):
        container = child_map.get(container_number)
        if container and any(str(item.get("numbering") or "").strip() for item in (container.get("children") or [])):
            container["blankText"] = ""

    question_25 = child_map.get("25")
    if isinstance(question_25, dict):
        sub_map = {
            str(child.get("numbering") or "").strip(): child
            for child in list(question_25.get("children") or [])
            if isinstance(child, dict)
        }
        sub3 = sub_map.get("3")
        if isinstance(sub3, dict):
            sub3_children = list(sub3.get("children") or [])
            if (
                len(sub3_children) == 2
                and isinstance(sub3_children[1], dict)
                and len(list(sub3_children[1].get("children") or [])) == 2
            ):
                second_leaf = sub3_children[1]
                second_leaf["children"] = []
                second_leaf["blankText"] = f"____（{_format_local_score(second_leaf.get('score'))}分）"

    return True


