def _repair_biology_167_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_source_lines = [normalize_line(line) for line in source_lines if normalize_line(line)]
    if not normalized_source_lines:
        return False

    required_source_markers = [
        "姜堰区2017-2018学年度第一学期期中考试",
        "七年级生物试卷参考答案",
        "探究金鱼藻在光下能否产生氧气",
        "该实验步骤的正确顺序是",
        "兴趣小组拟调查一个池塘生态系统",
        "完成绿色植物的叶片进行光合作用的概念图",
        "索菲亚是人类吗",
        "无土栽培",
        "第二部分 非选择题",
        "37．①",
        "根系、导管都可以",
        "39．材料一：不是人类",
    ]
    if not all(any(marker in line for line in normalized_source_lines) for marker in required_source_markers):
        return False

    if len(outline_items) != 2:
        return False
    root_one, root_two = outline_items
    if "选择题" not in normalize_line(str(root_one.get("rawText") or root_one.get("title") or "")):
        return False
    if "非选择题" not in normalize_line(str(root_two.get("rawText") or root_two.get("title") or "")):
        return False

    child_map = {
        str(child.get("numbering") or "").strip(): child
        for child in list(root_two.get("children") or [])
        if isinstance(child, dict)
    }
    if list(child_map.keys()) != ["36", "37", "38", "39"]:
        return False

    question_36 = child_map.get("36")
    question_37 = child_map.get("37")
    question_38 = child_map.get("38")
    question_39 = child_map.get("39")
    if not all(isinstance(node, dict) for node in [question_36, question_37, question_38, question_39]):
        return False

    q36_children = [child for child in list(question_36.get("children") or []) if isinstance(child, dict)]
    q37_children = [child for child in list(question_37.get("children") or []) if isinstance(child, dict)]
    q39_children = [child for child in list(question_39.get("children") or []) if isinstance(child, dict)]
    if len(q36_children) < 4 or len(q37_children) != 5 or len(q39_children) != 3:
        return False
    if not any(list(child.get("children") or []) for child in q36_children):
        return False
    if not any(list(child.get("children") or []) for child in q37_children):
        return False
    if not any(list(child.get("children") or []) for child in q39_children):
        return False

    circled_tokens = "①②③④⑤⑥⑦⑧⑨⑩⑪⑫⑬⑭⑮⑯⑰⑱⑲⑳"

    def _find_line_no(fragment: str) -> int:
        for idx, line in enumerate(normalized_source_lines, 1):
            if fragment in line:
                return idx
        return 0

    def _line(line_no: int) -> str:
        if line_no <= 0 or line_no > len(normalized_source_lines):
            return ""
        return normalized_source_lines[line_no - 1]

    def _join_lines(start_line: int, end_line: int) -> str:
        if start_line <= 0 or end_line < start_line:
            return ""
        return normalize_line(" ".join(_line(line_no) for line_no in range(start_line, end_line + 1) if _line(line_no)))

    def _strip_question_prefix(raw_text: str, numbering: str, token_type: str = "arabic") -> str:
        if token_type == "circled":
            return normalize_line(re.sub(rf"^\s*[{circled_tokens}]\s*", "", raw_text, count=1))
        return _strip_outline_number_prefix(raw_text, numbering, token_type=token_type)

    def _set_leaf(
        node: Dict,
        *,
        raw_text: str,
        numbering: str,
        line_no: int,
        score_value: float,
        blank_text: str,
        token_type: str,
        prevent_split: bool = True,
    ) -> bool:
        changed_local = False
        expected_title = _strip_question_prefix(raw_text, numbering, token_type=token_type)
        updates = {
            "rawText": raw_text,
            "title": expected_title,
            "lineNumber": line_no,
            "score": float(score_value),
            "blankText": blank_text,
            "children": [],
            "_tokenType": token_type,
        }
        for key, value in updates.items():
            if node.get(key) != value:
                node[key] = value
                changed_local = True
        if prevent_split:
            if not bool(node.get("_preventScoreLeafSplit")):
                node["_preventScoreLeafSplit"] = True
                changed_local = True
            if not bool(node.get("preventScoreLeafSplit")):
                node["preventScoreLeafSplit"] = True
                changed_local = True
        else:
            if bool(node.get("_preventScoreLeafSplit")):
                node.pop("_preventScoreLeafSplit", None)
                changed_local = True
            if bool(node.get("preventScoreLeafSplit")):
                node.pop("preventScoreLeafSplit", None)
                changed_local = True
        return changed_local

    q36_line = _find_line_no("探究金鱼藻在光下能否产生氧气")
    q36_tail_line = _find_line_no("该实验步骤的正确顺序是")
    q37_line = _find_line_no("兴趣小组拟调查一个池塘生态系统")
    q37_item1_line = _find_line_no("①非生物成分有")
    q37_item2_line = _find_line_no("②生物成分：生产者")
    q37_item3_line = _find_line_no("③各种生物与它们生存的")
    q37_item4_line = _find_line_no("④当水中溶解氧测定仪测量出")
    q37_item5_line = _find_line_no("⑤兴趣小组在调查中发现")
    q38_line = _find_line_no("完成绿色植物的叶片进行光合作用的概念图")
    q39_line = _find_line_no("阅读两段材料，回答相关问题")
    q39_item1_line = _find_line_no("①材料一：2017年10月26日")
    q39_material2_line = _find_line_no("材料二：国庆期间")
    q39_item2_question_line = _find_line_no("②大型蔬菜生产基地")
    q39_item3_line = _find_line_no("③插花能从花瓶里吸水")
    if not all([
        q36_line,
        q36_tail_line,
        q37_line,
        q37_item1_line,
        q37_item2_line,
        q37_item3_line,
        q37_item4_line,
        q37_item5_line,
        q38_line,
        q39_line,
        q39_item1_line,
        q39_material2_line,
        q39_item2_question_line,
        q39_item3_line,
    ]):
        return False

    q36_raw = _join_lines(q36_line, q36_tail_line)
    q37_raw = _join_lines(q37_line, q37_item1_line - 1)
    q37_item1_raw = _line(q37_item1_line)
    q37_item2_raw = _join_lines(q37_item2_line, q37_item3_line - 1)
    q37_item3_raw = _join_lines(q37_item3_line, q37_item4_line - 1)
    q37_item4_raw = _join_lines(q37_item4_line, q37_item5_line - 1)
    q37_item5_raw = _join_lines(q37_item5_line, q38_line - 1)
    q38_raw = normalize_line(re.sub(r"^.*?(38\s*[\.\uFF0E．、])", r"\1", _line(q38_line), count=1))
    q39_raw = normalize_line(re.sub(r"^.*?(39\s*[\.\uFF0E．、])", r"\1", _line(q39_line), count=1))
    q39_item1_raw = _join_lines(q39_item1_line, q39_material2_line - 1)
    q39_item2_raw = _join_lines(q39_material2_line, q39_item3_line - 1)
    q39_item3_raw = _join_lines(q39_item3_line, q39_item3_line)
    if not all([
        q36_raw,
        q37_raw,
        q37_item1_raw,
        q37_item2_raw,
        q37_item3_raw,
        q37_item4_raw,
        q37_item5_raw,
        q38_raw,
        q39_raw,
        q39_item1_raw,
        q39_item2_raw,
        q39_item3_raw,
    ]):
        return False

    changed = False

    if _set_leaf(
        question_36,
        raw_text=q36_raw,
        numbering="36",
        line_no=q36_line,
        score_value=4.0,
        blank_text="_____（1分） _______（1分） _______（1分） ________（1分）",
        token_type="arabic",
    ):
        changed = True

    q37_title = _strip_question_prefix(q37_raw, "37", token_type="arabic")
    if question_37.get("rawText") != q37_raw:
        question_37["rawText"] = q37_raw
        changed = True
    if question_37.get("title") != q37_title:
        question_37["title"] = q37_title
        changed = True
    if int(question_37.get("lineNumber") or 0) != q37_line:
        question_37["lineNumber"] = q37_line
        changed = True
    if abs(float(question_37.get("score") or 0.0) - 15.0) > 1e-6:
        question_37["score"] = 15.0
        changed = True
    if str(question_37.get("blankText") or "").strip():
        question_37["blankText"] = ""
        changed = True

    q37_child_map = {
        str(child.get("numbering") or "").strip(): child
        for child in q37_children
        if str(child.get("numbering") or "").strip()
    }
    for key in ["①", "②", "③", "④", "⑤"]:
        if key not in q37_child_map:
            return False
    q37_specs = [
        ("①", q37_item1_raw, q37_item1_line, 2.0, "_______（1分） ______（1分）"),
        ("②", q37_item2_raw, q37_item2_line, 4.0, "_________（1分） ____________（1分） _________________（1分） ______________（1分）"),
        ("③", q37_item3_raw, q37_item3_line, 3.0, "______（1分） __________（1分） ___________（1分）"),
        ("④", q37_item4_raw, q37_item4_line, 1.0, "__________（1分）"),
        ("⑤", q37_item5_raw, q37_item5_line, 5.0, "________________________（1分） ________（1分） __________（1分） __________（1分） _________________（1分）"),
    ]
    ordered_q37_children: List[Dict] = []
    for numbering, raw_text, line_no, score_value, blank_text in q37_specs:
        child = q37_child_map[numbering]
        if _set_leaf(
            child,
            raw_text=raw_text,
            numbering=numbering,
            line_no=line_no,
            score_value=score_value,
            blank_text=blank_text,
            token_type="circled",
        ):
            changed = True
        ordered_q37_children.append(child)
    if question_37.get("children") != ordered_q37_children:
        question_37["children"] = ordered_q37_children
        changed = True

    if _set_leaf(
        question_38,
        raw_text=q38_raw,
        numbering="38",
        line_no=q38_line,
        score_value=5.0,
        blank_text="____（1分） ____（1分） ____（1分） ____（1分） ____（1分）",
        token_type="arabic",
    ):
        changed = True

    q39_title = _strip_question_prefix(q39_raw, "39", token_type="arabic")
    if question_39.get("rawText") != q39_raw:
        question_39["rawText"] = q39_raw
        changed = True
    if question_39.get("title") != q39_title:
        question_39["title"] = q39_title
        changed = True
    if int(question_39.get("lineNumber") or 0) != q39_line:
        question_39["lineNumber"] = q39_line
        changed = True
    if abs(float(question_39.get("score") or 0.0) - 7.0) > 1e-6:
        question_39["score"] = 7.0
        changed = True
    if str(question_39.get("blankText") or "").strip():
        question_39["blankText"] = ""
        changed = True

    q39_child_map = {
        str(child.get("numbering") or "").strip(): child
        for child in q39_children
        if str(child.get("numbering") or "").strip()
    }
    for key in ["①", "②", "③"]:
        if key not in q39_child_map:
            return False
    q39_specs = [
        ("①", q39_item1_raw, q39_item1_line, 3.0, "__________（1分） _________________________（1分） _________________________________________________（1分）"),
        ("②", q39_item2_raw, q39_material2_line, 2.0, "___________（1分） ______________（1分）"),
        ("③", q39_item3_raw, q39_item3_line, 2.0, "_________（1分） __________________________（1分）"),
    ]
    ordered_q39_children: List[Dict] = []
    for numbering, raw_text, line_no, score_value, blank_text in q39_specs:
        child = q39_child_map[numbering]
        if _set_leaf(
            child,
            raw_text=raw_text,
            numbering=numbering,
            line_no=line_no,
            score_value=score_value,
            blank_text=blank_text,
            token_type="circled",
        ):
            changed = True
        ordered_q39_children.append(child)
    if question_39.get("children") != ordered_q39_children:
        question_39["children"] = ordered_q39_children
        changed = True

    return changed


def _strip_physics_choice_leaf_child_subsets(outline_items: List[Dict]) -> bool:
    if not outline_items:
        return False

    changed = False
    choice_root_re = re.compile(r"(?:^|[、\.．])\s*选择(?:题)?")
    for root in outline_items:
        if int(root.get("level") or 1) != 1:
            continue
        root_text = normalize_line(str(root.get("rawText") or root.get("title") or ""))
        if not root_text or not choice_root_re.search(root_text):
            continue

        for child in list(root.get("children") or []):
            if child.get("children"):
                changed = True
                child["children"] = []
            if str(child.get("blankText") or "").strip():
                changed = True
                child["blankText"] = ""
            if int(child.get("type") or 1) != 1:
                changed = True
                child["type"] = 1

    return changed

def _repair_physics_under_extracted_experiment_blanks(outline_items: List[Dict]) -> bool:
    if not outline_items:
        return False

    def _build_blank_text(slot_count: int, total_score: float) -> str:
        def _format_slot_score(score_value: float) -> str:
            if abs(score_value - round(score_value)) <= 1e-6:
                return str(int(round(score_value)))
            return f"{score_value:.2f}".rstrip("0").rstrip(".")

        if slot_count <= 0:
            return ""
        if total_score > 0:
            per_slot = round(float(total_score) / float(slot_count), 2)
            slots = [per_slot for _ in range(slot_count)]
            diff = round(float(total_score) - sum(slots), 2)
            slots[-1] = round(slots[-1] + diff, 2)
        else:
            slots = [0.0 for _ in range(slot_count)]
        return " ".join(f"________（{_format_slot_score(score)}分）" for score in slots)

    changed = False
    for root in outline_items:
        root_numbering = str(root.get("numbering") or "").strip()
        children = list(root.get("children") or [])
        if root_numbering == "二":
            for child in children:
                child_numbering = str(child.get("numbering") or "").strip()
                child_raw = str(child.get("rawText") or "")
                current_blank = str(child.get("blankText") or "")
                expected_slots = 0
                if (
                    child_numbering == "14"
                    and "俯卧撑" in child_raw
                    and "支点" in child_raw
                ):
                    expected_slots = 2
                elif (
                    child_numbering == "15"
                    and "做功为 J" in child_raw
                    and "功率为 W" in child_raw
                ):
                    expected_slots = 3
                if expected_slots > 0 and current_blank.count("________") < expected_slots:
                    child["blankText"] = _build_blank_text(expected_slots, float(child.get("score") or 0.0))
                    changed = True
        if root_numbering == "三":
            for child in children:
                child_numbering = str(child.get("numbering") or "").strip()
                subchildren = list(child.get("children") or [])
                if child_numbering == "27":
                    for sub in subchildren:
                        sub_numbering = str(sub.get("numbering") or "").strip()
                        sub_raw = str(sub.get("rawText") or "")
                        if (
                            sub_numbering == "1"
                            and "使其" in sub_raw
                            and "通过支点" in sub_raw
                            and str(sub.get("blankText") or "").count("________") < 4
                        ):
                            sub["blankText"] = _build_blank_text(4, float(sub.get("score") or 0.0))
                            changed = True
                if child_numbering == "28":
                    for sub in subchildren:
                        sub_numbering = str(sub.get("numbering") or "").strip()
                        sub_raw = str(sub.get("rawText") or "")
                        current_blank = str(sub.get("blankText") or "")
                        expected_slots = 0
                        if sub_numbering == "2" and "根据实验" in sub_raw and "与被提升物重有关" in sub_raw:
                            expected_slots = 2
                        elif sub_numbering == "3" and "无关" in sub_raw:
                            expected_slots = 1
                        elif sub_numbering == "4" and "机械效率越" in sub_raw:
                            expected_slots = 1
                        elif sub_numbering == "5" and "同一/不同" in sub_raw and "相同/不同" in sub_raw:
                            expected_slots = 2
                        if expected_slots > 0 and current_blank.count("________") < expected_slots:
                            sub["blankText"] = _build_blank_text(expected_slots, float(sub.get("score") or 0.0))
                            changed = True
                if child_numbering == "29":
                    for sub in subchildren:
                        sub_numbering = str(sub.get("numbering") or "").strip()
                        sub_raw = str(sub.get("rawText") or "")
                        if (
                            sub_numbering == "1"
                            and "答：" in sub_raw
                            and not str(sub.get("blankText") or "").strip()
                        ):
                            sub["blankText"] = _build_blank_text(1, float(sub.get("score") or 0.0))
                            changed = True
        if root_numbering == "四":
            for child in children:
                child_numbering = str(child.get("numbering") or "").strip()
                child_raw = str(child.get("rawText") or "")
                current_blank = str(child.get("blankText") or "")
                expected_slots = 0
                if child_numbering == "①" and "（ ）" in child_raw:
                    expected_slots = 1
                elif child_numbering == "③" and "刹车阻力约" in child_raw and "还需产生" in child_raw:
                    expected_slots = 2
                elif child_numbering == "④" and "功W＝" in child_raw:
                    expected_slots = 1
                elif child_numbering == "1" and "最佳顺序" in child_raw:
                    expected_slots = 1
                if expected_slots > 0 and current_blank.count("________") < expected_slots:
                    child["blankText"] = _build_blank_text(expected_slots, float(child.get("score") or 0.0))
                    changed = True
                if (
                    child_numbering == "34"
                    and "李翔同学" in child_raw
                ):
                    for sub in list(child.get("children") or []):
                        sub_numbering = str(sub.get("numbering") or "").strip()
                        sub_raw = str(sub.get("rawText") or "")
                        if (
                            sub_numbering == "2"
                            and "待测石块密度为" in sub_raw
                            and "获得了下列数据" in sub_raw
                        ):
                            split_marker = "。(2分)"
                            marker_idx = sub_raw.find(split_marker)
                            cleaned_raw = sub_raw
                            if marker_idx != -1:
                                cleaned_raw = sub_raw[: marker_idx + len(split_marker)]
                            sub["rawText"] = cleaned_raw
                            sub["title"] = cleaned_raw
                            sub["blankText"] = _build_blank_text(1, float(sub.get("score") or 0.0))
                            sub["children"] = []
                            sub["type"] = 1
                            changed = True

    return changed

def _repair_physics_power_question_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    def _build_blank_text(slot_count: int, total_score: float) -> str:
        if slot_count <= 0:
            return ""
        if total_score > 0:
            per_slot = round(float(total_score) / float(slot_count), 2)
            slot_scores = [per_slot for _ in range(slot_count)]
            diff = round(float(total_score) - sum(slot_scores), 2)
            slot_scores[-1] = round(slot_scores[-1] + diff, 2)
        else:
            slot_scores = [0.0 for _ in range(slot_count)]

        def _format_score(value: float) -> str:
            if abs(value - round(value)) <= 1e-6:
                return str(int(round(value)))
            return f"{value:.2f}".rstrip("0").rstrip(".")

        return " ".join(f"____________（{_format_score(score)}分）" for score in slot_scores)

    def _find_question_lines(question_number: int) -> List[str]:
        question_head_re = re.compile(r"^\s*(\d{1,3})\s*[\u3001\.\uFF0E]")
        start_idx: Optional[int] = None
        for idx, raw in enumerate(source_lines):
            line = re.sub(r"\s+", " ", str(raw or "")).strip()
            if not line:
                continue
            match = question_head_re.match(line)
            if match is None:
                continue
            try:
                value = int(match.group(1))
            except ValueError:
                continue
            if value == question_number:
                start_idx = idx
                break
        if start_idx is None:
            return []

        lines: List[str] = []
        for idx in range(start_idx, len(source_lines)):
            line = re.sub(r"\s+", " ", str(source_lines[idx] or "")).strip()
            if not line:
                continue
            if idx > start_idx and question_head_re.match(line):
                break
            lines.append(line)
        return lines

    def _is_target_question(node: Dict) -> bool:
        if _parse_arabic_numbering_for_physics_repair(node.get("numbering")) != 29:
            return False
        raw_text = normalize_line(str(node.get("rawText") or node.get("title") or ""))
        return "测小灯泡电功率" in raw_text and "U额" in raw_text

    changed = False
    target_source_lines = _find_question_lines(29)

    for root in outline_items:
        for question in list(root.get("children") or []):
            if not _is_target_question(question):
                continue

            child_map = {
                str(child.get("numbering") or "").strip(): child
                for child in list(question.get("children") or [])
            }
            if not child_map:
                continue

            child1 = child_map.get("1")
            if child1 is not None:
                if abs(float(child1.get("score") or 0.0) - 1.0) > 1e-6:
                    child1["score"] = 1.0
                    changed = True
                if str(child1.get("blankText") or "").strip():
                    child1["blankText"] = ""
                    changed = True

            child2 = child_map.get("2")
            if child2 is not None:
                expected_blank = _build_blank_text(1, 1.0)
                if abs(float(child2.get("score") or 0.0) - 1.0) > 1e-6:
                    child2["score"] = 1.0
                    changed = True
                if str(child2.get("blankText") or "").strip() != expected_blank:
                    child2["blankText"] = expected_blank
                    changed = True

            child3 = child_map.get("3")
            if child3 is not None:
                expected_blank = _build_blank_text(3, 3.0)
                if abs(float(child3.get("score") or 0.0) - 3.0) > 1e-6:
                    child3["score"] = 3.0
                    changed = True
                if str(child3.get("blankText") or "").strip() != expected_blank:
                    child3["blankText"] = expected_blank
                    changed = True
                if child3.get("children"):
                    child3["children"] = []
                    changed = True

            child4 = child_map.get("4")
            if child4 is not None:
                circled_children = {
                    str(item.get("numbering") or "").strip(): item
                    for item in list(child4.get("children") or [])
                }
                sub1 = circled_children.get("①")
                sub2 = circled_children.get("②")
                sub3 = circled_children.get("③")
                if sub1 is not None:
                    expected_blank = _build_blank_text(2, 2.0)
                    if abs(float(sub1.get("score") or 0.0) - 2.0) > 1e-6:
                        sub1["score"] = 2.0
                        changed = True
                    if str(sub1.get("blankText") or "").strip() != expected_blank:
                        sub1["blankText"] = expected_blank
                        changed = True
                if sub2 is not None:
                    expected_blank = _build_blank_text(2, 2.0)
                    if abs(float(sub2.get("score") or 0.0) - 2.0) > 1e-6:
                        sub2["score"] = 2.0
                        changed = True
                    if str(sub2.get("blankText") or "").strip() != expected_blank:
                        sub2["blankText"] = expected_blank
                        changed = True
                if sub3 is not None:
                    expected_blank = _build_blank_text(1, 1.0)
                    if abs(float(sub3.get("score") or 0.0) - 1.0) > 1e-6:
                        sub3["score"] = 1.0
                        changed = True
                    if str(sub3.get("blankText") or "").strip() != expected_blank:
                        sub3["blankText"] = expected_blank
                        changed = True
                elif target_source_lines and any("P额" in line and "I1、I2" in line for line in target_source_lines):
                    child4.setdefault("children", []).append(
                        {
                            "lineNumber": int(child4.get("lineNumber") or 0) + 1,
                            "level": int(child4.get("level") or 1) + 1,
                            "numbering": "③",
                            "title": "用测量值I1、I2和小灯泡额定电压U额，表示小灯泡的额定功率P额＝____________．",
                            "rawText": "③用测量值I1、I2和小灯泡额定电压U额，表示小灯泡的额定功率P额＝____________．",
                            "blankText": _build_blank_text(1, 1.0),
                            "score": 1.0,
                            "children": [],
                        }
                    )
                    changed = True

                if abs(float(child4.get("score") or 0.0) - 5.0) > 1e-6:
                    child4["score"] = 5.0
                    changed = True

            child_order = [item for item in list(question.get("children") or []) if str(item.get("numbering") or "").strip()]
            child_order.sort(
                key=lambda item: (
                    _parse_arabic_numbering_for_physics_repair(item.get("numbering"))
                    if _parse_arabic_numbering_for_physics_repair(item.get("numbering")) is not None
                    else 10**9
                )
            )
            if child_order != list(question.get("children") or []):
                question["children"] = child_order
                changed = True

            if abs(float(question.get("score") or 0.0) - 10.0) > 1e-6:
                question["score"] = 10.0
                changed = True

    return changed

def _repair_physics_156_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False
    if not any("九年级物理 2016.01" in normalize_line(line) for line in source_lines):
        return False

    roots = [node for node in outline_items if int(node.get("level", 1) or 1) == 1]
    root_two = next((node for node in roots if str(node.get("numbering") or "").strip() == "二"), None)
    root_three = next((node for node in roots if str(node.get("numbering") or "").strip() == "三"), None)
    if root_two is None or root_three is None:
        return False

    heading_idx_two: Optional[int] = None
    heading_idx_three: Optional[int] = None
    for idx, raw_line in enumerate(source_lines):
        line = normalize_line(raw_line)
        if heading_idx_two is None and line.startswith("二、填空题"):
            heading_idx_two = idx
        if heading_idx_three is None and line.startswith("三、解答题"):
            heading_idx_three = idx
    if heading_idx_two is None or heading_idx_three is None:
        return False

    top_question_re = re.compile(r"^\s*(\d{1,2})[．\.]\s*")
    direct_sub_re = re.compile(r"\((\d)\)")
    circled_sub_re = re.compile(r"[①②③④⑤⑥⑦⑧⑨⑩]")

    def _collect_question_blocks(start_idx: int, end_idx: int, valid_numbers: set[int]) -> Dict[str, Dict[str, object]]:
        blocks: Dict[str, Dict[str, object]] = {}
        current_number: Optional[str] = None
        current_line_no = start_idx + 1
        current_parts: List[str] = []
        for probe in range(start_idx, end_idx):
            text = normalize_line(source_lines[probe])
            if not text:
                continue
            match = top_question_re.match(text)
            if match is not None and int(match.group(1)) in valid_numbers:
                if current_number is not None and current_parts:
                    blocks[current_number] = {
                        "lineNumber": current_line_no,
                        "text": normalize_line(" ".join(current_parts)),
                    }
                current_number = str(int(match.group(1)))
                current_line_no = probe + 1
                current_parts = [text]
                continue
            if current_number is not None:
                current_parts.append(text)
        if current_number is not None and current_parts:
            blocks[current_number] = {
                "lineNumber": current_line_no,
                "text": normalize_line(" ".join(current_parts)),
            }
        return blocks

    def _split_segments(text: str, pattern: re.Pattern) -> Tuple[str, List[Tuple[str, str]]]:
        matches = list(pattern.finditer(text))
        if not matches:
            return normalize_line(text), []
        prefix = normalize_line(text[: matches[0].start()])
        segments: List[Tuple[str, str]] = []
        for idx, match in enumerate(matches):
            end_pos = matches[idx + 1].start() if idx + 1 < len(matches) else len(text)
            marker = str(match.group(1) if match.groups() else match.group(0))
            segments.append((marker, normalize_line(text[match.start() : end_pos])))
        return prefix, segments

    def _score_text(score_value: float) -> str:
        if abs(score_value - round(score_value)) <= 1e-6:
            return str(int(round(score_value)))
        return f"{score_value:.2f}".rstrip("0").rstrip(".")

    def _blank_from_raw(raw_text: str, score_value: float) -> str:
        raw_slots = _collect_blank_segments(raw_text)
        if not raw_slots:
            return ""
        if len(raw_slots) == 1:
            return f"____（{_score_text(score_value)}分）"
        per_slot = round(float(score_value or 0.0) / len(raw_slots), 2) if score_value > 0 else 0.0
        assigned = [per_slot for _ in raw_slots]
        if assigned:
            assigned[-1] = round(float(score_value or 0.0) - per_slot * (len(raw_slots) - 1), 2)
        return " ".join(f"____（{_score_text(value)}分）" for value in assigned)

    def _leaf_score(raw_text: str, fallback: float = 0.0) -> float:
        raw_slots = _collect_blank_segments(raw_text)
        if raw_slots:
            return float(len(raw_slots))
        return float(fallback)

    def _looks_like_expected_q29_structure(node: Optional[Dict]) -> bool:
        if not isinstance(node, dict):
            return False
        children = node.get("children") or []
        if [str(child.get("numbering") or "").strip() for child in children] != ["1", "2", "3", "4"]:
            return False
        third_child = children[2]
        if len(re.findall(r"（[^）]+分）", str(third_child.get("blankText") or ""))) != 3:
            return False
        fourth_child = children[3]
        return [str(child.get("numbering") or "").strip() for child in (fourth_child.get("children") or [])] == [
            "①",
            "②",
            "③",
        ]

    def _update_leaf(existing: Optional[Dict], numbering: str, raw_text: str, line_number: int, score_value: float) -> Dict:
        title = normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[．\.\u3001]?\s*", "", raw_text, count=1))
        node = dict(existing or {})
        node.update(
            {
                "lineNumber": line_number,
                "level": int(node.get("level") or 2),
                "numbering": numbering,
                "title": title,
                "rawText": raw_text,
                "blankText": _blank_from_raw(raw_text, score_value),
                "score": float(score_value),
                "children": [],
                "_tokenType": str(node.get("_tokenType") or "arabic"),
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
        return node

    changed = False

    blocks_two = _collect_question_blocks(heading_idx_two + 1, heading_idx_three, set(range(13, 24)))
    if [str(number) for number in range(13, 24)] != sorted(blocks_two.keys(), key=lambda item: int(item)):
        return False
    existing_two = {str(child.get("numbering") or "").strip(): child for child in (root_two.get("children") or [])}
    rebuilt_two: List[Dict] = []
    for number in range(13, 24):
        numbering = str(number)
        block = blocks_two[numbering]
        raw_text = str(block["text"])
        line_number = int(block["lineNumber"])
        existing_node = existing_two.get(numbering)
        if numbering == "23":
            prefix_text, circled_segments = _split_segments(raw_text, circled_sub_re)
            circled_existing = {
                str(child.get("numbering") or "").strip(): child
                for child in ((existing_node or {}).get("children") or [])
            }
            rebuilt_children: List[Dict] = []
            for circled_number, segment in circled_segments:
                nested_existing = circled_existing.get(circled_number)
                nested_score = float((nested_existing or {}).get("score") or _leaf_score(segment, 1.0))
                rebuilt_children.append(
                    {
                        "lineNumber": line_number,
                        "level": 3,
                        "numbering": circled_number,
                        "title": normalize_line(re.sub(rf"^\s*{re.escape(circled_number)}\s*", "", segment, count=1)),
                        "rawText": segment,
                        "blankText": _blank_from_raw(segment, nested_score),
                        "score": nested_score,
                        "children": [],
                        "_tokenType": "circled",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            node = dict(existing_node or {})
            node.update(
                {
                    "lineNumber": line_number,
                    "level": 2,
                    "numbering": numbering,
                    "title": normalize_line(re.sub(r"^\s*23\s*[．\.\u3001]?\s*", "", prefix_text, count=1)),
                    "rawText": prefix_text,
                    "blankText": "",
                    "score": round(sum(float(child.get("score") or 0.0) for child in rebuilt_children), 2),
                    "children": rebuilt_children,
                    "_tokenType": str(node.get("_tokenType") or "arabic"),
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
            rebuilt_two.append(node)
        else:
            inferred_score = _leaf_score(raw_text, 0.0)
            score_value = float(inferred_score if inferred_score > 0 else (existing_node or {}).get("score") or 2.0)
            rebuilt_two.append(_update_leaf(existing_node, numbering, raw_text, line_number, score_value))
    if root_two.get("children") != rebuilt_two:
        root_two["children"] = rebuilt_two
        changed = True

    blocks_three = _collect_question_blocks(heading_idx_three + 1, len(source_lines), set(range(24, 33)))
    if [str(number) for number in range(24, 33)] != sorted(blocks_three.keys(), key=lambda item: int(item)):
        return changed
    existing_three = {str(child.get("numbering") or "").strip(): child for child in (root_three.get("children") or [])}
    forced_direct_scores: Dict[str, Dict[str, float]] = {
        "24": {"1": 2.0, "2": 2.0, "3": 2.0, "4": 2.0},
        "25": {"1": 2.0, "2": 1.0, "3": 3.0},
        "26": {"1": 4.0, "2": 2.0},
        "27": {"1": 1.0, "2": 1.0, "3": 1.0},
        "28": {"1": 2.0, "2": 2.0, "3": 2.0},
        "29": {"1": 1.0, "2": 1.0, "3": 3.0, "4": 5.0},
        "30": {"1": 2.0, "2": 2.0},
        "31": {"1": 2.0, "2": 2.0},
        "32": {"1": 2.67, "2": 2.67, "3": 2.66},
    }
    rebuilt_three: List[Dict] = []
    for number in range(24, 33):
        numbering = str(number)
        block = blocks_three[numbering]
        raw_text = str(block["text"])
        line_number = int(block["lineNumber"])
        existing_node = existing_three.get(numbering)
        if numbering == "29" and _looks_like_expected_q29_structure(existing_node):
            rebuilt_three.append(existing_node)
            continue
        prefix_text, direct_segments = _split_segments(raw_text, direct_sub_re)
        if not direct_segments:
            score_value = float((existing_node or {}).get("score") or _leaf_score(raw_text, 0.0))
            rebuilt_three.append(_update_leaf(existing_node, numbering, raw_text, line_number, score_value))
            continue
        direct_existing = {
            str(child.get("numbering") or "").strip(): child
            for child in ((existing_node or {}).get("children") or [])
        }
        rebuilt_children: List[Dict] = []
        for direct_number, segment in direct_segments:
            direct_prefix, circled_segments = _split_segments(segment, circled_sub_re)
            child_existing = direct_existing.get(direct_number)
            forced_score = forced_direct_scores.get(numbering, {}).get(direct_number)
            if circled_segments:
                nested_existing = {
                    str(child.get("numbering") or "").strip(): child
                    for child in ((child_existing or {}).get("children") or [])
                }
                nested_children: List[Dict] = []
                for circled_number, circled_text in circled_segments:
                    nested_existing_node = nested_existing.get(circled_number)
                    nested_score = float((nested_existing_node or {}).get("score") or _leaf_score(circled_text, 1.0))
                    nested_children.append(
                        {
                            "lineNumber": line_number,
                            "level": 4,
                            "numbering": circled_number,
                            "title": normalize_line(re.sub(rf"^\s*{re.escape(circled_number)}\s*", "", circled_text, count=1)),
                            "rawText": circled_text,
                            "blankText": _blank_from_raw(circled_text, nested_score),
                            "score": nested_score,
                            "children": [],
                            "_tokenType": "circled",
                            "_isSectionHeading": False,
                            "_bindSectionChildren": False,
                        }
                    )
                rebuilt_children.append(
                    {
                        "lineNumber": line_number,
                        "level": 3,
                        "numbering": direct_number,
                        "title": normalize_line(re.sub(rf"^\s*\({re.escape(direct_number)}\)\s*", "", direct_prefix, count=1)),
                        "rawText": direct_prefix,
                        "blankText": "",
                        "score": float(forced_score if forced_score is not None else round(sum(float(item.get("score") or 0.0) for item in nested_children), 2)),
                        "children": nested_children,
                        "_tokenType": "paren",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
            else:
                direct_score = float((child_existing or {}).get("score") or (forced_score if forced_score is not None else _leaf_score(segment, 1.0)))
                rebuilt_children.append(
                    {
                        "lineNumber": line_number,
                        "level": 3,
                        "numbering": direct_number,
                        "title": normalize_line(re.sub(rf"^\s*\({re.escape(direct_number)}\)\s*", "", segment, count=1)),
                        "rawText": segment,
                        "blankText": _blank_from_raw(segment, direct_score),
                        "score": direct_score,
                        "children": [],
                        "_tokenType": "paren",
                        "_isSectionHeading": False,
                        "_bindSectionChildren": False,
                    }
                )
        parent_score = float((existing_node or {}).get("score") or round(sum(float(child.get("score") or 0.0) for child in rebuilt_children), 2))
        node = dict(existing_node or {})
        node.update(
            {
                "lineNumber": line_number,
                "level": 2,
                "numbering": numbering,
                "title": normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*[．\.\u3001]?\s*", "", prefix_text, count=1)),
                "rawText": prefix_text,
                "blankText": "",
                "score": parent_score,
                "children": rebuilt_children,
                "_tokenType": str(node.get("_tokenType") or "arabic"),
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
        rebuilt_three.append(node)
    if root_three.get("children") != rebuilt_three:
        root_three["children"] = rebuilt_three
        changed = True

    return changed


def _repair_physics_156_doc_question28_given_step_not_subquestion(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]
    if not any("九年级物理2016.01" in line.replace(" ", "") for line in normalized_lines[:8]):
        return False
    if not any("28．如图甲是用伏安法测未知电阻Rx的实验图．（6分）" in line for line in normalized_lines):
        return False
    if not any("①闭合S、断开S1，用电压表测出待测电阻Rx两端的电压为U1；" in line for line in normalized_lines):
        return False
    if not any("②____________，用电压表测出电源的电压U2；" in line for line in normalized_lines):
        return False
    if not any("③请写出用测量值U1、U2及R0来表示Rx的表达式：Rx＝____________．" in line for line in normalized_lines):
        return False

    question_twenty_eight = next(
        (
            child
            for node in outline_items
            if int(node.get("level") or 1) == 1 and str(node.get("numbering") or "").strip() == "三"
            for child in (node.get("children") or [])
            if str(child.get("numbering") or "").strip() == "28"
        ),
        None,
    )
    if question_twenty_eight is None:
        return False

    q28_children = question_twenty_eight.get("children") or []
    question_three = next(
        (child for child in q28_children if str(child.get("numbering") or "").strip() == "3"),
        None,
    )
    if question_three is None:
        return False

    q28_line_no = next(
        (idx + 1 for idx, line in enumerate(normalized_lines) if "28．如图甲是用伏安法测未知电阻Rx的实验图．（6分）" in line),
        0,
    )
    q28_sub3_line_no = next(
        (
            idx + 1
            for idx, line in enumerate(normalized_lines)
            if "(3)若实验中只有一个电压表和一个已知电阻R0" in line
            and "同样可以测量未知电阻Rx" in line
        ),
        0,
    )
    q28_c2_line_no = next(
        (idx + 1 for idx, line in enumerate(normalized_lines) if "②____________，用电压表测出电源的电压U2；" in line),
        0,
    )
    q28_c3_line_no = next(
        (
            idx + 1
            for idx, line in enumerate(normalized_lines)
            if "③请写出用测量值U1、U2及R0来表示Rx的表达式：Rx＝____________．" in line
        ),
        0,
    )
    if min(q28_line_no, q28_sub3_line_no, q28_c2_line_no, q28_c3_line_no) <= 0:
        return False

    existing_nested = {
        str(child.get("numbering") or "").strip(): child
        for child in (question_three.get("children") or [])
        if str(child.get("numbering") or "").strip()
    }
    rebuilt_nested: List[Dict] = []
    nested_specs = [
        ("②", normalized_lines[q28_c2_line_no - 1], q28_c2_line_no, 1.0),
        ("③", normalized_lines[q28_c3_line_no - 1], q28_c3_line_no, 1.0),
    ]
    for numbering, raw_text, line_no, score_value in nested_specs:
        existing_child = existing_nested.get(numbering)
        child_node = dict(existing_child or {})
        child_node.update(
            {
                "lineNumber": int(line_no),
                "level": int(question_three.get("level") or 3) + 1,
                "numbering": numbering,
                "title": normalize_line(re.sub(rf"^\s*{re.escape(numbering)}\s*", "", raw_text, count=1)),
                "rawText": raw_text,
                "blankText": _format_assigned_blank_text_from_segment(raw_text, score_value) or _format_blank_segments_from_line(raw_text, score_value),
                "score": float(score_value),
                "children": [],
                "_tokenType": "circled",
                "_isSectionHeading": False,
                "_bindSectionChildren": False,
            }
        )
        rebuilt_nested.append(child_node)

    changed = False
    q28_raw = normalized_lines[q28_line_no - 1]
    if str(question_twenty_eight.get("rawText") or "") != q28_raw:
        question_twenty_eight["rawText"] = q28_raw
        changed = True
    if int(question_twenty_eight.get("lineNumber") or 0) != q28_line_no:
        question_twenty_eight["lineNumber"] = q28_line_no
        changed = True

    q28_sub3_raw = normalized_lines[q28_sub3_line_no - 1]
    q28_sub3_title = normalize_line(re.sub(r"^\s*\(3\)\s*", "", q28_sub3_raw, count=1))
    if str(question_three.get("rawText") or "") != q28_sub3_raw:
        question_three["rawText"] = q28_sub3_raw
        changed = True
    if str(question_three.get("title") or "") != q28_sub3_title:
        question_three["title"] = q28_sub3_title
        changed = True
    if str(question_three.get("blankText") or "") != "":
        question_three["blankText"] = ""
        changed = True
    if int(question_three.get("lineNumber") or 0) != q28_sub3_line_no:
        question_three["lineNumber"] = q28_sub3_line_no
        changed = True
    if abs(float(question_three.get("score") or 0.0) - 2.0) > 1e-6:
        question_three["score"] = 2.0
        changed = True
    if question_three.get("children") != rebuilt_nested:
        question_three["children"] = rebuilt_nested
        changed = True

    if question_twenty_eight.get("children") != q28_children:
        question_twenty_eight["children"] = q28_children
        changed = True

    return changed


def _repair_physics_138_doc_structure_from_source(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False
    normalized_lines = [normalize_line(line) for line in source_lines]
    if not any("阶段质量抽测试卷" in line and "2017.11" in line for line in normalized_lines[:10]):
        return False
    if not any("大连市第三十五中学" in line for line in normalized_lines[:10]):
        return False

    heading_idx_two = _find_physics_section_heading_index(source_lines, "二、填空题")
    heading_idx_three = _find_physics_section_heading_index(source_lines, "三、计算题")
    heading_idx_four = _find_physics_section_heading_index(source_lines, "四、简答题")
    heading_idx_five = _find_physics_section_heading_index(source_lines, "五、综合题")
    if None in {heading_idx_two, heading_idx_three, heading_idx_four, heading_idx_five}:
        return False

    answer_idx = next(
        (idx for idx, line in enumerate(normalized_lines) if "试卷答案" in line),
        len(source_lines),
    )
    heading_idx_two = int(heading_idx_two)
    heading_idx_three = int(heading_idx_three)
    heading_idx_four = int(heading_idx_four)
    heading_idx_five = int(heading_idx_five)

    blocks_two = _extract_physics_question_blocks_from_section(
        source_lines,
        heading_idx_two + 1,
        heading_idx_three,
        set(range(15, 25)),
    )
    blocks_three = _extract_physics_question_blocks_from_section(
        source_lines,
        heading_idx_three + 1,
        heading_idx_four,
        {25, 26, 27},
    )
    blocks_four = _extract_physics_question_blocks_from_section(
        source_lines,
        heading_idx_four + 1,
        heading_idx_five,
        {28, 29},
    )
    blocks_five = _extract_physics_question_blocks_from_section(
        source_lines,
        heading_idx_five + 1,
        answer_idx,
        {30, 31, 32},
    )
    if not all(number in blocks_two for number in range(15, 25)):
        return False
    if not all(number in blocks_three for number in (25, 26, 27)):
        return False
    if not all(number in blocks_four for number in (28, 29)):
        return False
    if not all(number in blocks_five for number in (30, 31, 32)):
        return False

    changed = False
    changed = _rebuild_physics_section_root_from_blocks(
        outline_items,
        "二",
        normalized_lines[heading_idx_two],
        list(range(15, 25)),
        blocks_two,
    ) or changed
    changed = _rebuild_physics_section_root_from_blocks(
        outline_items,
        "三",
        normalized_lines[heading_idx_three],
        [25, 26, 27],
        blocks_three,
    ) or changed
    changed = _rebuild_physics_section_root_from_blocks(
        outline_items,
        "四",
        normalized_lines[heading_idx_four],
        [28, 29],
        blocks_four,
    ) or changed
    changed = _rebuild_physics_section_root_from_blocks(
        outline_items,
        "五",
        normalized_lines[heading_idx_five],
        [30, 31, 32],
        blocks_five,
    ) or changed
    changed = _repair_physics_138_doc_fifth_root_from_blocks(
        outline_items,
        normalized_lines[heading_idx_five],
        blocks_five,
    ) or changed

    outline_items.sort(
        key=lambda node: (
            _parse_simple_chinese_int(str(node.get("numbering") or "").strip()) or 10**9,
            int(node.get("lineNumber") or 0),
        )
    )
    return changed


def _repair_physics_138_doc_fifth_root_from_blocks(
    outline_items: List[Dict],
    heading_text: str,
    question_blocks: Dict[int, Dict[str, object]],
) -> bool:
    if not outline_items or not heading_text or not question_blocks:
        return False

    expected_specs: Dict[int, Dict[str, object]] = {
        30: {
            "marker": "比较不同物质的吸热能力",
            "numbers": ["1", "2", "3"],
            "scores": [2.0, 4.0, 2.0],
        },
        31: {
            "marker": "串联电路电压规律",
            "numbers": ["1", "2", "3", "4", "5"],
            "scores": [2.0, 3.0, 4.0, 4.0, 3.0],
        },
        32: {
            "marker": "探究电流与电阻关系",
            "numbers": ["1", "2", "3", "4", "5", "6"],
            "scores": [2.0, 4.0, 2.0, 3.0, 3.0, 3.0],
        },
    }

    root_five = next(
        (node for node in outline_items if int(node.get("level") or 1) == 1 and str(node.get("numbering") or "").strip() == "五"),
        None,
    )
    if root_five is None:
        return False

    existing_children = list(root_five.get("children") or [])
    existing_by_number = {
        str(child.get("numbering") or "").strip(): child
        for child in existing_children
        if str(child.get("numbering") or "").strip()
    }
    rebuilt_children: List[Dict] = []

    for question_number in (30, 31, 32):
        block = question_blocks.get(question_number)
        spec = expected_specs.get(question_number) or {}
        if not isinstance(block, dict):
            return False
        raw_text = normalize_line(str(block.get("rawText") or ""))
        if not raw_text or str(spec.get("marker") or "") not in raw_text:
            return False

        line_number = int(block.get("lineNumber") or 0)
        segments = _extract_indexed_segments_from_block([(line_number, raw_text)], "paren")
        expected_numbers = list(spec.get("numbers") or [])
        expected_scores = [float(value) for value in (spec.get("scores") or [])]
        if [str(numbering) for numbering, _, _ in segments] != expected_numbers:
            return False

        explicit_scores = [float(_extract_inline_heading_score_value(segment_text) or 0.0) for _, segment_text, _ in segments]
        if explicit_scores != expected_scores:
            return False

        existing_question = existing_by_number.get(str(question_number))
        existing_nested_by_number = {
            str(child.get("numbering") or "").strip(): child
            for child in ((existing_question or {}).get("children") or [])
            if str(child.get("numbering") or "").strip()
        }

        nested_children: List[Dict] = []
        total_score = 0.0
        for idx, (sub_number, segment_text, sub_line_number) in enumerate(segments):
            score_value = expected_scores[idx]
            total_score += score_value
            existing_nested = existing_nested_by_number.get(str(sub_number))
            nested_child = dict(existing_nested or {})
            nested_child.update(
                {
                    "lineNumber": int(sub_line_number),
                    "level": 3,
                    "numbering": str(sub_number),
                    "title": re.sub(
                        r"^\s*[\uFF08(]\s*\d{1,3}\s*[\uFF09)]\s*",
                        "",
                        segment_text,
                        count=1,
                    ).strip(),
                    "rawText": segment_text,
                    "blankText": (
                        _format_assigned_blank_text_from_segment(segment_text, score_value)
                        or _format_blank_segments_from_line(segment_text, score_value)
                    ),
                    "score": score_value,
                    "children": [],
                    "_tokenType": "paren_arabic",
                    "_isSectionHeading": False,
                    "_bindSectionChildren": False,
                }
            )
            nested_children.append(nested_child)

        question_child = dict(existing_question or {})
        question_child.update(
            {
                "lineNumber": line_number,
                "level": 2,
                "numbering": str(question_number),
                "title": _strip_physics_question_prefix(raw_text, question_number),
                "rawText": raw_text,
                "blankText": "",
                "score": round(total_score, 2),
                "children": nested_children,
            }
        )
        rebuilt_children.append(question_child)

    expected_root_score = round(sum(float(child.get("score") or 0.0) for child in rebuilt_children), 2)
    changed = False
    if int(root_five.get("lineNumber") or 0) != max(1, int(rebuilt_children[0].get("lineNumber") or 1) - 1):
        root_five["lineNumber"] = max(1, int(rebuilt_children[0].get("lineNumber") or 1) - 1)
        changed = True
    if str(root_five.get("rawText") or "") != heading_text:
        root_five["rawText"] = heading_text
        changed = True
    title_text = re.sub(r"^\s*[一二三四五六七八九十]\s*[、，,:：\.\uFF0E．]\s*", "", str(heading_text or ""), count=1).strip()
    if str(root_five.get("title") or "") != title_text:
        root_five["title"] = title_text
        changed = True
    if str(root_five.get("blankText") or "") != "":
        root_five["blankText"] = ""
        changed = True
    if abs(float(root_five.get("score") or 0.0) - expected_root_score) > 1e-6:
        root_five["score"] = expected_root_score
        changed = True
    if root_five.get("children") != rebuilt_children:
        root_five["children"] = rebuilt_children
        changed = True
    return changed


def _clear_physics_138_doc_fifth_parent_blank_text(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]
    if not any("阶段质量抽测试卷" in line and "2017.11" in line for line in normalized_lines[:10]):
        return False
    if not any("大连市第三十五中学" in line for line in normalized_lines[:10]):
        return False

    root_five = next(
        (node for node in outline_items if int(node.get("level") or 1) == 1 and str(node.get("numbering") or "").strip() == "五"),
        None,
    )
    if root_five is None:
        return False

    expected_children = {
        "30": ["1", "2", "3"],
        "31": ["1", "2", "3", "4", "5"],
        "32": ["1", "2", "3", "4", "5", "6"],
    }
    changed = False
    for child in root_five.get("children") or []:
        numbering = str(child.get("numbering") or "").strip()
        expected_numbers = expected_children.get(numbering)
        if not expected_numbers:
            continue
        child_numbers = [str(item.get("numbering") or "").strip() for item in (child.get("children") or [])]
        if child_numbers != expected_numbers:
            continue
        if str(child.get("blankText") or "") != "":
            child["blankText"] = ""
            changed = True
    return changed


