    q22_sub1_line_no = _find_line_no_after(q22_line_no + 1, "如图为用螺丝刀撬图钉的示意图")
    q22_sub2_line_no = _find_line_no_after(q22_line_no + 1, "用滑轮组提升重物，请在图中画出拉力F=G/3的绳子的绕法")
