def _repair_math_83_doc_no_arithmetic_group_children(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]
    source_text = "\n".join(line for line in normalized_lines if line)
    required_snippets = [
        "第六单元测试卷",
        "三、计算题。(27分)",
        "1.直接写得数。(9分)",
        "400×30= 50×200= 130×30=",
        "2.先判断积是几位数,再用竖式计算。(18分)",
        "145×34= 110×46=",
        "五、下面的竖式计算对吗?错的画“✕”,并把错误的改正过来。(4分)",
    ]
    if any(snippet not in source_text for snippet in required_snippets):
        return False

    target_root: Optional[Dict] = None
    for node in outline_items:
        if str(node.get("numbering") or "").strip() == "三":
            target_root = node
            break
    if target_root is None:
        return False

    question1: Optional[Dict] = None
    question2: Optional[Dict] = None
    for child in target_root.get("children") or []:
        numbering = str(child.get("numbering") or "").strip()
        if numbering == "1":
            question1 = child
        elif numbering == "2":
            question2 = child
    if question1 is None or question2 is None:
        return False

    question1_raw = normalize_line(str(question1.get("rawText") or question1.get("title") or ""))
    question2_raw = normalize_line(str(question2.get("rawText") or question2.get("title") or ""))
    if question1_raw != "1.直接写得数。(9分)" or question2_raw != "2.先判断积是几位数,再用竖式计算。(18分)":
        return False

    def _clear_arithmetic_children(question: Dict) -> bool:
        children = list(question.get("children") or [])
        if not children:
            return False
        if not all(
            normalize_line(str(child.get("rawText") or child.get("title") or ""))
            in {
                "400×30= 50×200= 130×30=",
                "11×800= 20×150= 19×4=",
                "36×2= 200×90= 32×30=",
                "145×34= 110×46=",
                "302×28= 324×25=",
                "220×64= 408×15=",
            }
            for child in children
        ):
            return False

        changed_local = False
        question["children"] = []
        changed_local = True
        if str(question.get("blankText") or "") != "":
            question["blankText"] = ""
        if not bool(question.get("_preventScoreLeafSplit")):
            question["_preventScoreLeafSplit"] = True
        if not bool(question.get("preventScoreLeafSplit")):
            question["preventScoreLeafSplit"] = True
        return changed_local

    changed = False
    if _clear_arithmetic_children(question1):
        changed = True
    if _clear_arithmetic_children(question2):
        changed = True

    return changed


