def _repair_math_87_doc_question23_followup_child(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]
    source_text = "\n".join(line for line in normalized_lines if line)
    if (
        "江苏省泰州市2018-2019学年度秋学期" not in source_text
        or "七年级第一次月度检测试题" not in source_text
        or "23．（本题满分10分）某儿童服装店老板以32元的价格买进30件连衣裙" not in source_text
        or "请问，该服装店售完这30件连衣裙后，赚了多少钱？" not in source_text
        or "24.（本题满分10分）纽约、悉尼与上海的时差如下表" not in source_text
    ):
        return False

    target_root: Optional[Dict] = None
    for node in outline_items:
        if str(node.get("numbering") or "").strip() == "三":
            target_root = node
            break
    if target_root is None:
        return False

    question23: Optional[Dict] = None
    for child in target_root.get("children") or []:
        if str(child.get("numbering") or "").strip() == "23":
            question23 = child
            break
    if question23 is None:
        return False

    question_raw = normalize_line(str(question23.get("rawText") or question23.get("title") or ""))
    if not question_raw.startswith("23．（本题满分10分）某儿童服装店老板以32元的价格买进30件连衣裙"):
        return False

    followup_text = "请问，该服装店售完这30件连衣裙后，赚了多少钱？"
    followup_line_no = next(
        (idx for idx, line in enumerate(normalized_lines, start=1) if line == followup_text),
        0,
    )
    if followup_line_no <= 0:
        return False

    expected_child = {
        "lineNumber": followup_line_no,
        "level": int(question23.get("level") or 1) + 1,
        "numbering": "",
        "title": followup_text,
        "rawText": followup_text,
        "blankText": "",
        "score": float(question23.get("score") or 0.0),
        "children": [],
    }

    existing_children = list(question23.get("children") or [])
    if existing_children == [expected_child]:
        return False
    if existing_children:
        child = existing_children[0]
        child_raw = normalize_line(str(child.get("rawText") or child.get("title") or ""))
        if len(existing_children) == 1 and child_raw == followup_text:
            changed = False
            if int(child.get("lineNumber") or 0) != followup_line_no:
                child["lineNumber"] = followup_line_no
                changed = True
            expected_level = int(question23.get("level") or 1) + 1
            if int(child.get("level") or 0) != expected_level:
                child["level"] = expected_level
                changed = True
            if str(child.get("numbering") or "") != "":
                child["numbering"] = ""
                changed = True
            if str(child.get("title") or "") != followup_text:
                child["title"] = followup_text
                changed = True
            if str(child.get("rawText") or "") != followup_text:
                child["rawText"] = followup_text
                changed = True
            if str(child.get("blankText") or "") != "":
                child["blankText"] = ""
                changed = True
            expected_score = float(question23.get("score") or 0.0)
            if abs(float(child.get("score") or 0.0) - expected_score) > 1e-6:
                child["score"] = expected_score
                changed = True
            if child.get("children"):
                child["children"] = []
                changed = True
            return changed
        return False

    question23["children"] = [expected_child]
    return True


