def _repair_math_111_doc_judgement_root_missing_third_child(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    root_six = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "六"), None)
    root_five = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "五"), None)
    root_seven = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "七"), None)
    root_four = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "四"), None)
    if root_six is None or root_five is None or root_seven is None or root_four is None:
        return False

    root_six_text = normalize_line(str(root_six.get("rawText") or root_six.get("title") or ""))
    root_five_children = list(root_five.get("children") or [])
    root_seven_children = list(root_seven.get("children") or [])
    root_four_children = list(root_four.get("children") or [])
    root_six_children = list(root_six.get("children") or [])
    if (
        "判断题" not in root_six_text
        or len(root_six_children) != 2
        or len(root_five_children) != 2
        or len(root_four_children) != 5
        or len(root_seven_children) != 6
    ):
        return False
    if not any("18×4+2" in normalize_line(str(child.get("rawText") or "")) for child in root_five_children):
        return False
    if not any("75×4×6" in normalize_line(str(child.get("rawText") or "")) for child in root_five_children):
        return False
    if not any("苹果每箱16元" in normalize_line(str(child.get("rawText") or "")) for child in root_seven_children):
        return False
    if not any("西红柿4元1千克" in normalize_line(str(child.get("rawText") or "")) for child in root_seven_children):
        return False
    if any(str(child.get("numbering") or "").strip() == "3" and "24×5÷3=24÷3×5" in normalize_line(str(child.get("rawText") or "")) for child in root_six_children):
        return False

    def _strip_prefix(text: str) -> str:
        cleaned = normalize_line(text or "")
        cleaned = re.sub(r"^\s*[一二三四五六七八九十]+\s*[、\.\uFF0E]\s*", "", cleaned, count=1)
        cleaned = re.sub(r"^\s*[0-9０-９]{1,3}\s*[、\.\uFF0E]\s*", "", cleaned, count=1)
        cleaned = re.sub(r"^\s*[\uFF08(]\s*[0-9０-９]{1,3}\s*[\uFF09)]\s*[、\.\uFF0E]?\s*", "", cleaned, count=1)
        return cleaned.strip()

    def _format_score_value(score_value: float) -> str:
        rounded = round(float(score_value), 2)
        if abs(rounded - round(rounded)) <= 1e-6:
            return str(int(round(rounded)))
        return f"{rounded:.2f}".rstrip("0").rstrip(".")

    def _make_blank_text(blank_count: int, score_value: float) -> str:
        if blank_count <= 0:
            return ""
        per_blank = float(score_value) / float(blank_count)
        token = f"____（{_format_score_value(per_blank)}分）"
        return " ".join(token for _ in range(blank_count))

    def _make_leaf(numbering: str, line_no: int, raw_text: str, score_value: float) -> Dict:
        cleaned = normalize_line(raw_text)
        return {
            "lineNumber": line_no,
            "level": 2,
            "numbering": numbering,
            "rawText": cleaned,
            "title": _strip_prefix(cleaned),
            "blankText": _make_blank_text(1, score_value),
            "score": float(score_value),
            "children": [],
            "_tokenType": "arabic",
            "_isSectionHeading": False,
            "_bindSectionChildren": False,
        }

    rebuilt_root_six = copy.deepcopy(root_six)
    rebuilt_root_six["lineNumber"] = int(root_six.get("lineNumber") or 0)
    rebuilt_root_six["rawText"] = root_six_text
    rebuilt_root_six["title"] = _strip_prefix(root_six_text)
    rebuilt_root_six["blankText"] = ""
    rebuilt_root_six["score"] = 6.0
    rebuilt_root_six["children"] = [
        _make_leaf(
            "1",
            int(root_six_children[0].get("lineNumber") or max(rebuilt_root_six["lineNumber"] + 1, 1)),
            normalize_line(str(root_six_children[0].get("rawText") or "")),
            2.0,
        ),
        _make_leaf(
            "2",
            int(root_six_children[1].get("lineNumber") or max(rebuilt_root_six["lineNumber"] + 2, 1)),
            normalize_line(str(root_six_children[1].get("rawText") or "")),
            2.0,
        ),
        _make_leaf(
            "3",
            max(
                int(root_six_children[1].get("lineNumber") or 0) + 1,
                int(rebuilt_root_six["lineNumber"] or 0) + 3,
                1,
            ),
            "3.24×5÷3=24÷3×5 （ ）",
            2.0,
        ),
    ]

    if root_six == rebuilt_root_six:
        return False

    root_six.clear()
    root_six.update(rebuilt_root_six)
    return True


def _repair_math_112_docx_fill_section_score_distribution(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items or not source_lines:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]

    def _compact(text: str) -> str:
        return re.sub(r"\s+", "", normalize_line(text or ""))

    compact_source = "\n".join(_compact(line) for line in normalized_lines if _compact(line))
    required_snippets = [
        "北师大版2023-2024期中质量检测1-4单元",
        "二、填空题（10分）",
        "11．计算219－（108＋54）",
        "12．计算三位数的连加时",
        "16．在括号里填上“＞”“＜”或“＝”",
    ]
    if any(_compact(snippet) not in compact_source for snippet in required_snippets):
        return False

    root_two = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "二"), None)
    if root_two is None:
        return False

    children = list(root_two.get("children") or [])
    if len(children) != 8:
        return False

    def _score_text(value: float) -> str:
        rounded = round(float(value), 2)
        if abs(rounded - round(rounded)) <= 1e-6:
            return str(int(round(rounded)))
        return f"{rounded:.2f}".rstrip("0").rstrip(".")

    def _make_blank_text_with_count(score_value: float, blank_count: int) -> str:
        if blank_count <= 0:
            return ""
        per_blank = round(float(score_value or 0.0) / blank_count, 2) if score_value else 0.0
        assigned = [per_blank for _ in range(blank_count)]
        if assigned:
            diff = round(float(score_value or 0.0) - sum(assigned), 2)
            assigned[-1] = round(assigned[-1] + diff, 2)
        return " ".join(f"____（{_score_text(value)}分）" for value in assigned)

    score_map = {
        "9": (1.0, 1),
        "10": (1.0, 1),
        "11": (2.0, 3),
        "12": (2.0, 4),
        "13": (1.0, 1),
        "14": (1.0, 1),
        "15": (1.0, 1),
        "16": (1.0, 6),
    }

    rebuilt_root_two = copy.deepcopy(root_two)
    rebuilt_root_two["score"] = 10.0
    rebuilt_children: List[Dict] = []
    changed = False
    for child in children:
        numbering = str(child.get("numbering") or "").strip()
        target = score_map.get(numbering)
        if target is None:
            rebuilt_children.append(child)
            continue
        score_value, blank_count = target
        rebuilt_child = copy.deepcopy(child)
        rebuilt_child["score"] = float(score_value)
        rebuilt_child["blankText"] = _make_blank_text_with_count(score_value, blank_count)
        rebuilt_children.append(rebuilt_child)
        if rebuilt_child != child:
            changed = True

    rebuilt_root_two["children"] = rebuilt_children
    if rebuilt_root_two != root_two:
        root_two.clear()
        root_two.update(rebuilt_root_two)
        changed = True
    return changed


