def _repair_math_115_docx_fill_scores_and_requirement_children(
    outline_items: List[Dict],
    source_lines: List[str],
) -> bool:
    if not outline_items:
        return False

    normalized_lines = [normalize_line(line) for line in source_lines]

    def _compact(text: str) -> str:
        return re.sub(r"\s+", "", normalize_line(text or ""))

    root_one = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "一"), None)
    root_four = next((node for node in outline_items if str(node.get("numbering") or "").strip() == "四"), None)

    source_signature = False
    if normalized_lines:
        compact_source = "\n".join(_compact(line) for line in normalized_lines if _compact(line))
        required_snippets = [
            "第七单元评估",
            "一、填空。(34分)",
            "一个面积是1平方米的正方形",
            "四、按要求做题。(10分)",
            "100平方厘米",
            "下面两个图形,哪个面积大",
        ]
        source_signature = not any(_compact(snippet) not in compact_source for snippet in required_snippets)

    outline_signature = False
    if root_one is not None and root_four is not None:
        root_one_text = normalize_line(str(root_one.get("rawText") or root_one.get("title") or ""))
        root_four_text = normalize_line(str(root_four.get("rawText") or root_four.get("title") or ""))
        root_one_children = list(root_one.get("children") or [])
        root_four_children = list(root_four.get("children") or [])
        outline_signature = bool(
            "一、填空" in root_one_text
            and "34分" in root_one_text
            and len(root_one_children) == 7
            and any("在下面的括号里填上合适的单位" in normalize_line(str(child.get("rawText") or "")) for child in root_one_children)
            and any("一个面积是1平方米的正方形" in normalize_line(str(child.get("rawText") or "")) for child in root_one_children)
            and "四、按要求做题" in root_four_text
            and "10分" in root_four_text
            and any("下面两个图形,哪个面积大" in normalize_line(str(child.get("rawText") or "")) for child in root_four_children)
        )

    if not source_signature and not outline_signature:
        return False

    changed = False

    if root_one is not None:
        children = list(root_one.get("children") or [])
        if len(children) == 7:
            score_map = {
                "1": (8.0, ""),
                "2": (10.0, "____（2分） ____（2分） ____（2分） ____（2分） ____（2分）"),
                "3": (4.0, "____（2分） ____（2分）"),
                "4": (4.0, "____（2分） ____（2分）"),
                "5": (4.0, "____（2分） ____（2分）"),
                "6": (2.0, "____（2分）"),
                "7": (2.0, "____（2分）"),
            }
            rebuilt_root_one = copy.deepcopy(root_one)
            rebuilt_root_one["score"] = 34.0
            rebuilt_children: List[Dict] = []
            for child in children:
                numbering = str(child.get("numbering") or "").strip()
                rebuilt_child = copy.deepcopy(child)
                target = score_map.get(numbering)
                if target is not None:
                    rebuilt_child["score"] = float(target[0])
                    rebuilt_child["blankText"] = target[1]
                    if numbering == "1":
                        subchildren = list(rebuilt_child.get("children") or [])
                        if len(subchildren) == 3:
                            sub_score_map = {
                                "1": (4.0, "____（2分） ____（2分）"),
                                "2": (2.0, "____（2分）"),
                                "3": (2.0, "____（2分）"),
                            }
                            rebuilt_subchildren: List[Dict] = []
                            for subchild in subchildren:
                                rebuilt_subchild = copy.deepcopy(subchild)
                                sub_numbering = str(subchild.get("numbering") or "").strip()
                                sub_target = sub_score_map.get(sub_numbering)
                                if sub_target is not None:
                                    rebuilt_subchild["score"] = float(sub_target[0])
                                    rebuilt_subchild["blankText"] = sub_target[1]
                                rebuilt_subchildren.append(rebuilt_subchild)
                            rebuilt_child["children"] = rebuilt_subchildren
                rebuilt_children.append(rebuilt_child)
            rebuilt_root_one["children"] = rebuilt_children
            if rebuilt_root_one != root_one:
                root_one.clear()
                root_one.update(rebuilt_root_one)
                changed = True

    if root_four is not None:
        children = list(root_four.get("children") or [])
        first_child = next((child for child in children if str(child.get("numbering") or "").strip() == "1"), None)
        second_child = next(
            (
                child
                for child in children
                if "下面两个图形" in normalize_line(str(child.get("rawText") or ""))
                or str(child.get("numbering") or "").strip() == "2"
            ),
            None,
        )
        if first_child is not None and second_child is not None:
            rebuilt_root_four = copy.deepcopy(root_four)
            rebuilt_first = copy.deepcopy(first_child)
            rebuilt_first["numbering"] = "1"
            rebuilt_first["score"] = 6.0
            rebuilt_first["blankText"] = "____（2分） ____（2分） ____（2分）"
