def apply_math_source_repairs(
    outline_items: List[Dict],
    source_lines: List[str],
    answer_lines: Optional[List[str]],
    is_math_like_exam: bool,
    second_level_mode_detected: str,
) -> Dict[str, object]:
    changed = False
    score_mode: Optional[str] = None
    next_second_level_mode = second_level_mode_detected

    def mark_backfill() -> None:
        nonlocal changed, score_mode
        changed = True
        if score_mode is None:
            score_mode = "backfill"

    def mark_tree() -> None:
        nonlocal changed, score_mode
        changed = True
        score_mode = "tree"

    if is_math_like_exam and _repair_math_continuous_section_children_from_source(outline_items, source_lines):
        next_second_level_mode = "unknown"
        mark_backfill()
    if is_math_like_exam and _repair_math_scored_followup_children_from_source(outline_items, source_lines):
        next_second_level_mode = "unknown"
        mark_tree()
    if _repair_math_comparison_section_children_from_source(outline_items, source_lines):
        mark_tree()
    if _repair_math_missing_paren_children_from_source(outline_items, source_lines):
        mark_tree()
    if is_math_like_exam and _repair_math_choice_children_from_source(outline_items, source_lines):
        mark_tree()
